// v6.13.9 — Task render per stories tab redesign 3(c) collapsible by
// default. Tap the header row to expand; expansion state persists in
// state._prdTaskExpanded across re-renders so the WS push doesn't lose
// the operator's spot. The `editable` param is passed in from
// renderStory so the gate is computed once per story, not per task.
function renderTask(prd, story, task, editable) {
  // editable is now passed from caller; fall back when called standalone.
  if (typeof editable === 'undefined') {
    editable = (prd.status === 'needs_review' || prd.status === 'revisions_asked');
  }
  const taskID = task.id || '';
  state._prdTaskExpanded = state._prdTaskExpanded || {};
  const isExpanded = !!state._prdTaskExpanded[taskID];
  const chevron = isExpanded ? '▾' : '▸'; // ▾ vs ▸

  // Edit affordances — distinct icons per 1(b).
  const editFn = `openPRDEditTaskModal(${JSON.stringify(prd.id)},${JSON.stringify(task.id)},${JSON.stringify(task.spec || '')},${JSON.stringify(task.backend || '')},${JSON.stringify(String(task.effort || ''))},${JSON.stringify(task.model || '')})`;
  const filesEditFn = `openPRDEditTaskFilesModal(${JSON.stringify(prd.id)},${JSON.stringify(task.id)},${JSON.stringify(task.files || [])})`;
  const editIcons = editable
    ? `<span class="prd-task-edit-group" onclick="event.stopPropagation()">
         <button class="prd-story-edit-icon" onclick="${escHtml(editFn)}"      title="Edit spec + LLM">&#9998;</button>
         <button class="prd-story-edit-icon" onclick="${escHtml(filesEditFn)}" title="Edit planned files">&#128193;</button>
       </span>`
    : '';

  // Inline badges visible whether collapsed or expanded.
  const llmBadge = (task.backend || task.effort || task.model)
    ? `<span class="prd-task-llm-badge">LLM: ${escHtml(task.backend || 'inherit')}${task.effort ? ' / ' + escHtml(String(task.effort)) : ''}${task.model ? ' / ' + escHtml(task.model) : ''}</span>`
    : '';
  const spawnBadge = task.spawn_prd
    ? `<span class="prd-task-spawn-badge" title="this task spec is a child automaton spec; executor will Plan + Approve + Run">&#8627; spawn</span>`
    : '';
  const childLink = task.child_prd_id
    ? `<span class="prd-task-child-link">&rarr; child <code>${escHtml(task.child_prd_id)}</code></span>`
    : '';
  const verdicts = task.verdicts && task.verdicts.length
    ? `<span class="prd-task-verdicts">${renderVerdicts(task.verdicts)}</span>`
    : '';

  // Status glyph for the collapsed header row.
  const statusGlyph = ({completed: '✓', failed: '✗', running: '▶', pending: '○'})[task.status] || '';
  const statusGlyphSpan = statusGlyph
    ? `<span class="prd-task-status-glyph status-${escHtml(task.status||'')}">${statusGlyph}</span>`
    : '';

  // Expanded body: spec text + files-planned row + files-touched row.
  let expandedBody = '';
  if (isExpanded) {
    const hasTaskFiles = task.files && task.files.length;
    const hasTaskTouched = task.files_touched && task.files_touched.length;
    const filesP = hasTaskFiles
      ? `<div class="prd-task-files">
           <span class="prd-task-files-label">Files:</span>
           ${task.files.map(f => `<code class="prd-task-file-chip">${escHtml(f)}</code>`).join('')}
           ${editable ? `<button class="prd-story-edit-icon" onclick="event.stopPropagation();${escHtml(filesEditFn)}" title="Edit planned files">&#128193;</button>` : ''}
         </div>`
      : (editable
        ? `<div class="prd-task-files">
             <span class="prd-task-files-label">Files:</span>
             <button class="prd-story-edit-icon" onclick="event.stopPropagation();${escHtml(filesEditFn)}" title="Add planned files">&#128193;</button>
           </div>`
        : '');
    const filesT = hasTaskTouched
      ? `<div class="prd-task-touched">
           <span class="prd-task-touched-label">&#9989; Touched:</span>
           ${task.files_touched.map(f => `<code class="prd-task-touched-chip">${escHtml(f)}</code>`).join('')}
         </div>`
      : '';
    expandedBody = `<div class="prd-task-expanded-body">
      ${task.spec ? `<div class="prd-task-spec">${escHtml(task.spec)}</div>` : ''}
      ${filesP}${filesT}
    </div>`;
  }

  return `<div class="prd-task-row${isExpanded ? ' expanded' : ''}" data-task-id="${escHtml(taskID)}">
    <div class="prd-task-header" onclick="_prdToggleTask('${escHtml(taskID)}')" title="${isExpanded ? 'Collapse' : 'Expand'}">
      <span class="prd-task-chevron">${chevron}</span>
      ${statusGlyphSpan}
      <code class="prd-task-id">${escHtml(taskID)}</code>
      <strong class="prd-task-title">${escHtml(task.title || '')}</strong>
      ${llmBadge}${spawnBadge}${childLink}${verdicts}
      <span class="prd-task-header-spacer"></span>
      ${editIcons}
    </div>
    ${expandedBody}
  </div>`;
}

// v6.13.9 — toggle expanded state for a task; re-renders the parent
// PRD detail panel so the chevron + body flip in place.
function _prdToggleTask(taskID) {
  state._prdTaskExpanded = state._prdTaskExpanded || {};
  state._prdTaskExpanded[taskID] = !state._prdTaskExpanded[taskID];
  if (typeof _refreshAutomataOrPRD === 'function') _refreshAutomataOrPRD();
}
window._prdToggleTask = _prdToggleTask;

// BL191 Q6 (v5.16.0) — per-guardrail verdict badges shown inline on
// stories + tasks. Color-coded by outcome with a tooltip showing
// severity + summary + first issue.
//
// v5.26.6 BL202 polish — badges are now clickable on touch devices
// (tooltips don't work on mobile / Wear OS). Click expands an inline
// drill-down panel with summary, severity, and the full issues list.
// Click again to collapse. Group ID lets us collocate the panel
// directly under the row of badges.
let _verdictDrilldownSeq = 0;
function renderVerdicts(verdicts) {
  if (!verdicts || verdicts.length === 0) return '';
  const colors = { pass: '#10b981', warn: '#f59e0b', block: '#ef4444' };
  const groupId = 'vd-' + (++_verdictDrilldownSeq);
  if (!state._verdictPayloads) state._verdictPayloads = {};
  state._verdictPayloads[groupId] = verdicts;
  const badges = verdicts.map((v, i) => {
    const c = colors[v.outcome] || '#6b7280';
    const tip = (v.summary || '') + (v.severity ? ' [' + v.severity + ']' : '') + (v.issues && v.issues.length ? '\n• ' + v.issues.slice(0, 3).join('\n• ') : '');
    return `<span title="${escHtml(tip)}" onclick="toggleVerdictDrilldown('${groupId}',${i})" style="background:${c};color:#fff;font-size:9px;padding:1px 5px;border-radius:6px;margin-left:2px;cursor:pointer;user-select:none;">${escHtml(v.guardrail || '?')}: ${escHtml(v.outcome || '?')}</span>`;
  }).join('');
  // Drill-down panel sits inline (initially hidden); toggleVerdictDrilldown fills it.
  return ' ' + badges + `<div id="${groupId}-panel" style="display:none;font-size:10px;color:var(--text);background:rgba(255,255,255,0.04);border-left:2px solid var(--border);padding:4px 6px;margin-top:3px;border-radius:3px;"></div>`;
}

window.toggleVerdictDrilldown = function(groupId, idx) {
  const panel = document.getElementById(groupId + '-panel');
  if (!panel) return;
  const verdicts = (state._verdictPayloads || {})[groupId] || [];
  const v = verdicts[idx];
  if (!v) return;
  // If already showing this verdict, collapse. Otherwise replace contents.
  if (panel.dataset.idx === String(idx) && panel.style.display !== 'none') {
    panel.style.display = 'none';
    panel.dataset.idx = '';
    return;
  }
  panel.dataset.idx = String(idx);
  const issues = (v.issues || []).map(s => '<li>' + escHtml(s) + '</li>').join('') || '<li><em style="opacity:0.7;">no issues</em></li>';
  panel.innerHTML =
    `<div style="font-weight:600;margin-bottom:2px;">${escHtml(v.guardrail || '?')} — ${escHtml(v.outcome || '?')}${v.severity ? ' <span style="opacity:0.7;">[' + escHtml(v.severity) + ']</span>' : ''}</div>` +
    (v.summary ? `<div style="margin-bottom:3px;">${escHtml(v.summary)}</div>` : '') +
    `<ul style="margin:0;padding-left:16px;">${issues}</ul>`;
  panel.style.display = 'block';
};

// BL293 — Automata card button matrix (verified 2026-05-11):
// ┌─────────────────┬──────────────────────────────────────────────────────┐
// │ Status          │ Buttons                                              │
// ├─────────────────┼──────────────────────────────────────────────────────┤
// │ draft           │ Plan · LLM · Edit · Delete                           │
// │ needs_review    │ LLM · Approve · Reject · Revise · Edit · Delete      │
// │ revisions_asked │ Plan · LLM · Approve · Reject · Revise · Edit · Delete │
// │ approved        │ LLM · Run · Edit · Delete                            │
// │ running         │ Cancel · Delete                                      │
// │ completed       │ Edit · Delete                                        │
// │ cancelled       │ LLM · Edit · Delete                                  │
// │ archived        │ LLM · Edit · Delete                                  │
// │ template        │ Instantiate (only)                                   │
// └─────────────────┴──────────────────────────────────────────────────────┘
// LLM absent on running+completed (can't change LLM mid-run or post-run).
// Edit absent on running (spec change during execution is unsafe).
function renderPRDActions(prd) {
  const id = prd.id || '';
  const idJ = JSON.stringify(id);
  const status = prd.status || '';
  // v5.26.3 — operator-reported: every PRD button (Edit, Delete, Run,
  // Approve, …) silently no-op'd. Cause: `onclick="${fn}"` interpolated
  // JSON.stringify outputs that contain literal `"` chars, which closed
  // the outer onclick attribute mid-string. v5.22.0 fixed this for the
  // submitPRDEdit modal but missed renderPRDActions itself. escHtml
  // converts inner `"` → `&quot;`; the browser decodes back when parsing
  // the attribute, so the JS expression remains valid.
  const a = (label, fn, color) => `<button class="btn-secondary" style="font-size:10px;${color ? 'background:' + color + ';color:#fff;' : ''}" onclick="${escHtml(fn)}">${label}</button>`;
  if (prd.is_template) {
    return a('Instantiate', `openPRDInstantiateModal(${idJ})`);
  }
  const btns = [];
  if (status === 'draft' || status === 'revisions_asked') btns.push(a('Plan', `prdAction(${idJ},'decompose','POST')`));
  // BL203 — Set LLM button is available pre-Run so the operator can pin a backend before approval.
  if (status !== 'running' && status !== 'completed') {
    const cur = JSON.stringify({ backend: prd.backend || '', effort: String(prd.effort || ''), model: prd.model || '' });
    btns.push(a('LLM', `openPRDSetLLMModal(${idJ},${cur})`, ''));
  }
  if (status === 'needs_review' || status === 'revisions_asked') {
    btns.push(a('Approve', `prdAction(${idJ},'approve','POST',{actor:'operator'})`, '#10b981'));
    btns.push(a('Reject', `prdActionPrompt(${idJ},'reject','reason','Rejection reason')`, '#ef4444'));
    btns.push(a('Revise', `prdActionPrompt(${idJ},'request_revision','note','What needs revision?')`, '#f59e0b'));
  }
  if (status === 'approved') btns.push(a('Run', `prdAction(${idJ},'run','POST')`, '#3b82f6'));
  if (status === 'running') btns.push(a('Cancel', `prdAction(${idJ},'','DELETE')`, '#ef4444'));
  // v5.19.0 — full CRUD finally. Edit (title + spec) on any non-running
  // status; Delete (hard remove + descendants) on every status. Both
  // confirm before firing because they're destructive.
  if (status !== 'running') {
    btns.push(a('Edit', `openPRDEditModal(${idJ},${JSON.stringify(prd.title || '')},${JSON.stringify(prd.spec || '')})`, ''));
  }
  btns.push(a('Delete', `confirmPRDDelete(${idJ})`, '#7c2d12'));
  return btns.join('');
}

// v5.19.0 — confirmation prompt + hard-delete REST call.
//
// v5.26.8 — operator-reported: "I get an error when trying to delete
// an autonomous task, and deleting a task with children should
// delete the children". Two improvements:
//  1. Pre-fetch /children so the confirm message names the count
//     of cascading deletions ("and 3 child PRD(s) under it").
//  2. Strip the "Error: " prefix from the apiFetch failure and
//     surface the daemon's actual message in the toast — pre-v5.26.8
//     toasts said "PRD delete failed: Error: prd ... is running ..."
//     which buried the actionable bit under double-prefix noise.
window.confirmPRDDelete = function(id) {
  apiFetch('/api/autonomous/prds/' + encodeURIComponent(id) + '/children')
    .catch(() => ({ children: [] }))
    .then(data => {
      const kids = (data && data.children) || [];
      const nKids = kids.length;
      const runningKid = kids.find(c => c.status === 'running');
      let msg = 'Delete Automaton ' + id + '?';
      if (nKids > 0) {
        msg += ' This permanently removes it AND ' + nKids + ' child automaton' + (nKids === 1 ? '' : 's') +
               ' spawned via spawn-automaton' + (runningKid ? ' (one of which is running — daemon will refuse until you Cancel it first)' : '') + '.';
      } else {
        msg += ' This permanently removes it.';
      }
      msg += ' Cancelling first is reversible — deletion is not.';
      if (!window.confirm(msg)) return;
      apiFetch('/api/autonomous/prds/' + encodeURIComponent(id) + '?hard=true', { method: 'DELETE' })
        .then(() => { showToast('PRD ' + id + ' deleted' + (nKids > 0 ? ' (+' + nKids + ' child)' : ''), 'success', 1800); _refreshAutomataOrPRD(); })
        .catch(err => {
          const raw = String((err && err.message) || err);
          const trimmed = raw.replace(/^Error:\s*/, '');
          showToast('Delete failed: ' + trimmed, 'error', 4500);
        });
    });
};

// v5.19.0 — modal for editing PRD-level title + spec via PATCH.
// v5.22.0 — fix: inline `onclick="submitPRDEdit(${JSON.stringify(id)})"`
// produced double-quotes inside a double-quoted attribute and broke the
// handler. Use HTML-attribute-escape so the embedded quotes survive.
window.openPRDEditModal = function(id, currentTitle, currentSpec) {
  const idAttr = escHtml(JSON.stringify(id)); // inner double-quotes → &quot;
  const html = `
    <div style="padding:14px;">
      <div style="font-weight:600;margin-bottom:8px;">Edit Automaton <code>${escHtml(id)}</code></div>
      <label style="display:block;font-size:11px;margin-bottom:4px;">Title</label>
      <input id="prdEditTitle" type="text" class="form-input" style="width:100%;margin-bottom:10px;" value="${escHtml(currentTitle || '')}" placeholder="Short headline" />
      <label style="display:flex;align-items:center;gap:4px;font-size:11px;margin-bottom:4px;">Spec ${micButtonHTML('prdEditSpec')}</label>
      <textarea id="prdEditSpec" class="form-input" style="width:100%;height:140px;font-family:monospace;font-size:12px;" placeholder="Describe the feature in plain English">${escHtml(currentSpec || '')}</textarea>
      <div style="display:flex;justify-content:flex-end;gap:6px;margin-top:10px;">
        <button class="btn-secondary" onclick="document.getElementById('prdModal').remove();">Cancel</button>
        <button class="btn-primary" onclick="submitPRDEdit(${idAttr})">Save</button>
      </div>
    </div>
  `;
  _prdMountModal(html);
};

window.submitPRDEdit = function(id) {
  const title = document.getElementById('prdEditTitle')?.value || '';
  const spec = document.getElementById('prdEditSpec')?.value || '';
  apiFetch('/api/autonomous/prds/' + encodeURIComponent(id), {
    method: 'PATCH',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ title, spec, actor: 'operator' }),
  }).then(() => {
    document.getElementById('prdModal')?.remove();
    showToast('Automaton updated', 'success', 1500);
    _refreshAutomataOrPRD();
  }).catch(err => showToast('Automaton edit failed: ' + String(err), 'error', 3000));
};

// _refreshAutomataOrPRD — called after any PRD mutation; refreshes whichever
// panel is currently visible (Automata tab uses loadAutomataPanel, legacy
// views fall back to loadPRDPanel).
function _refreshAutomataOrPRD() {
  if (state.activeView === 'autonomous' && typeof loadAutomataPanel === 'function') {
    loadAutomataPanel();
  } else {
    loadPRDPanel();
  }
}

function prdAction(id, action, method, body) {
  const url = '/api/autonomous/prds/' + encodeURIComponent(id) + (action ? '/' + action : '');
  const opts = { method, headers: { 'Content-Type': 'application/json' } };
  if (body) opts.body = JSON.stringify(body);
  apiFetch(url, opts).then(() => { showToast('PRD action ok', 'success', 1500); _refreshAutomataOrPRD(); })
    .catch(err => showToast('Automaton action failed: ' + String(err), 'error', 3000));
}
window.prdAction = prdAction;

function prdActionPrompt(id, action, key, prompt) {
  const val = window.prompt(prompt, '');
  if (val === null) return;
  prdAction(id, action, 'POST', { actor: 'operator', [key]: val });
}
window.prdActionPrompt = prdActionPrompt;

// BL221 Phase 1B — lifecycle strip replacing the flat action button row.
// 5-step ordered sequence: Plan → Review → Approve → Run → Done.
// Overflow ⋯ menu: Edit, Delete, Archive (terminal only).
// renderPRDActions() is kept for the legacy renderPRDRow() path.
function _lifecycleOverflowToggle(id) {
  const menu = document.getElementById('lc-menu-' + id);
  if (!menu) return;
  const open = menu.classList.toggle('open');
  if (open) {
    const close = (e) => {
      if (!menu.contains(e.target)) { menu.classList.remove('open'); document.removeEventListener('click', close, true); }
    };
    setTimeout(() => document.addEventListener('click', close, true), 0);
  }
}
window._lifecycleOverflowToggle = _lifecycleOverflowToggle;

function renderLifecycleStrip(prd) {
  const id = prd.id || '';
  const idJ = escHtml(JSON.stringify(id));
  const status = prd.status || 'draft';
  const isTemplate = !!prd.is_template;
  if (isTemplate) {
    return `<div class="lifecycle-strip"><button class="lifecycle-step-btn clickable" onclick="openPRDInstantiateModal(${idJ})">${t('prd_action_instantiate')||'Instantiate'}</button></div>`;
  }

  // Step state helpers
  const steps = ['plan','review','approve','run','done'];
  const statusToStep = {
    draft: 'plan', planning: 'plan', revisions_asked: 'plan',
    needs_review: 'review',
    approved: 'approve',
    running: 'run',
    completed: 'done', rejected: 'done', cancelled: 'done', archived: 'done',
  };
  const currentStep = statusToStep[status] || 'plan';
  const stepIdx = steps.indexOf(currentStep);

  function stepClass(i) {
    if (i < stepIdx) return 'done';
    if (i === stepIdx) return 'current';
    return '';
  }

  const planLabel = status === 'revisions_asked' ? 'Re-plan' : 'Plan';
  const planAction = `prdAction(${idJ},'decompose','POST')`;
  const planDisabled = (status !== 'draft' && status !== 'revisions_asked') ? '' : 'clickable';

  // Plan step
  const planBtn = (() => {
    const cls = stepClass(0);
    if (cls === 'done') return `<button class="lifecycle-step-btn done" disabled title="${t('prd_step_planned_title')||'Planned'}">✓ ${t('prd_step_plan')||'Plan'}</button>`;
    if (cls === 'current') return `<button class="lifecycle-step-btn current clickable" onclick="${planAction}" title="${t('prd_step_run_planning')||'Run planning'}">▶ ${planLabel}</button>`;
    return `<button class="lifecycle-step-btn" disabled title="${t('prd_step_plan_first')||'Plan first'}">${t('prd_step_plan')||'Plan'}</button>`;
  })();

  // Review step
  const reviewBtn = (() => {
    const cls = stepClass(1);
    if (cls === 'done') return `<button class="lifecycle-step-btn done" disabled>✓ ${t('prd_step_review')||'Review'}</button>`;
    if (cls === 'current') return `<button class="lifecycle-step-btn current" disabled title="${t('prd_step_review_progress')||'Review in progress'}">${t('prd_step_review')||'Review'}</button>`;
    return `<button class="lifecycle-step-btn" disabled>${t('prd_step_review')||'Review'}</button>`;
  })();

  // Approve step — has sub-actions (Reject, Revise) inline
  const approveBtn = (() => {
    const cls = stepClass(2);
    if (cls === 'done') return `<button class="lifecycle-step-btn done" disabled>✓ ${t('prd_step_approve')||'Approve'}</button>`;
    if (cls === 'current') {
      const approveAct = `prdAction(${idJ},'approve','POST',{actor:'operator'})`;
      const rejectAct  = `prdActionPrompt(${idJ},'reject','reason','Rejection reason')`;
      const reviseAct  = `prdActionPrompt(${idJ},'request_revision','note','What needs revision?')`;
      return `<button class="lifecycle-step-btn current clickable" onclick="${approveAct}" title="${t('prd_step_approve')||'Approve'}">${t('prd_step_approve')||'Approve'}</button>` +
             `<button class="lifecycle-step-btn danger clickable" style="margin-left:2px;" onclick="${rejectAct}" title="${t('prd_action_reject')||'Reject'}">✗</button>` +
             `<button class="lifecycle-step-btn clickable" style="margin-left:2px;border-color:var(--warning);color:var(--warning);" onclick="${reviseAct}" title="${t('prd_action_request_revision')||'Request revision'}">↩</button>`;
    }
    return `<button class="lifecycle-step-btn" disabled>${t('prd_step_approve')||'Approve'}</button>`;
  })();

  // Run step
  const runBtn = (() => {
    const cls = stepClass(3);
    if (cls === 'done' && status !== 'running') return `<button class="lifecycle-step-btn done" disabled>✓ ${t('prd_step_run')||'Run'}</button>`;
    if (cls === 'current' && status === 'approved') return `<button class="lifecycle-step-btn current clickable" onclick="prdAction(${idJ},'run','POST')" title="${t('prd_step_run')||'Run'}">▶ ${t('prd_step_run')||'Run'}</button>`;
    if (status === 'running') return `<button class="lifecycle-step-btn current clickable danger" onclick="prdAction(${idJ},'','DELETE')" title="${t('prd_action_cancel_running')||'Cancel running'}">■ ${t('prd_action_cancel')||'Cancel'}</button>`;
    return `<button class="lifecycle-step-btn" disabled>${t('prd_step_run')||'Run'}</button>`;
  })();

  // Done step
  const doneBtn = (() => {
    if (status === 'completed') return `<button class="lifecycle-step-btn done" disabled title="${t('prd_status_completed')||'Completed'}">✓ ${t('prd_step_done')||'Done'}</button>`;
    if (status === 'rejected')  return `<button class="lifecycle-step-btn" style="border-color:var(--error);color:var(--error);" disabled>✗ ${t('prd_status_rejected')||'Rejected'}</button>`;
    if (status === 'cancelled') return `<button class="lifecycle-step-btn" disabled style="opacity:0.6;">${t('prd_status_cancelled')||'Cancelled'}</button>`;
    return `<button class="lifecycle-step-btn" disabled>${t('prd_step_done')||'Done'}</button>`;
  })();

  const sep = `<span class="lifecycle-sep">›</span>`;
  // v6.13.4 — operator's biggest issue: "how can I know what is done,
  // what needs to be done, and what is next". Add a plain-English
  // current-step hint above the strip so the workflow position is
  // obvious without parsing colors / chevrons.
  const currentLabels = {
    plan:    t('lifecycle_hint_plan')    || 'Next: Plan — break your spec into stories + tasks',
    review:  t('lifecycle_hint_review')  || 'Planning… review will become available shortly',
    approve: t('lifecycle_hint_approve') || 'Next: Review the plan and Approve / Reject / Revise',
    run:     status === 'running'
              ? (t('lifecycle_hint_running') || 'Running — Cancel below if needed')
              : (t('lifecycle_hint_run')     || 'Next: Run the approved automaton'),
    done:    {
      completed: t('lifecycle_hint_completed') || '✓ Completed',
      rejected:  t('lifecycle_hint_rejected')  || '✗ Rejected',
      cancelled: t('lifecycle_hint_cancelled') || 'Cancelled',
      archived:  t('lifecycle_hint_archived')  || 'Archived',
    }[status] || (t('lifecycle_hint_done') || '✓ Done'),
  };
  const currentHint = currentLabels[currentStep] || '';
  const hint = currentHint
    ? `<div class="lifecycle-strip-current">${escHtml(currentHint)}</div>`
    : '';
  const strip = hint + `<div class="lifecycle-strip">${planBtn}${sep}${reviewBtn}${sep}${approveBtn}${sep}${runBtn}${sep}${doneBtn}</div>`;

  // Overflow ⋯ menu
  const isTerminal = ['completed','rejected','cancelled','archived'].includes(status);
  const isRunning  = status === 'running';
  const editItem   = !isRunning
    ? `<button class="lifecycle-overflow-item" onclick="_lifecycleOverflowToggle(${idJ});openPRDEditModal(${idJ},${escHtml(JSON.stringify(prd.title||''))},${escHtml(JSON.stringify(prd.spec||''))})">Edit</button>`
    : '';
  const archiveItem = isTerminal && status !== 'archived'
    ? `<button class="lifecycle-overflow-item" onclick="_lifecycleOverflowToggle(${idJ});prdAction(${idJ},'archive','POST')">Archive</button>`
    : '';
  const cloneItem = `<button class="lifecycle-overflow-item" onclick="_lifecycleOverflowToggle(${idJ});openCloneToTemplateModal(${idJ})">Clone to Template…</button>`;
  const deleteItem = `<button class="lifecycle-overflow-item danger" onclick="_lifecycleOverflowToggle(${idJ});confirmPRDDelete(${idJ})">Delete</button>`;
  const llmItem = !isRunning && status !== 'completed'
    ? `<button class="lifecycle-overflow-item" onclick="_lifecycleOverflowToggle(${idJ});openPRDSetLLMModal(${idJ},${escHtml(JSON.stringify({backend:prd.backend||'',effort:String(prd.effort||''),model:prd.model||''}))})">Set LLM…</button>`
    : '';
  // v6.13.1 (C2) — operator: "since the buttons are there (and on all
  // stages of automata) the '...' dropdown isn't needed. make sure no
  // buttons are missing with this gone". Header toolbar (rendered by
  // _renderDetailHeader) carries Edit Spec / Settings / Request
  // Revision / Clone to Template / Delete; Archive moves into the
  // header toolbar too when terminal. Drop the overflow.
  const archiveBtn = isTerminal && status !== 'archived'
    ? `<button class="lifecycle-step-btn clickable" style="margin-left:4px;" onclick="prdAction(${idJ},'archive','POST')" title="${t('prd_action_archive')||'Archive'}">📦 ${t('prd_step_archive')||'Archive'}</button>`
    : '';
  return strip + archiveBtn;
}
window.renderLifecycleStrip = renderLifecycleStrip;

// BL203 (v5.4.x) — proper modal helpers replacing the v5.3.0 prompt()
// chains. Each modal opens with backend/effort/model dropdowns wired to
// the new SetPRDLLM / SetTaskLLM endpoints.
function _prdMountModal(html, onSubmit) {
  const existing = document.getElementById('prdModal');
  if (existing) existing.remove();
  const modal = document.createElement('div');
  modal.id = 'prdModal';
  // GATE alpha.36 (operator 2026-05-10): anchor the modal overlay inside
  // the .app container (which has position:relative) instead of <body>,
  // so the modal width is naturally bounded by the PWA shell — not the
  // browser viewport. The .app-anchored class applies position:absolute
  // (not fixed) and inherits the shell's width as the constraint, so
  // max-width:100% inside the modal honors the PWA edges.
  const host = document.querySelector('.app') || document.body;
  modal.className = 'confirm-modal-overlay app-anchored';
  modal.innerHTML = `<div class="response-modal" style="width:100%;max-width:100%;">${html}</div>`;
  modal.addEventListener('click', e => { if (e.target === modal) modal.remove(); });
  host.appendChild(modal);
  const form = document.getElementById('prdModalForm');
  if (form) form.addEventListener('submit', ev => {
    ev.preventDefault();
    onSubmit();
  });
}
function _prdCloseModal() { const m = document.getElementById('prdModal'); if (m) m.remove(); }

function openPRDCreateModal() {
  // v5.27.0 — operator-reported: backend should only show configured
  // backends; model should list available models for the selected
  // backend; if list isn't available, hide the model selector.
  // Pre-fetch backends + ollama + openwebui model lists in parallel.
  //
  // v5.26.20 — operator-reported: PRDs should be based on directory or
  // profile; PWA New PRD modal needs profile dropdowns. Fetch
  // /api/profiles/{projects,clusters} alongside the backend lists.
  const ensureBackends = state._prdBackends
    ? Promise.resolve()
    : fetch('/api/llms', { headers: tokenHeader() }).then(r => r.ok ? r.json() : null).then(d => { state._prdBackends = (d && d.llms || []).filter(l => !l.disabled); }).catch(() => {});
  const ensureModels = (state._availableModels !== undefined)
    ? Promise.resolve()
    : Promise.all([
        fetch('/api/ollama/models', { headers: tokenHeader() }).then(r => r.ok ? r.json() : null).catch(() => null),
        fetch('/api/openwebui/models', { headers: tokenHeader() }).then(r => r.ok ? r.json() : null).catch(() => null),
      ]).then(([oll, owui]) => {
        state._availableModels = {};
        if (oll && Array.isArray(oll.models)) state._availableModels.ollama = oll.models.map(m => m.name || m).filter(Boolean);
        else if (Array.isArray(oll)) state._availableModels.ollama = oll.map(m => m.name || m).filter(Boolean);
        if (owui && Array.isArray(owui.data)) state._availableModels.openwebui = owui.data.map(m => m.id || m.name || m).filter(Boolean);
        else if (Array.isArray(owui)) state._availableModels.openwebui = owui.map(m => m.id || m.name || m).filter(Boolean);
      });
  const ensureProfiles = Promise.all([
    fetch('/api/profiles/projects', { headers: tokenHeader() }).then(r => r.ok ? r.json() : null).catch(() => null),
    fetch('/api/profiles/clusters', { headers: tokenHeader() }).then(r => r.ok ? r.json() : null).catch(() => null),
  ]).then(([projs, clusters]) => {
    const projectsArr = Array.isArray(projs) ? projs : (projs && projs.projects) || (projs && projs.profiles) || [];
    const clustersArr = Array.isArray(clusters) ? clusters : (clusters && clusters.clusters) || (clusters && clusters.profiles) || [];
    state._prdProjectProfiles = projectsArr.map(p => p && (p.name || p)).filter(Boolean);
    state._prdClusterProfiles = clustersArr.map(c => c && (c.name || c)).filter(Boolean);
  });
  Promise.all([ensureBackends, ensureModels, ensureProfiles]).then(() => {
    // v5.26.30 — operator-asked: collapse the three separate fields
    // (project_dir / project_profile / cluster_profile) into a single
    // "Profile" dropdown. The first option is the explicit
    // project_dir mode (operator types a path); subsequent options
    // are configured project profiles. When a profile is selected,
    // backend + effort are inherited from the profile's image_pair
    // so we hide those rows; cluster dropdown becomes required.
    const profileOpts = ['<option value="__dir__">— project directory (local checkout) —</option>']
      .concat((state._prdProjectProfiles || []).map(n => `<option value="${escHtml(n)}">${escHtml(n)}</option>`));
    // v5.26.34 — operator clarification: when a project profile is
    // selected, the cluster dropdown's first option is "Local service
    // instance" (empty value = daemon-side clone + local tmux
    // session). A real Cluster Profile is only required when the
    // operator specifically wants to dispatch to a remote cluster.
    const clusterProfileOpts = ['<option value="">— Local service instance (daemon-side) —</option>']
      .concat((state._prdClusterProfiles || []).map(n => `<option value="${escHtml(n)}">${escHtml(n)}</option>`));
    _prdMountModal(`
      <div class="response-modal-header">
        <strong>${t('prd_new_title')||'New Automaton'}</strong>
        <button class="btn-icon" onclick="_prdCloseModal()" title="${t('btn_close')||'Close'}">&#10005;</button>
      </div>
      <form id="prdModalForm" class="response-modal-body" style="display:flex;flex-direction:column;gap:8px;">
        <label style="font-size:11px;color:var(--text2);">${t('prd_new_title_label')||'Title (optional)'}</label>
        <input id="prdNewTitle" type="text" class="form-input" placeholder="${t('prd_new_title_ph')||'Short headline'}" />
        <label style="font-size:11px;color:var(--text2);display:flex;align-items:center;gap:4px;">${t('prd_new_spec_label')||'Spec — describe the feature in plain English'} ${micButtonHTML('prdNewSpec')}</label>
        <textarea id="prdNewSpec" class="form-input" rows="6" placeholder="${t('prd_new_spec_ph')||'Add a CACHE column to /api/stats…'}" style="resize:vertical;font-family:inherit;"></textarea>
        <label style="font-size:11px;color:var(--text2);">${t('new_session_profile_label')||'Profile'}</label>
        <select id="prdNewProfile" class="form-select" style="font-size:11px;padding:1px 4px;" onchange="_prdNewProfileChanged()">${profileOpts.join('')}</select>
        <div id="prdNewDirRow">
          <label style="font-size:11px;color:var(--text2);">${t('new_session_dir_label')||'Project directory'}</label>
          <!-- v5.26.46 — operator-asked: directory selector like New
               Session, with "+ New folder" affordance. Reuses the
               existing dir-browser pattern; #selectedDirDisplay +
               #dirBrowser are singletons in the DOM and the modals
               (new-session vs. new-PRD) are mutually exclusive
               by view, so collision is fine. -->
          <div class="dir-picker">
            <span id="selectedDirDisplay" class="dir-display dir-display-clickable" onclick="openDirBrowser()" title="Click to browse">~/</span>
          </div>
          <div id="dirBrowser" class="dir-browser" style="display:none">
            <div id="dirBrowserContent"></div>
          </div>
        </div>
        <div id="prdNewClusterRow" style="display:none;">
          <label style="font-size:11px;color:var(--text2);">${t('new_session_cluster_label')||'Cluster'}</label>
          <select id="prdNewClusterProfile" class="form-select" style="font-size:11px;padding:1px 4px;">${clusterProfileOpts.join('')}</select>
        </div>
        <div id="prdNewBackendRow" style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:6px;">
          <div><label style="font-size:11px;color:var(--text2);">${t('prd_new_backend_label')||'Backend'}</label>${renderBackendSelect('prdNewBackend', '', 'updatePRDNewModelField()')}</div>
          <div><label style="font-size:11px;color:var(--text2);">${t('prd_new_effort_label')||'Effort'}</label>${renderEffortSelect('prdNewEffort', '', '')}</div>
          <div id="prdNewModelWrap" style="display:none;"><label style="font-size:11px;color:var(--text2);">${t('prd_new_model_label')||'Model (optional)'}</label><div id="prdNewModelInner"></div></div>
        </div>
        <div style="display:flex;gap:6px;justify-content:flex-end;">
          <button type="button" class="btn-secondary" onclick="_prdCloseModal()">${t('btn_cancel')||'Cancel'}</button>
          <button type="submit" class="btn-secondary" style="background:var(--accent2);color:#fff;">${t('btn_create')||'Create'}</button>
        </div>
      </form>
    `, () => {
      const spec = document.getElementById('prdNewSpec').value.trim();
      if (!spec) { showToast('Spec required', 'error', 2000); return; }
      const profileSel = document.getElementById('prdNewProfile').value;
      const usingProfile = profileSel && profileSel !== '__dir__';
      const projectProfile = usingProfile ? profileSel : '';
      const clusterProfile = usingProfile ? document.getElementById('prdNewClusterProfile').value : '';
      // v5.26.46 — pull from the dir-picker. newSessionState.selectedDir
      // is set by selectDir() (shared with New Session); when nothing has
      // been selected, fall back to the display span's textContent (the
      // "~/" placeholder, which we treat as empty).
      let projectDir = '';
      if (!usingProfile) {
        const sel = (typeof newSessionState !== 'undefined' && newSessionState.selectedDir) || '';
        const disp = document.getElementById('selectedDirDisplay');
        const dispTxt = disp ? disp.textContent.trim() : '';
        projectDir = sel || (dispTxt && dispTxt !== '~/' ? dispTxt : '');
      }
      // v5.26.34 — operator clarification: empty cluster_profile
      // means "local service instance" (daemon-side clone + local
      // tmux). Only validate that a cluster pick was made if the
      // operator is dispatching to a remote cluster — and that's
      // simply whatever the operator picks. So no required-field
      // check on cluster_profile when a project_profile is selected.
      // Dir mode still requires a path.
      if (!usingProfile) {
        if (!projectDir) {
          showToast('Enter a project directory', 'error', 2500);
          return;
        }
      }
      const body = {
        spec,
        title: document.getElementById('prdNewTitle').value.trim(),
        project_dir: projectDir,
        project_profile: projectProfile,
        cluster_profile: clusterProfile,
        // Backend/effort only set when running in dir mode — profile
        // mode inherits the worker LLM from the profile's image_pair.
        backend: usingProfile ? '' : document.getElementById('prdNewBackend').value,
        effort: usingProfile ? '' : document.getElementById('prdNewEffort').value,
      };
      // v5.27.0 — model field is dynamic (input or select inside
      // prdNewModelInner) and may be hidden entirely when no model
      // list is available for the selected backend.
      const modelEl = document.getElementById('prdNewModelInner')?.querySelector('input,select');
      const model = modelEl ? modelEl.value.trim() : '';
      apiFetch('/api/autonomous/prds', {
        method: 'POST', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
      }).then(prd => {
        // PRD-level LLM (backend/effort already in create payload — model
        // and any consolidation goes through set_llm so the audit trail
        // gets the full triple).
        if (model || body.backend || body.effort) {
          return apiFetch('/api/autonomous/prds/' + encodeURIComponent(prd.id) + '/set_llm', {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ backend: body.backend, effort: body.effort, model, actor: 'operator' }),
          });
        }
      }).then(() => { showToast('PRD created', 'success', 1500); _prdCloseModal(); _refreshAutomataOrPRD(); })
        .catch(err => showToast('Create failed: ' + String(err), 'error', 3000));
    });
  });
}
window.openPRDCreateModal = openPRDCreateModal;

// v5.26.30 — toggle dir-vs-cluster row when the unified Profile
// dropdown changes. Profile mode hides the path input + the
// backend/effort row (profile carries the worker LLM); dir mode
// hides the cluster dropdown.
function _prdNewProfileChanged() {
  const sel = document.getElementById('prdNewProfile');
  if (!sel) return;
  const usingProfile = sel.value && sel.value !== '__dir__';
  const dirRow = document.getElementById('prdNewDirRow');
  const clusterRow = document.getElementById('prdNewClusterRow');
  const backendRow = document.getElementById('prdNewBackendRow');
  if (dirRow) dirRow.style.display = usingProfile ? 'none' : '';
  if (clusterRow) clusterRow.style.display = usingProfile ? '' : 'none';
  if (backendRow) backendRow.style.display = usingProfile ? 'none' : '';
}
window._prdNewProfileChanged = _prdNewProfileChanged;

// v5.27.0 — operator-reported: New PRD model field should list models
// available for the selected backend. Hide entirely when the backend
// has no known model list.
//
// v5.26.8 — generalized into refreshLLMModelField(wrapId, innerId,
// backendId, currentValue) so the same dynamic-dropdown pattern works
// in the per-PRD and per-task LLM modals too. updatePRDNewModelField
// stays as a thin wrapper for backwards compat with the existing
// `onchange` hook in renderBackendSelect.
window.refreshLLMModelField = function(wrapId, innerId, backendId, currentValue) {
  const wrap = document.getElementById(wrapId);
  const inner = document.getElementById(innerId);
  const backendEl = document.getElementById(backendId);
  if (!wrap || !inner || !backendEl) return;
  const backend = backendEl.value || '';
  const models = (state._availableModels || {})[backend] || [];
  if (!backend || models.length === 0) {
    wrap.style.display = 'none';
    inner.innerHTML = '';
    return;
  }
  wrap.style.display = '';
  // Preserve a model that the operator already had set when toggling
  // backends — surface as "(custom: <name>)" if it isn't in the list.
  let foundCurrent = false;
  const opts = ['<option value="">(backend default)</option>'];
  for (const m of models) {
    const sel = (currentValue && m === currentValue) ? ' selected' : '';
    if (sel) foundCurrent = true;
    opts.push(`<option value="${escHtml(m)}"${sel}>${escHtml(m)}</option>`);
  }
  if (currentValue && !foundCurrent) {
    opts.push(`<option value="${escHtml(currentValue)}" selected>(custom) ${escHtml(currentValue)}</option>`);
  }
  inner.innerHTML = `<select class="form-select" style="font-size:12px;width:100%;">${opts.join('')}</select>`;
};

window.updatePRDNewModelField = function() {
  refreshLLMModelField('prdNewModelWrap', 'prdNewModelInner', 'prdNewBackend', '');
};

// v5.26.8 — ensure /api/ollama/models + /api/openwebui/models are
// in state._availableModels. Used by the per-PRD + per-task LLM
// modals to populate the dropdown on open. openPRDCreateModal already
// pre-fetched these inline; the helper hoists the same logic so the
// edit-task and set-llm modals don't have to duplicate it.
window.ensureLLMModelLists = function() {
  if (state._availableModels !== undefined) return Promise.resolve();
  return Promise.all([
    fetch('/api/ollama/models', { headers: tokenHeader() }).then(r => r.ok ? r.json() : null).catch(() => null),
    fetch('/api/openwebui/models', { headers: tokenHeader() }).then(r => r.ok ? r.json() : null).catch(() => null),
  ]).then(([oll, owui]) => {
    state._availableModels = {};
    if (oll && Array.isArray(oll.models)) state._availableModels.ollama = oll.models.map(m => m.name || m).filter(Boolean);
    else if (Array.isArray(oll)) state._availableModels.ollama = oll.map(m => m.name || m).filter(Boolean);
    if (owui && Array.isArray(owui.data)) state._availableModels.openwebui = owui.data.map(m => m.id || m.name || m).filter(Boolean);
    else if (Array.isArray(owui)) state._availableModels.openwebui = owui.map(m => m.id || m.name || m).filter(Boolean);
  });
};

function openPRDEditTaskModal(prdID, taskID, currentSpec, currentBackend, currentEffort, currentModel) {
  // v5.26.8 — populate the model dropdown as soon as the modal mounts,
  // and refresh it every time the operator switches backends.
  ensureLLMModelLists().then(() => {
    _prdMountModal(`
    <div class="response-modal-header">
      <strong>${t('prd_edit_task_title_prefix')||'Edit task'} ${escHtml(taskID)}</strong>
      <button class="btn-icon" onclick="_prdCloseModal()" title="${t('btn_close')||'Close'}">&#10005;</button>
    </div>
    <form id="prdModalForm" class="response-modal-body" style="display:flex;flex-direction:column;gap:8px;">
      <label style="font-size:11px;color:var(--text2);display:flex;align-items:center;gap:4px;">${t('prd_spec_label')||'Spec'} ${micButtonHTML('prdEditSpec')}</label>
      <textarea id="prdEditSpec" class="form-input" rows="6" style="resize:vertical;font-family:inherit;">${escHtml(currentSpec || '')}</textarea>
      <div style="font-size:10px;color:var(--text2);">${t('prd_task_llm_hint')||'Per-task LLM override — empty inherits Automaton then global.'}</div>
      <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:6px;">
        <div><label style="font-size:11px;color:var(--text2);">${t('prd_new_backend_label')||'Backend'}</label>${renderBackendSelect('prdEditBackend', currentBackend || '', `refreshLLMModelField('prdEditModelWrap','prdEditModelInner','prdEditBackend',${JSON.stringify(currentModel || '')})`)}</div>
        <div><label style="font-size:11px;color:var(--text2);">${t('prd_new_effort_label')||'Effort'}</label>${renderEffortSelect('prdEditEffort', currentEffort || '', '')}</div>
        <div id="prdEditModelWrap" style="display:none;"><label style="font-size:11px;color:var(--text2);">${t('prd_new_model_label')||'Model (optional)'}</label><div id="prdEditModelInner"></div></div>
      </div>
      <div style="display:flex;gap:6px;justify-content:flex-end;">
        <button type="button" class="btn-secondary" onclick="_prdCloseModal()">${t('btn_cancel')||'Cancel'}</button>
        <button type="submit" class="btn-secondary" style="background:var(--accent2);color:#fff;">${t('btn_save')||'Save'}</button>
      </div>
    </form>
  `, () => {
    const newSpec = document.getElementById('prdEditSpec').value;
    const backend = document.getElementById('prdEditBackend').value;
    const effort = document.getElementById('prdEditEffort').value;
    const modelEl = document.getElementById('prdEditModelInner')?.querySelector('input,select');
    const model = modelEl ? modelEl.value.trim() : '';
    const calls = [];
    if (newSpec !== currentSpec) {
      calls.push(apiFetch('/api/autonomous/prds/' + encodeURIComponent(prdID) + '/edit_task', {
        method: 'POST', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ task_id: taskID, new_spec: newSpec, actor: 'operator' }),
      }));
    }
    if (backend !== (currentBackend || '') || effort !== (currentEffort || '') || model !== (currentModel || '')) {
      calls.push(apiFetch('/api/autonomous/prds/' + encodeURIComponent(prdID) + '/set_task_llm', {
        method: 'POST', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ task_id: taskID, backend, effort, model, actor: 'operator' }),
      }));
    }
    if (calls.length === 0) { _prdCloseModal(); return; }
    Promise.all(calls)
      .then(() => { showToast('Task updated', 'success', 1500); _prdCloseModal(); _refreshAutomataOrPRD(); })
      .catch(err => showToast('Save failed: ' + String(err), 'error', 3000));
  });
  // Populate the model dropdown for the current backend now that
  // the modal is mounted in the DOM.
  refreshLLMModelField('prdEditModelWrap', 'prdEditModelInner', 'prdEditBackend', currentModel || '');
  });
}
window.openPRDEditTaskModal = openPRDEditTaskModal;

// v5.26.32 — operator-asked: "i don't see a story review or
// approval or story edit option." The story edit modal mirrors the
// task edit modal but only takes title + description (no LLM
// override at the story level — that's a future phase 3 item per
// docs/plans/2026-04-27-v6-prep-backlog.md).
function openPRDEditStoryModal(prdID, storyID, currentTitle, currentDescription) {
  _prdMountModal(`
    <div class="response-modal-header">
      <strong>${t('prd_edit_story_title_prefix')||'Edit story'} ${escHtml(storyID)}</strong>
      <button class="btn-icon" onclick="_prdCloseModal()" title="${t('btn_close')||'Close'}">&#10005;</button>
    </div>
    <form id="prdModalForm" class="response-modal-body" style="display:flex;flex-direction:column;gap:8px;">
      <label style="font-size:11px;color:var(--text2);">${t('prd_story_title_label')||'Title'}</label>
      <input id="prdEditStoryTitle" type="text" class="form-input" value="${escHtml(currentTitle || '')}" />
      <label style="font-size:11px;color:var(--text2);display:flex;align-items:center;gap:4px;">${t('prd_story_desc_label')||'Description'} ${micButtonHTML('prdEditStoryDesc')}</label>
      <textarea id="prdEditStoryDesc" class="form-input" rows="5" style="resize:vertical;font-family:inherit;">${escHtml(currentDescription || '')}</textarea>
      <div style="display:flex;gap:6px;justify-content:flex-end;">
        <button type="button" class="btn-secondary" onclick="_prdCloseModal()">${t('btn_cancel')||'Cancel'}</button>
        <button type="submit" class="btn-secondary" style="background:var(--accent2);color:#fff;">${t('btn_save')||'Save'}</button>
      </div>
    </form>
  `, () => {
    const newTitle = document.getElementById('prdEditStoryTitle').value.trim();
    const newDesc = document.getElementById('prdEditStoryDesc').value;
    if (newTitle === (currentTitle || '') && newDesc === (currentDescription || '')) {
      _prdCloseModal();
      return;
    }
    if (!newTitle && !newDesc) {
      showToast('Story needs at least a title or description', 'error', 2000);
      return;
    }
    apiFetch('/api/autonomous/prds/' + encodeURIComponent(prdID) + '/edit_story', {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        story_id: storyID,
        new_title: newTitle === (currentTitle || '') ? '' : newTitle,
        new_description: newDesc === (currentDescription || '') ? '' : newDesc,
        actor: 'operator',
      }),
    })
      .then(() => { showToast('Story updated', 'success', 1500); _prdCloseModal(); _refreshAutomataOrPRD(); })
      .catch(err => showToast('Save failed: ' + String(err), 'error', 3000));
  });
}
window.openPRDEditStoryModal = openPRDEditStoryModal;

function openPRDSetLLMModal(prdID, current) {
  // v5.26.8 — same dynamic model dropdown pattern as the New PRD and
  // Edit Task modals.
  ensureLLMModelLists().then(() => {
    _prdMountModal(`
    <div class="response-modal-header">
      <strong>${t('prd_set_llm_title')||'Automaton-level worker LLM'}</strong>
      <button class="btn-icon" onclick="_prdCloseModal()" title="${t('btn_close')||'Close'}">&#10005;</button>
    </div>
    <form id="prdModalForm" class="response-modal-body" style="display:flex;flex-direction:column;gap:8px;">
      <div style="font-size:11px;color:var(--text2);">${t('prd_set_llm_hint')||'Tasks without a per-task override inherit these values. Empty = fall back to the global session.backend_family default.'}</div>
      <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:6px;">
        <div><label style="font-size:11px;color:var(--text2);">${t('prd_new_backend_label')||'Backend'}</label>${renderBackendSelect('prdSetBackend', current.backend || '', `refreshLLMModelField('prdSetModelWrap','prdSetModelInner','prdSetBackend',${JSON.stringify(current.model || '')})`)}</div>
        <div><label style="font-size:11px;color:var(--text2);">${t('prd_new_effort_label')||'Effort'}</label>${renderEffortSelect('prdSetEffort', current.effort || '', '')}</div>
        <div id="prdSetModelWrap" style="display:none;"><label style="font-size:11px;color:var(--text2);">${t('prd_new_model_label')||'Model (optional)'}</label><div id="prdSetModelInner"></div></div>
      </div>
      <div style="display:flex;gap:6px;justify-content:flex-end;">
        <button type="button" class="btn-secondary" onclick="_prdCloseModal()">${t('btn_cancel')||'Cancel'}</button>
        <button type="submit" class="btn-secondary" style="background:var(--accent2);color:#fff;">${t('btn_save')||'Save'}</button>
      </div>
    </form>
  `, () => {
    const modelEl = document.getElementById('prdSetModelInner')?.querySelector('input,select');
    const body = {
      backend: document.getElementById('prdSetBackend').value,
      effort: document.getElementById('prdSetEffort').value,
      model: modelEl ? modelEl.value.trim() : '',
      actor: 'operator',
    };
    apiFetch('/api/autonomous/prds/' + encodeURIComponent(prdID) + '/set_llm', {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
    }).then(() => { showToast('PRD LLM updated', 'success', 1500); _prdCloseModal(); _refreshAutomataOrPRD(); })
      .catch(err => showToast('Save failed: ' + String(err), 'error', 3000));
  });
  // Populate the model dropdown for the current backend now that the
  // modal is mounted.
  refreshLLMModelField('prdSetModelWrap', 'prdSetModelInner', 'prdSetBackend', current.model || '');
  });
}
window.openPRDSetLLMModal = openPRDSetLLMModal;
window._prdCloseModal = _prdCloseModal;

// BL246 v6.6.0 — unified PRD Settings modal: type, backend, effort, model,
// skills, guided_mode in one place. Splits "edit spec" (handled by
// openPRDEditModal) from non-spec settings so each form stays small and
// readable.
function openPRDSettingsModal(prdID) {
  apiFetch('/api/autonomous/prds/' + encodeURIComponent(prdID))
    .then(prd => {
      const cur = {
        type:        prd.type || '',
        backend:     prd.backend || '',
        effort:      prd.effort || '',
        model:       prd.model || '',
        skills:      (prd.skills || []).join(', '),
        guided_mode: !!prd.guided_mode,
      };
      ensureLLMModelLists().then(() => {
        _prdMountModal(`
          <div class="response-modal-header">
            <strong>${escHtml(t('prd_settings_modal_title')||'Automaton settings')}</strong>
            <button class="btn-icon" onclick="_prdCloseModal()" title="${escHtml(t('btn_close')||'Close')}">&#10005;</button>
          </div>
          <!-- v6.7.5 — gap tightened from 10px to 6px; field-group internal
               spacing standardised; footer separated by a thin border + 6px
               margin so it reads as a clear action row, not another field. -->
          <!-- v6.13.2 — operator: "edit dialog has large space in rows
               between every element". Using the same wizard-mobile shape
               so spacing matches the new-automaton wizard. -->
          <form id="prdModalForm" class="response-modal-body wizard-mobile prd-settings-modal" style="display:flex;flex-direction:column;gap:6px;">
            <div class="wizard-field">
              <label class="wizard-label">${escHtml(t('prd_settings_type_label')||'Type')}</label>
              <select id="prdSettingsType" class="form-select">
                <option value="" ${!cur.type?'selected':''}>—</option>
                ${['software','research','operational','personal'].map(v => `<option value="${v}" ${cur.type===v?'selected':''}>${v}</option>`).join('')}
              </select>
            </div>
            <div class="wizard-grid-mobile">
              <div class="wizard-field">
                <label class="wizard-label">${escHtml(t('prd_new_backend_label')||'Backend')}</label>
                ${renderBackendSelect('prdSettingsBackend', cur.backend, `refreshLLMModelField('prdSettingsModelWrap','prdSettingsModelInner','prdSettingsBackend',${JSON.stringify(cur.model)})`)}
              </div>
              <div class="wizard-field">
                <label class="wizard-label">${escHtml(t('prd_new_effort_label')||'Effort')}</label>
                ${renderEffortSelect('prdSettingsEffort', cur.effort, '')}
              </div>
              <div class="wizard-field" id="prdSettingsModelWrap" style="display:none;">
                <label class="wizard-label">${escHtml(t('prd_new_model_label')||'Model (optional)')}</label>
                <div id="prdSettingsModelInner"></div>
              </div>
            </div>
            <!-- v6.13.4 — operator: "skills should be a selectable list
                 from what is installed... if no skills installed say
                 no skills available". + "Message under skills selector
                 isn't necessary". Render a chip-picker that loads from
                 /api/skills; empty state shows "No skills available". -->
            <div class="wizard-field">
              <label class="wizard-label">${escHtml(t('prd_settings_skills_label')||'Skills')}</label>
              <div id="prdSettingsSkillsPicker" class="skill-chip-picker" data-current="${escHtml(cur.skills)}">
                <span style="color:var(--text2);font-size:11px;">${escHtml(t('common_loading')||'Loading…')}</span>
              </div>
              <input id="prdSettingsSkills" type="hidden" value="${escHtml(cur.skills)}" />
            </div>
            <!-- v6.13.2 — operator: "guided mode is weirdly right justified
                 but checkbox is left". Switched to a single .wizard-checkbox-row
                 with the iOS-style switch (per the global mobile-first
                 pattern); checkbox + label flow left-to-right naturally. -->
            <label class="wizard-checkbox-row" style="margin-top:4px;">
              <input type="checkbox" id="prdSettingsGuidedMode" ${cur.guided_mode?'checked':''}>
              <span>${escHtml(t('prd_settings_guided_label')||'Guided mode — pause for operator after each story for review')}</span>
            </label>
            <div style="display:flex;gap:6px;justify-content:flex-end;margin-top:6px;padding-top:8px;border-top:1px solid var(--border);">
              <button type="button" class="btn-secondary" onclick="_prdCloseModal()">${escHtml(t('btn_cancel')||'Cancel')}</button>
              <button type="submit" class="btn-secondary" style="background:var(--accent2);color:#fff;">${escHtml(t('btn_save')||'Save')}</button>
            </div>
          </form>
        `, () => {
          const newType = document.getElementById('prdSettingsType').value;
          const newBackend = document.getElementById('prdSettingsBackend').value;
          const newEffort = document.getElementById('prdSettingsEffort').value;
          const modelEl = document.getElementById('prdSettingsModelInner')?.querySelector('input,select');
          const newModel = modelEl ? modelEl.value.trim() : '';
          // v6.13.4 — read skills from the chip-picker hidden input
          // (populated by _renderSkillChipPicker on toggle).
          const newSkills = (document.getElementById('prdSettingsSkills').value || '').split(',').map(s => s.trim()).filter(Boolean);
          const newGuided = !!document.getElementById('prdSettingsGuidedMode').checked;

          const calls = [];
          if (newType !== cur.type) {
            calls.push(apiFetch('/api/autonomous/prds/' + encodeURIComponent(prdID) + '/set_type', {
              method: 'POST', headers: {'Content-Type':'application/json'},
              body: JSON.stringify({ type: newType, actor: 'operator' }),
            }));
          }
          if (newBackend !== cur.backend || newEffort !== cur.effort || newModel !== cur.model) {
            calls.push(apiFetch('/api/autonomous/prds/' + encodeURIComponent(prdID) + '/set_llm', {
              method: 'POST', headers: {'Content-Type':'application/json'},
              body: JSON.stringify({ backend: newBackend, effort: newEffort, model: newModel, actor: 'operator' }),
            }));
          }
          const skillsChanged = JSON.stringify(newSkills) !== JSON.stringify((prd.skills || []));
          if (skillsChanged) {
            calls.push(apiFetch('/api/autonomous/prds/' + encodeURIComponent(prdID) + '/set_skills', {
              method: 'POST', headers: {'Content-Type':'application/json'},
              body: JSON.stringify({ skills: newSkills, actor: 'operator' }),
            }));
          }
          if (newGuided !== cur.guided_mode) {
            calls.push(apiFetch('/api/autonomous/prds/' + encodeURIComponent(prdID) + '/set_guided_mode', {
              method: 'POST', headers: {'Content-Type':'application/json'},
              body: JSON.stringify({ guided_mode: newGuided, actor: 'operator' }),
            }));
          }
          if (calls.length === 0) { _prdCloseModal(); return; }
          Promise.all(calls)
            .then(() => { showToast(t('prd_settings_saved')||'Settings saved', 'success', 1500); _prdCloseModal(); _refreshAutomataOrPRD(); })
            .catch(err => showToast((t('prd_settings_save_failed')||'Save failed') + ': ' + String(err), 'error', 3000));
        });
        // Populate the model dropdown for the current backend now that the modal is mounted.
        refreshLLMModelField('prdSettingsModelWrap', 'prdSettingsModelInner', 'prdSettingsBackend', cur.model);
      });
    })
    .catch(err => showToast('Failed to load automaton: ' + String(err), 'error', 3000));
}
// v6.13.5 — operator: "clicking settings doesn't do anything".
// Root cause: my v6.13.4 wrapper assigned a new function to
// window.openPRDSettingsModal that called the unqualified name
// openPRDSettingsModal(prdID) — which resolves through the window
// global to the wrapper itself → infinite recursion → JS error →
// Settings dial silently fails. Save a reference to the original
// function before reassignment so the wrapper calls the inner impl.
const _origOpenPRDSettingsModal = openPRDSettingsModal;
window.openPRDSettingsModal = function(prdID) {
  _origOpenPRDSettingsModal(prdID);
  // Populate the skill chip picker after the modal has mounted.
  setTimeout(() => _renderSkillChipPicker('prdSettingsSkillsPicker', 'prdSettingsSkills'), 50);
};

// v6.13.4 — operator-directed skill chip picker. Loads the synced
// skills via /api/skills, renders each as a togglable chip, and writes
// the comma-joined selection back to the hidden input. Empty-state
// renders "No skills available — sync via Settings → Automate → Skill
// Registries". Call from a setTimeout AFTER the modal mounts.
function _renderSkillChipPicker(containerId, hiddenInputId) {
  const container = document.getElementById(containerId);
  const hidden = document.getElementById(hiddenInputId);
  if (!container || !hidden) return;
  const current = new Set(
    (hidden.value || '').split(',').map(s => s.trim()).filter(Boolean)
  );
  apiFetch('/api/skills').then(resp => {
    const skills = (resp && (resp.skills || resp)) || [];
    if (!Array.isArray(skills) || skills.length === 0) {
      container.innerHTML = `<span style="color:var(--text2);font-size:12px;">${escHtml(t('skills_none_available')||'No skills available — sync via Settings → Automate → Skill Registries.')}</span>`;
      return;
    }
    const renderChips = () => {
      container.innerHTML = skills.map(s => {
        const name = (s && (s.name || s.id || s)) || '';
        if (!name) return '';
        const on = current.has(name);
        const cls = on ? 'skill-chip selected' : 'skill-chip';
        return `<button type="button" class="${cls}" data-name="${escHtml(name)}" onclick="_toggleSkillChip(this,'${escHtml(containerId)}','${escHtml(hiddenInputId)}')">${escHtml(name)}</button>`;
      }).filter(Boolean).join('');
    };
    renderChips();
  }).catch(() => {
    container.innerHTML = `<span style="color:var(--text2);font-size:12px;">${escHtml(t('skills_load_failed')||'Could not load skills.')}</span>`;
  });
}
window._renderSkillChipPicker = _renderSkillChipPicker;

window._toggleSkillChip = function(btn, containerId, hiddenInputId) {
  const name = btn.getAttribute('data-name');
  const hidden = document.getElementById(hiddenInputId);
  if (!hidden) return;
  const current = new Set(
    (hidden.value || '').split(',').map(s => s.trim()).filter(Boolean)
  );
  if (current.has(name)) { current.delete(name); btn.classList.remove('selected'); }
  else { current.add(name); btn.classList.add('selected'); }
  hidden.value = [...current].join(',');
};

function openPRDInstantiateModal(templateID) {
  const varsCSV = window.prompt('Template vars (k=v,k=v):', '') || '';
  const vars = {};
  varsCSV.split(',').forEach(kv => { const i = kv.indexOf('='); if (i > 0) vars[kv.slice(0,i).trim()] = kv.slice(i+1).trim(); });
  apiFetch('/api/autonomous/prds/' + encodeURIComponent(templateID) + '/instantiate', {
    method: 'POST', headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ vars, actor: 'operator' }),
  }).then(() => { showToast('Template instantiated', 'success', 1500); _refreshAutomataOrPRD(); })
    .catch(err => showToast('Instantiate failed: ' + String(err), 'error', 3000));
}
window.openPRDInstantiateModal = openPRDInstantiateModal;

function toggleLLM(cfgKey, enabled, name) {
  if (!cfgKey) return;
  fetch('/api/config', {
    method: 'PUT',
    headers: { 'Content-Type': 'application/json', ...tokenHeader() },
    body: JSON.stringify({ [cfgKey]: enabled }),
  })
    .then(r => {
      if (r.ok) {
        showToast(name + (enabled ? ' enabled' : ' disabled'), 'success', 2000);
        loadLLMTabConfig();
      } else showToast('Save failed', 'error');
    })
    .catch(() => showToast('Save failed', 'error'));
}

function openLLMSetup(name) {
  // Session-backend kinds: settings live in the LLM registry now.
  if (_llmSessionBackendKinds && _llmSessionBackendKinds.has(name)) {
    apiFetch('/api/llms/' + encodeURIComponent(name))
      .then(llm => openLLMEditPanel(llm))
      .catch(() => openLLMEditPanel({ name, kind: name }));
    return;
  }
  const section = LLM_CFG_SECTION[name];
  if (!section) { showToast('No config fields for ' + name, 'info'); return; }
  fetch('/api/config', { headers: tokenHeader() })
    .then(r => {
      if (!r.ok) throw new Error('HTTP ' + r.status);
      return r.json();
    })
    .then(cfg => {
      const fields = LLM_FIELDS[name] || [];
      const sectionCfg = cfg[section] || {};
      showBackendConfigPopup(section, sectionCfg, fields, name);
    })
    .catch(err => {
      console.error('openLLMSetup error:', err);
      showToast('Failed to load config: ' + err.message, 'error');
    });
}

function setActiveLLM(name) {
  fetch('/api/config', {
    method: 'PUT',
    headers: { 'Content-Type': 'application/json', ...tokenHeader() },
    body: JSON.stringify({ 'session.backend_family': name }),
  })
    .then(r => r.ok ? loadLLMTabConfig() : showToast('Save failed', 'error'))
    .catch(() => showToast('Save failed', 'error'));
}

