window.openTemplateInstantiateModal = function(id) {
  apiFetch('/api/autonomous/templates/' + encodeURIComponent(id))
    .then(tmpl => {
      const vars = tmpl.vars || [];
      const varFields = vars.map(v => `
        <div style="margin-bottom:6px;">
          <label style="font-size:11px;font-weight:600;color:var(--text2);">${escHtml(v.name)}${v.required ? ' *' : ''}</label>
          ${v.description ? `<div style="font-size:10px;color:var(--text2);margin-bottom:2px;">${escHtml(v.description)}</div>` : ''}
          <input id="tmplVar_${escHtml(v.name)}" type="text" class="form-input" placeholder="${escHtml(v.default||'')}" style="font-size:13px;width:100%;box-sizing:border-box;">
        </div>
      `).join('');
      showModal({
        title: t('automata_tmpl_modal_use').replace('%s', tmpl.title||''),
        body: `
          <div style="display:flex;flex-direction:column;gap:6px;">
            ${vars.length ? `<div style="font-size:12px;font-weight:600;margin-bottom:4px;">${escHtml(t('automata_tmpl_vars_label'))}</div>${varFields}` : ''}
            <input id="tmplInstDir" type="text" class="form-input" placeholder="${escHtml(t('automata_wizard_workspace'))}" style="font-size:13px;">
            <select id="tmplInstBackend" class="form-input" style="font-size:13px;">
              <option value="">${escHtml(t('automata_wizard_backend_default'))}</option>
              ${(state._prdBackends||[]).filter(b=>b&&(b.name||typeof b==='string')&&!NON_LLM_BACKENDS.has(b.name||b)).map(b=>{const n=typeof b==='string'?b:b.name;return `<option value="${escHtml(n)}">${escHtml(n)}</option>`;}).join('')}
            </select>
            <select id="tmplInstEffort" class="form-input" style="font-size:13px;">
              <option value="">— ${escHtml(t('automata_wizard_effort'))} —</option>
              ${['low','medium','high'].map(e=>`<option value="${e}">${e}</option>`).join('')}
            </select>
          </div>
        `,
        confirmLabel: t('automata_tmpl_btn_launch'),
        onConfirm: () => {
          const varValues = {};
          vars.forEach(v => {
            const el = document.getElementById('tmplVar_' + v.name);
            if (el && el.value) varValues[v.name] = el.value;
          });
          const body = {
            vars: varValues,
            project_dir: (document.getElementById('tmplInstDir')||{}).value||'',
            backend: (document.getElementById('tmplInstBackend')||{}).value||'',
            effort: (document.getElementById('tmplInstEffort')||{}).value||'',
          };
          apiFetch('/api/autonomous/templates/' + encodeURIComponent(id) + '/instantiate', { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify(body) })
            .then(prd => {
              showToast(t('automata_tmpl_launched'), 'success', 2000);
              switchAutomataTab('automata');
              if (prd && prd.id) renderPRDDetailView(prd.id);
            })
            .catch(e => showToast(String(e.message||e), 'error'));
        },
      });
    })
    .catch(e => showToast(String(e.message||e), 'error'));
};

function _automataRenderCards() {
  const panel = document.getElementById('automataPanel');
  if (!panel) return;
  const filtered = _automataFilteredList();

  // Update select-all checkbox state
  const allCb = document.getElementById('automataSelectAll');
  if (allCb) {
    const ids = filtered.map(p => p.id);
    allCb.checked = ids.length > 0 && ids.every(i => _automataState.selected.has(i));
    allCb.indeterminate = !allCb.checked && ids.some(i => _automataState.selected.has(i));
  }

  if (filtered.length === 0) {
    const key = _automataState.tab === 'templates'
      ? 'automata_empty_templates'
      : (_automataState.historyOn ? 'automata_empty_history' : 'automata_empty_active');
    panel.innerHTML = `<div style="text-align:center;color:var(--text2);padding:32px;">${escHtml(t(key))}</div>`;
    return;
  }
  panel.innerHTML = filtered.map(renderAutomataCard).join('');
  _automataRenderBatchBar();
}

function switchAutomataTab(tab) {
  _automataState.tab = tab;
  _automataState.selected.clear();
  document.querySelectorAll('.automata-tab').forEach(btn => {
    btn.classList.toggle('active', btn.dataset.tab === tab);
  });
  // BL221 — toggle action buttons per tab.
  // BL246-followup v6.6.1 — Launch button removed from header (FAB covers it).
  const newTmplBtn = document.getElementById('automataNewTmplBtn');
  const filterBtn = document.getElementById('automataFilterBtn');
  const historyBtn = document.getElementById('automataHistoryBtn');
  if (newTmplBtn) newTmplBtn.style.display = tab === 'templates' ? '' : 'none';
  if (filterBtn) filterBtn.style.display = tab === 'automata' ? '' : 'none';
  if (historyBtn) historyBtn.style.display = tab === 'automata' ? '' : 'none';
  if (tab === 'templates') loadAutomataTemplatesPanel();
  else loadAutomataPanel();
}
window.switchAutomataTab = switchAutomataTab;

function toggleAutomataFilter() {
  _automataState.filterOpen = !_automataState.filterOpen;
  localStorage.setItem('cs_automata_filter', _automataState.filterOpen ? '1' : '0');
  const bar = document.getElementById('automataFilterBar');
  if (bar) bar.style.display = _automataState.filterOpen ? 'flex' : 'none';
  const btn = document.getElementById('automataFilterBtn');
  if (btn) btn.classList.toggle('active', _automataState.filterOpen);
}
window.toggleAutomataFilter = toggleAutomataFilter;

// BL246 v6.6.0 — toggles per-card checkbox visibility. Off by default so
// the list reads cleanly until the operator opts into batch operations.
function toggleAutomataSelectMode() {
  _automataState.selectMode = !_automataState.selectMode;
  if (!_automataState.selectMode) {
    // leaving select mode also clears the selection so the batch bar dismisses.
    _automataState.selected.clear();
  }
  const btn = document.getElementById('automataSelectBtn');
  if (btn) btn.classList.toggle('active', _automataState.selectMode);
  _automataRenderCards();
  // v6.12.4 — operator: "the floating action bar doesn't appear until i
  // click on one and it should display when the checkboxes are activated".
  // ALWAYS render the bar after toggling (the renderer itself decides
  // remove vs show based on selectMode flag).
  _automataRenderBatchBar();
}
window.toggleAutomataSelectMode = toggleAutomataSelectMode;

function toggleAutomataHistory() {
  _automataState.historyOn = !_automataState.historyOn;
  _automataState.selected.clear();
  const btn = document.getElementById('automataHistoryBtn');
  if (btn) {
    btn.classList.toggle('active', _automataState.historyOn);
    btn.title = _automataState.historyOn ? t('automata_history_on') : t('automata_history_off');
  }
  _automataRenderCards();
}
window.toggleAutomataHistory = toggleAutomataHistory;

function toggleAutomataStatusFilter(s) {
  if (_automataState.statusFilter.has(s)) _automataState.statusFilter.delete(s);
  else _automataState.statusFilter.add(s);
  const btn = document.querySelector(`.automata-filter-badge.status-${s}`);
  if (btn) btn.classList.toggle('active', _automataState.statusFilter.has(s));
  _automataRenderCards();
}
window.toggleAutomataStatusFilter = toggleAutomataStatusFilter;

function toggleAutomataTypeFilter(type) {
  if (_automataState.typeFilter.has(type)) _automataState.typeFilter.delete(type);
  else _automataState.typeFilter.add(type);
  document.querySelectorAll(`.automata-filter-badge.type-badge`).forEach(btn => {
    if (btn.dataset.type === type) btn.classList.toggle('active', _automataState.typeFilter.has(type));
  });
  _automataRenderCards();
}
window.toggleAutomataTypeFilter = toggleAutomataTypeFilter;

function onAutomataSearchChange(val) {
  _automataState.search = val;
  _automataRenderCards();
}
window.onAutomataSearchChange = onAutomataSearchChange;

// BL221 Phase 1D — Launch Automaton wizard (replaces New PRD modal).
// Progressive disclosure: Intent always visible; Execution revealed on first
// type; Advanced collapsed until operator expands it.

function _inferAutomataType(text) {
  const lower = (text || '').toLowerCase();
  if (/\b(research|analyze|analyz|summarize|summarise|literature|survey|read\b)/.test(lower)) return 'research';
  if (/\b(write|blog|post|content|draft\b)/.test(lower)) return 'operational';
  if (/\b(personal|goal|plan my|habit)/.test(lower)) return 'personal';
  return 'software';
}

let _wizardState = {
  type: 'software',
  typeOverridden: false,
  guidedMode: false,
  scanEnabled: true,
  rulesEnabled: true,
  storyApproval: false,
  advancedOpen: false,
};

function _wizardUpdateInferred(intent) {
  if (_wizardState.typeOverridden) return;
  const inferred = _inferAutomataType(intent);
  _wizardState.type = inferred;
  document.querySelectorAll('.wizard-type-btn').forEach(btn => {
    btn.classList.toggle('selected', btn.dataset.type === inferred);
  });
  // v6.13.1 — update the "Detected: <type>" pill.
  const pill = document.getElementById('wizardDetectedType');
  if (pill) pill.textContent = inferred;
}

function openLaunchAutomatonWizard() {
  _wizardState = { type: 'software', typeOverridden: false, guidedMode: false, scanEnabled: true, rulesEnabled: true, storyApproval: false, advancedOpen: false };
  // Pre-fetch backends + profiles (same as openPRDCreateModal)
  const ensureBackends = state._prdBackends
    ? Promise.resolve()
    : fetch('/api/llms', { headers: tokenHeader() }).then(r => r.ok ? r.json() : null).then(d => { state._prdBackends = (d && d.llms || []).filter(l => !l.disabled); }).catch(() => {});
  const ensureProfiles = Promise.all([
    fetch('/api/profiles/projects', { headers: tokenHeader() }).then(r => r.ok ? r.json() : null).catch(() => null),
    fetch('/api/profiles/clusters', { headers: tokenHeader() }).then(r => r.ok ? r.json() : null).catch(() => null),
  ]).then(([projs, clusters]) => {
    const toArr = (d, keys) => { for (const k of keys) { if (d && Array.isArray(d[k])) return d[k].map(p => p && (p.name || p)).filter(Boolean); } return Array.isArray(d) ? d.map(p => p && (p.name || p)).filter(Boolean) : []; };
    state._prdProjectProfiles = toArr(projs, ['projects','profiles']);
    state._prdClusterProfiles = toArr(clusters, ['clusters','profiles']);
  });
  Promise.all([ensureBackends, ensureProfiles]).then(() => {
    const profileOpts = ['<option value="__dir__">— project directory —</option>']
      .concat((state._prdProjectProfiles || []).map(n => `<option value="${escHtml(n)}">${escHtml(n)}</option>`));
    const types = ['software','research','operational','personal'];
    const typeBtns = types.map(tp =>
      `<button type="button" class="wizard-type-btn ${tp === 'software' ? 'selected' : ''}" data-type="${tp}" onclick="_wizardSelectType('${tp}')">${escHtml(tp)}</button>`
    ).join('');
    // v6.13.1 — operator-directed mobile-first overhaul.
    //
    // Major changes:
    //   - Start-from-template strip: single-line flex row that fits any viewport;
    //     no more 2-char-wide × 30-row malformed column.
    //   - Intent textarea: full width, 4-row min, with a 🎤 mic button.
    //   - "Inferred" header DROPPED — type is now a "Detected: <type> ✏️"
    //     pill below intent that taps to expand the chip row (Q1 option c).
    //   - Type chips: single-row scroll-x on mobile; no wrap.
    //   - Workspace + Execution + Advanced: tightened paddings (6px instead of 12px+).
    //   - Advanced checkboxes: 2px row gap, no excess margins.
    //   - Skills copy: "Configure in Settings → Agents → Project Profiles → Skills"
    //     once we add that field (A9 below).
    _prdMountModal(`
      <div class="response-modal-header" style="display:flex;align-items:center;gap:8px;">
        <strong>⚡ ${escHtml(t('automata_wizard_title'))}</strong>
        <span style="margin-left:auto;display:inline-flex;align-items:center;gap:4px;">
          <a href="/diagrams.html#docs/howto/automata-wizard.md" target="_blank" rel="noopener" title="${escHtml(t('automata_wizard_help_tip')||'Open the Launch Automaton howto — covers every wizard field including Advanced switches')}" style="color:inherit;text-decoration:none;font-size:18px;padding:4px 8px;cursor:pointer;line-height:1;" aria-label="Help">?</a>
          <button class="btn-icon" onclick="_prdCloseModal()" title="Close">&#10005;</button>
        </span>
      </div>
      <form id="prdModalForm" class="response-modal-body wizard-mobile" style="display:flex;flex-direction:column;">

        <!-- Start-from-template strip — single flex row, no wrap, fits mobile. -->
        <div class="wizard-template-strip">
          <span class="wizard-template-icon">📦</span>
          <span class="wizard-template-text">${escHtml(t('automata_wizard_template_link')||'Start from template')}</span>
          <button type="button" class="btn-secondary wizard-template-btn" onclick="switchAutomataTab('templates');_prdCloseModal();">${escHtml(t('automata_wizard_use_template')||'Browse')}</button>
        </div>

        <!-- Intent — full-width textarea with mic. -->
        <div class="wizard-field">
          <label class="wizard-label">${escHtml(t('automata_wizard_intent'))}</label>
          <div class="wizard-input-with-mic">
            <textarea id="wizardIntent" class="form-input wizard-textarea" rows="4"
              placeholder="${escHtml(t('automata_wizard_intent_placeholder'))}"
              oninput="_wizardOnIntent(this.value)"></textarea>
            <button type="button" class="wizard-mic-btn" title="Voice input"
              onclick="_wizardMicForField('wizardIntent')">🎤</button>
          </div>
          <!-- GATE alpha.36 (operator 2026-05-10): Detected pill restyled
               with the same accent border + tinted bg + bold treatment as
               the LLM badge on session cards. Type pills converted to a
               dropdown — operator: "either remove or turn into dropdown".
               Detection still runs from the intent text and pre-selects
               the dropdown, but the operator can override directly here. -->
          <div class="wizard-detected-row" style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;">
            <span class="wizard-detected-label" id="wizardDetectedLabel"
              title="${escHtml(t('automata_wizard_detected_help')||'Auto-inferred from your intent text (keyword scan: code/test/refactor → software; research/analyze → research; deploy/restart/migrate → operational; otherwise personal). Override via the dropdown.')}"
              style="font-size:11px;padding:3px 10px;border-radius:8px;background:rgba(96,165,250,0.12);color:var(--accent2,#60a5fa);border:1px solid var(--accent2,#60a5fa);font-weight:700;display:inline-flex;align-items:center;gap:6px;">
              <span style="opacity:0.7;font-weight:600;">${escHtml(t('automata_wizard_detected')||'Detected')}:</span>
              <span id="wizardDetectedType" style="text-transform:lowercase;">software</span>
            </span>
            <select id="wizardTypeSelect" class="form-select" style="max-width:180px;font-size:12px;padding:3px 8px;" onchange="_wizardSelectType(this.value)">
              ${types.map(tp => `<option value="${tp}" ${tp === 'software' ? 'selected' : ''}>${escHtml(tp)}</option>`).join('')}
            </select>
          </div>
        </div>

        <!-- Title (optional) — full-width with mic. -->
        <div class="wizard-field">
          <label class="wizard-label">${escHtml(t('automata_wizard_title_label')||'Title')} <span style="opacity:0.5;font-size:10px;">(optional)</span></label>
          <div class="wizard-input-with-mic">
            <input id="wizardTitle" type="text" class="form-input"
              placeholder="${escHtml(t('automata_wizard_title_placeholder')||'Auto-derived from intent if blank')}" />
            <button type="button" class="wizard-mic-btn" title="Voice input"
              onclick="_wizardMicForField('wizardTitle')">🎤</button>
          </div>
        </div>

        <!-- GATE alpha.36 (operator 2026-05-10): Workspace + Directory
             stacked on separate rows (operator: long paths scroll off
             when side-by-side). Directory cell hides entirely when a
             named profile is selected. -->
        <div class="wizard-field">
          <label class="wizard-label">${escHtml(t('automata_wizard_workspace'))}</label>
          <select id="wizardProfile" class="form-select" onchange="_wizardProfileChanged()">
            ${profileOpts.join('')}
          </select>
        </div>
        <div class="wizard-field" id="wizardDirCell">
          <label class="wizard-label">${escHtml(t('automata_wizard_directory')||'Directory')}</label>
          <div id="wizardDirRow">
            <div class="dir-picker">
              <span id="selectedDirDisplay" class="dir-display dir-display-clickable" onclick="openDirBrowser()" title="Click to browse">~/</span>
            </div>
            <div id="dirBrowser" class="dir-browser" style="display:none"><div id="dirBrowserContent"></div></div>
          </div>
        </div>

        <!-- GATE alpha.36 (operator 2026-05-10): Backend / Model / Effort
             each on their own row — model + effort labels can run long
             (e.g. claude-sonnet-4-6, "thorough"), and 3-up squeezes them. -->
        <div class="wizard-field">
          <label class="wizard-label">${escHtml(t('automata_wizard_backend'))}</label>
          ${renderBackendSelect('wizardBackend', '', '_wizardBackendChanged()')}
        </div>
        <div class="wizard-field" id="wizardModelField">
          <label class="wizard-label">${escHtml(t('automata_wizard_model')||'Model')}</label>
          <div id="wizardModelWrap">${renderModelSelect('wizardModel', '', '', '')}</div>
        </div>
        <div class="wizard-field">
          <label class="wizard-label">${escHtml(t('automata_wizard_effort'))}</label>
          <div id="wizardEffortWrap">${renderEffortSelect('wizardEffort', '', '', '')}</div>
        </div>

        <!-- Advanced (collapsed). -->
        <details class="wizard-advanced-details">
          <summary class="wizard-advanced-summary">${escHtml(t('automata_wizard_advanced'))}</summary>
          <div class="wizard-advanced-body-tight">
            <label class="wizard-checkbox-row">
              <input type="checkbox" id="wizardGuidedMode" ${_wizardState.guidedMode ? 'checked' : ''}>
              <span>${escHtml(t('automata_wizard_guided'))}</span>
            </label>
            <label class="wizard-checkbox-row">
              <input type="checkbox" id="wizardScanEnabled" checked>
              <span>${escHtml(t('automata_wizard_scan'))}</span>
            </label>
            <label class="wizard-checkbox-row">
              <input type="checkbox" id="wizardRulesEnabled" checked>
              <span>${escHtml(t('automata_wizard_rules'))}</span>
            </label>
            <label class="wizard-checkbox-row">
              <input type="checkbox" id="wizardStoryApproval">
              <span>${escHtml(t('automata_wizard_story_approval'))}</span>
            </label>
            <div class="wizard-skills-hint"><span>💡 </span><a href="#" onclick="event.preventDefault();_prdCloseModal();window.navigate&&window.navigate('settings');setTimeout(()=>{const s=document.querySelector('[data-settings-section=\\'project-profiles\\']');s&&s.scrollIntoView({behavior:'smooth'});},200);return false;" style="color:var(--accent2,#60a5fa);text-decoration:none;border-bottom:1px dashed var(--accent2,#60a5fa);">${escHtml(t('automata_wizard_skills_hint_link')||'Configure skills in Settings → Agents → Project Profiles → Skills')} ↗</a></div>
          </div>
        </details>

        <!-- Footer. -->
        <div class="wizard-footer">
          <button type="button" class="btn-secondary" onclick="_prdCloseModal()">${escHtml(t('automata_wizard_cancel'))}</button>
          <button type="submit" class="btn-primary">${escHtml(t('automata_wizard_launch'))}</button>
        </div>
      </form>
    `, _wizardSubmit);
  });
}
window.openLaunchAutomatonWizard = openLaunchAutomatonWizard;

function _wizardOnIntent(val) {
  _wizardUpdateInferred(val);
}
window._wizardOnIntent = _wizardOnIntent;

function _wizardSelectType(tp) {
  _wizardState.type = tp;
  _wizardState.typeOverridden = true;
  document.querySelectorAll('.wizard-type-btn').forEach(btn => btn.classList.toggle('selected', btn.dataset.type === tp));
  // Refresh both the badge and the dropdown so they stay in sync whether
  // the change came from auto-detect or from the operator's dropdown pick.
  const pill = document.getElementById('wizardDetectedType');
  if (pill) pill.textContent = tp;
  const sel = document.getElementById('wizardTypeSelect');
  if (sel && sel.value !== tp) sel.value = tp;
}
window._wizardSelectType = _wizardSelectType;

// GATE alpha.36 (operator 2026-05-10): when the operator picks a backend,
// the Effort + Model dropdowns repaint to show only the values that
// backend actually supports. Inherit collapses both to (inherit) only.
window._wizardBackendChanged = function() {
  const sel = document.getElementById('wizardBackend');
  const backend = sel ? sel.value : '';
  const effortWrap = document.getElementById('wizardEffortWrap');
  const modelWrap = document.getElementById('wizardModelWrap');
  if (effortWrap) effortWrap.innerHTML = renderEffortSelect('wizardEffort', '', '', backend);
  // GATE alpha.36 (operator 2026-05-10): live-fetch model lists for
  // backends that expose them. Static fallback for claude-code (model
  // IDs are released names). Ollama + openwebui hit their real /api
  // endpoints. Opencode reads OPENCODE_MODELS env from the project
  // profile — operator picks model in that env, so we surface a hint
  // rather than a dropdown.
  if (!modelWrap) return;
  const setOpts = (models) => {
    if (!models || models.length === 0) {
      modelWrap.innerHTML = renderModelSelect('wizardModel', '', '', backend);
      return;
    }
    const opts = ['<option value="">(inherit)</option>']
      .concat(models.map(m => `<option value="${escHtml(m)}">${escHtml(m)}</option>`));
    modelWrap.innerHTML = `<select id="wizardModel" class="form-select">${opts.join('')}</select>`;
  };
  // GATE alpha.36 (operator 2026-05-10): hide the entire Model field
  // (label + control) when no real list is available rather than
  // showing a placeholder/hint. The whole row vanishes for opencode
  // variants and council; reappears when a backend with models is
  // picked. Looks cleaner than a stale "(inherit)" or a prose hint.
  const modelField = document.getElementById('wizardModelField');
  const showModel = (b) => { if (modelField) modelField.style.display = ''; };
  const hideModel = () => { if (modelField) modelField.style.display = 'none'; };
  if (backend === 'ollama') {
    showModel(); apiFetch('/api/ollama/models').then(setOpts).catch(() => setOpts(null));
  } else if (backend === 'openwebui') {
    showModel(); apiFetch('/api/openwebui/models').then(setOpts).catch(() => setOpts(null));
  } else if (backend === 'claude-code') {
    showModel(); modelWrap.innerHTML = renderModelSelect('wizardModel', '', '', backend);
  } else {
    // opencode variants / council / inherit — model picker doesn't apply.
    hideModel();
  }
};

// Type chip toggle kept for back-compat (older inline event handlers may
// reference it); the new dropdown directly drives _wizardSelectType so
// this is a no-op when chips no longer exist.
window._wizardToggleTypeChips = function() {
  const chips = document.getElementById('wizardTypeChips');
  if (!chips) return;
  chips.style.display = chips.style.display === 'none' ? 'flex' : 'none';
};

// Voice-input mic helper for wizard text fields. Reuses the same
// /api/voice/transcribe endpoint the session input bar uses.
window._wizardMicForField = function(fieldId) {
  if (typeof startVoiceCapture === 'function') {
    // If the global voice capture helper exists (defined for session input
    // bar), reuse it. The helper writes the transcript into the focused
    // input. Focus the field first so the helper targets it.
    const el = document.getElementById(fieldId);
    if (el) el.focus();
    startVoiceCapture(fieldId);
    return;
  }
  // Fallback: tell the operator how to enable.
  showToast('Voice input requires whisper.enabled (Settings → General → Voice Input)', 'info', 3000);
};

function _wizardProfileChanged() {
  const sel = document.getElementById('wizardProfile');
  // GATE alpha.36 (operator 2026-05-10): hide the WHOLE Directory cell
  // (label + picker) when a named profile is selected — operator
  // reported the orphan label was lingering when only the dir-row was
  // hidden. Toggling the cell keeps the row's flex layout intact:
  // Workspace simply takes the full row width when Dir is hidden.
  const dirCell = document.getElementById('wizardDirCell');
  const isDir = !sel || sel.value === '__dir__';
  if (dirCell) dirCell.style.display = isDir ? 'flex' : 'none';
}
window._wizardProfileChanged = _wizardProfileChanged;

function _wizardToggleAdvanced() {
  _wizardState.advancedOpen = !_wizardState.advancedOpen;
  const body = document.getElementById('wizardAdvancedBody');
  const arrow = document.getElementById('wizardAdvancedArrow');
  if (body) body.style.display = _wizardState.advancedOpen ? 'block' : 'none';
  if (arrow) arrow.textContent = _wizardState.advancedOpen ? '▼' : '▶';
}
window._wizardToggleAdvanced = _wizardToggleAdvanced;

function _wizardSubmit() {
  const intent = (document.getElementById('wizardIntent')?.value || '').trim();
  if (!intent) { showToast('Intent required', 'error', 2000); return; }
  const title = document.getElementById('wizardTitle')?.value.trim() || '';
  const profileSel = document.getElementById('wizardProfile')?.value;
  const usingProfile = profileSel && profileSel !== '__dir__';
  const projectProfile = usingProfile ? profileSel : '';
  const projectDir = usingProfile ? '' : ((window.newSessionState && newSessionState.selectedDir) || '');
  const backend = document.getElementById('wizardBackend')?.value || '';
  const effort  = document.getElementById('wizardEffort')?.value || '';

  const guidedMode = document.getElementById('wizardGuidedMode')?.checked || false;
  const body = {
    spec: intent,
    title: title || undefined,
    type: _wizardState.type || undefined,
    guided_mode: guidedMode || undefined,
    backend: backend || undefined,
    effort: effort || undefined,
    project_dir: projectDir || undefined,
    project_profile: projectProfile || undefined,
  };
  Object.keys(body).forEach(k => { if (body[k] === undefined) delete body[k]; });

  apiFetch('/api/autonomous/prds', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(body),
  }).then(prd => {
    _prdCloseModal();
    showToast('Automaton created', 'success', 1500);
    if (prd && prd.id) {
      _automataDetailBreadcrumb = [];
      renderPRDDetailView(prd.id);
    } else {
      loadAutomataPanel();
    }
  }).catch(err => showToast('Launch failed: ' + String(err), 'error', 3500));
}

function openAutomataHowto() {
  // v6.12.1 (BL269) — open the rendered docs viewer on the central
  // definitions manual, anchored to Automata. The viewer takes the
  // file path + anchor in the URL hash.
  window.open('/diagrams.html#docs/datawatch-definitions.md#automata', '_blank', 'noopener');
}
window.openAutomataHowto = openAutomataHowto;

function _toggleAutonomousFilters() {
  toggleAutomataFilter();
}
window._toggleAutonomousFilters = _toggleAutonomousFilters;

// BL221 Phase 1C — PRD detail view.
// Navigation: clicking a card → detail view (pushState); browser back → list.
// Real-time: _prd_update WS events refresh the detail view in place.

let _automataDetailId = null;  // null = list view; string = detail view for this PRD id
let _automataDetailBreadcrumb = [];  // [{id, title}] chain from root to current
// BL246 v6.6.0 — sub-tabs in detail view: 'overview' | 'stories' | 'decisions' | 'scan'
let _automataDetailTab = 'overview';
function switchAutomataDetailTab(tab) {
  _automataDetailTab = tab;
  if (_automataDetailId) renderPRDDetailView(_automataDetailId);
}
window.switchAutomataDetailTab = switchAutomataDetailTab;

function _taskStatusIcon(status) {
  const icons = { completed: '✓', in_progress: '⚡', pending: '○', blocked: '✗', failed: '✗', cancelled: '○' };
  return icons[status] || '○';
}

function _fmtDate(ts) {
  if (!ts) return '—';
  try { return new Date(ts).toLocaleString(); } catch { return String(ts); }
}

// BL245 — schedule time formatter: maps Go zero-time (0001-01-01) to "on input"
// instead of rendering "12/31/1, 7:03:58 PM".
function _fmtScheduleTime(run_at) {
  if (!run_at) return t('session_detail_on_input') || 'on input';
  const d = new Date(run_at);
  if (isNaN(d.getTime()) || d.getFullYear() < 2000) return t('session_detail_on_input') || 'on input';
  return d.toLocaleString();
}

function renderDetailStoriesTree(prd) {
  const stories = prd.stories || prd.Story || [];
  if (stories.length === 0) return `<div style="color:var(--text2);font-size:12px;padding:8px 0;">${t('prd_no_stories')||'No stories yet.'}</div>`;
  return stories.map((st, si) => {
    const tasks = st.tasks || st.Tasks || [];
    const done = tasks.filter(t => (t.status || t.Status) === 'completed').length;
    const taskRows = tasks.map((t, ti) => {
      const sts = t.status || t.Status || 'pending';
      const icon = _taskStatusIcon(sts);
      const iconColor = { completed: 'var(--success)', in_progress: 'var(--accent)', failed: 'var(--error)', blocked: 'var(--error)' }[sts] || 'var(--text2)';
      const sessionLink = t.session_id
        ? `<span class="prd-task-session" onclick="navigate('sessions');setTimeout(()=>_highlightSession(${escHtml(JSON.stringify(t.session_id))}),300)" title="Go to session">→ session</span>`
        : '';
      const childPRD = t.child_prd_id
        ? `<span class="prd-task-session" onclick="renderPRDDetailView(${escHtml(JSON.stringify(t.child_prd_id))})" title="Open child automaton">↳ child automaton</span>`
        : '';
      return `<div class="prd-task-row">
        <span class="prd-task-icon" style="color:${iconColor};">${icon}</span>
        <span class="prd-task-title">${escHtml(t.title || t.Title || '(task ' + (ti+1) + ')')}</span>
        <span class="prd-task-status">${escHtml(sts)}</span>
        ${sessionLink}${childPRD}
      </div>`;
    }).join('');
    const verdicts = renderVerdicts(st.verdicts);
    const stStatus = st.status || st.Status || 'pending';
    const stIcon = _taskStatusIcon(stStatus);
    const stColor = { completed: 'var(--success)', in_progress: 'var(--accent)', failed: 'var(--error)', blocked: 'var(--error)' }[stStatus] || 'var(--text2)';
    const stId = `prd-story-${escHtml(prd.id)}-${si}`;
    return `<div class="prd-story-block">
      <div class="prd-story-header" onclick="document.getElementById('${stId}-tasks').classList.toggle('hidden')">
        <span style="color:${stColor};font-size:14px;">${stIcon}</span>
        <span style="font-weight:600;color:var(--text);flex:1;">${escHtml(st.title || st.Title || 'Story ' + (si+1))}</span>
        <span style="font-size:10px;color:var(--text2);">${done}/${tasks.length} tasks</span>
        ${verdicts}
      </div>
      <div id="${stId}-tasks" class="prd-story-tasks">${taskRows || `<em style="color:var(--text2);font-size:11px;">${t('prd_no_tasks')||'No tasks.'}</em>`}</div>
    </div>`;
  }).join('');
}

function renderDetailVerdicts(prd) {
  const stories = prd.stories || prd.Story || [];
  const allVerdicts = [];
  for (const st of stories) {
    for (const v of (st.verdicts || [])) allVerdicts.push(v);
    for (const t of (st.tasks || st.Tasks || [])) {
      for (const v of (t.verdicts || [])) allVerdicts.push(v);
    }
  }
  if (allVerdicts.length === 0) return '';
  const grouped = {};
  for (const v of allVerdicts) {
    const g = v.guardrail || v.source || 'unknown';
    if (!grouped[g] || v.outcome === 'block') grouped[g] = v;
  }
  const badges = Object.entries(grouped).map(([g, v]) => {
    const cls = v.outcome === 'pass' ? 'prd-verdict-pass' : v.outcome === 'block' ? 'prd-verdict-block' : 'prd-verdict-warn';
    const icon = v.outcome === 'pass' ? '✓' : v.outcome === 'block' ? '✗' : '⚠';
    return `<span class="prd-verdict-badge ${cls}">${escHtml(g)}: ${v.outcome} ${icon}</span>`;
  }).join('');
  return `<div style="margin:10px 0;">
    <div style="font-size:11px;font-weight:600;color:var(--text2);margin-bottom:4px;">${escHtml(t('automata_detail_verdicts'))}</div>
    <div class="prd-verdict-row">${badges}</div>
  </div>`;
}

function renderDetailDecisions(prd) {
  const decisions = prd.decisions || prd.Decisions || [];
  if (decisions.length === 0) return '';
  const rows = decisions.slice().reverse().map(d => {
    const time = _fmtDate(d.at || d.At);
    const kind = d.kind || d.Kind || '?';
    const note = d.note || d.Note || '';
    const actor = d.actor || d.Actor || '';
    return `<div class="prd-decision-row">
      <span class="prd-decision-time">${escHtml(time)}</span>
      <span class="prd-decision-kind">${escHtml(kind)}</span>
      <span class="prd-decision-note">${escHtml(actor ? actor + (note ? ': ' : '') : '')}${escHtml(note)}</span>
    </div>`;
  }).join('');
  return `<details style="margin:10px 0;"><summary style="cursor:pointer;font-size:12px;font-weight:600;color:var(--text2);">${escHtml(t('automata_detail_decisions'))} (${decisions.length})</summary>
    <div style="margin-top:6px;">${rows}</div>
  </details>`;
}

function renderPRDDetailView(prdId, breadcrumbAppend) {
  _automataDetailId = prdId;
  // Push browser state so back button returns to list
  if (history.state && history.state.prdDetail === prdId) {
    // Already here; don't double-push
  } else {
    history.pushState({ prdDetail: prdId, bc: _automataDetailBreadcrumb }, '', '');
  }

  const view = document.getElementById('view');
  if (!view) return;
  view.innerHTML = `<div class="view-content" style="position:relative;">
    <div class="prd-breadcrumb" id="automataDetailBreadcrumb"></div>
    <div id="automataDetailBody" style="padding:0;"><div style="text-align:center;padding:32px;color:var(--text2);">${escHtml(t('common_loading'))}</div></div>
  </div>`;

  apiFetch('/api/autonomous/prds/' + encodeURIComponent(prdId))
    .then(prd => {
      if (!prd || !prd.id) throw new Error('PRD not found');
      _renderDetailContent(prd);
    })
    .catch(err => {
      const body = document.getElementById('automataDetailBody');
      if (body) body.innerHTML = `<div style="padding:16px;color:var(--error);">Failed to load: ${escHtml(String(err))}</div>`;
    });
}
window.renderPRDDetailView = renderPRDDetailView;

function _renderDetailContent(prd) {
  const id = prd.id || '';
  const title = prd.title || '(no title)';
  const status = prd.status || 'draft';
  const type = prd.type || '';

  // Update breadcrumb chain
  const existing = _automataDetailBreadcrumb.findIndex(b => b.id === id);
  if (existing >= 0) {
    _automataDetailBreadcrumb = _automataDetailBreadcrumb.slice(0, existing + 1);
  } else {
    _automataDetailBreadcrumb.push({ id, title });
  }

  // GATE alpha.36 (operator 2026-05-10): the breadcrumb bar duplicated
  // the back button now rendered inside the new detail header (row 1
  // ← icon). Hide the breadcrumb element entirely unless we're inside
  // a parent-child chain (length > 1), where the breadcrumb still
  // provides useful navigation.
  const bcEl = document.getElementById('automataDetailBreadcrumb');
  if (bcEl) {
    const showBc = _automataDetailBreadcrumb.length > 1;
    bcEl.style.display = showBc ? '' : 'none';
    const parts = [
      `<button class="prd-breadcrumb-link" onclick="_backToAutomataList()">← ${escHtml(t('automata_detail_back'))}</button>`,
    ];
    // v6.13.5 — operator: "2 headers: <title> / <title>". The breadcrumb's
    // current-segment span duplicates the detail-header <h2> below it.
    // Drop the current segment; show only parent chain. (For a top-level
    // PRD with no parents, the breadcrumb becomes just "← Automata".)
    _automataDetailBreadcrumb.forEach((seg, i) => {
      if (i < _automataDetailBreadcrumb.length - 1) {
        parts.push(`<span class="prd-breadcrumb-sep">›</span>`);
        parts.push(`<button class="prd-breadcrumb-link" onclick="renderPRDDetailView(${escHtml(JSON.stringify(seg.id))})">${escHtml(seg.title)}</button>`);
      }
    });
    bcEl.innerHTML = parts.join('');
  }

  const typeBadge = type ? `<span class="automata-filter-badge type-badge active" style="font-size:11px;">${escHtml(type)}</span> ` : '';
  const tplBadge = prd.is_template ? `<span style="background:#7c3aed;color:#fff;font-size:10px;padding:1px 6px;border-radius:8px;margin-right:4px;">template</span>` : '';

  // BL246 v6.6.0 — persistent header toolbar across all sub-tabs.
  const tab = _automataDetailTab || 'overview';
  const header = _renderDetailHeader(prd, typeBadge, tplBadge);
  const tabStrip = _renderDetailTabStrip(prd, tab);
  let tabBody = '';
  if (tab === 'overview') tabBody = _renderDetailOverview(prd);
  else if (tab === 'stories') tabBody = _renderDetailStories(prd);
  else if (tab === 'decisions') tabBody = _renderDetailDecisionsTab(prd);
  else if (tab === 'scan') tabBody = _renderDetailScanTab(prd);
  else if (tab === 'rules') tabBody = _renderDetailRulesTab(prd);
  else tabBody = _renderDetailOverview(prd);

  const body = document.getElementById('automataDetailBody');
  if (!body) return;
  body.innerHTML = `<div class="prd-detail-body">
    ${header}
    ${tabStrip}
    <div class="prd-detail-tab-body" style="margin-top:10px;">${tabBody}</div>
  </div>`;
  // GATE alpha.36 (operator 2026-05-10): hoist the title + back into
  // the PWA banner header (matches session-detail behavior).
  // - backBtn shown with onclick=_backToAutomataList (chevron arrow,
  //   same color/style as session detail)
  // - headerTitle replaced with the automaton title + ✎ edit pencil
  //   (operator: "title should have an edit button like in a session")
  const backBtn = document.getElementById('backBtn');
  const headerTitle = document.getElementById('headerTitle');
  if (backBtn) {
    backBtn.style.display = 'inline';
    backBtn.onclick = () => _backToAutomataList();
  }
  // GATE alpha.36 (operator 2026-05-10): hide the header search/filter
  // icon inside the PRD detail view — search is only useful on the
  // list. It reappears automatically on _backToAutomataList because
  // navigate('autonomous') sets headerSearchBtn.display='inline-flex'.
  const headerSearchBtn = document.getElementById('headerSearchBtn');
  if (headerSearchBtn) headerSearchBtn.style.display = 'none';
  if (headerTitle) {
    const titleText = prd.title || '(no title)';
    const idJStr = JSON.stringify(prd.id || '');
    const titleStr = JSON.stringify(titleText);
    const specStr = JSON.stringify(prd.spec || '');
    // GATE alpha.36 (operator 2026-05-10): edit pencil sits to the
    // RIGHT of the (truncating) title, BEFORE the ID, so a long title
    // can't push the robot-identity wizard off the right edge of the
    // header bar. Title node truncates with ellipsis at narrow widths
    // — same affordance as session-detail header.
    headerTitle.innerHTML = `<span class="header-sess-name" onclick="openPRDEditModal(${escHtml(idJStr)},${escHtml(titleStr)},${escHtml(specStr)})" title="${escHtml(t('prd_edit_title_tip')||'Click to edit title')}" style="overflow:hidden;text-overflow:ellipsis;white-space:nowrap;min-width:0;max-width:60vw;">${escHtml(titleText)}</span><button class="btn-icon header-edit-btn" onclick="openPRDEditModal(${escHtml(idJStr)},${escHtml(titleStr)},${escHtml(specStr)})" title="${escHtml(t('prd_btn_edit')||'Edit')}">&#9998;</button><span class="header-id">#${escHtml(prd.id || '')}</span>`;
  }
  // Async load scan results when on Scan tab
  if (tab === 'scan') loadPRDScanResult(id);
  // GATE alpha.36 (operator 2026-05-10): inline active-session card
  // (#290). When the PRD is in an active state, surface the spawned
  // session(s) + hook status under "Next" hint, before the toolbar.
  if (['planning','decomposing','running'].includes(prd.status || '')) {
    _loadPRDActiveSessionCard(prd);
  }
}

window._loadPRDActiveSessionCard = function(prd) {
  const slot = document.getElementById('prdActiveSessionCard');
  if (!slot) return;
  apiFetch('/api/sessions').then(allSessions => {
    const list = Array.isArray(allSessions) ? allSessions : (allSessions.sessions || []);
    const matches = list.filter(s => (s.prd_id || s.parent_prd_id) === prd.id);
    if (matches.length === 0) {
      // GATE alpha.36 (operator 2026-05-10): no session yet — surface
      // the gap as a COLLAPSIBLE card (operator: hide/collapse if no
      // activity). Defaults open the first time, includes a Cancel
      // action so the operator can reset stuck planning state. Full
      // failed-state handling tracked in #291. Hidden entirely when
      // status isn't actually active anymore (caller already gates,
      // but defensive).
      if (!['planning','decomposing','running'].includes(prd.status || '')) {
        slot.style.display = 'none';
        return;
      }
      slot.style.display = 'block';
      const idJStr = JSON.stringify(prd.id || '');
      slot.innerHTML = `<details class="prd-stuck-warning" open style="background:rgba(245,158,11,0.08);border:1px solid rgba(245,158,11,0.3);border-radius:6px;font-size:12px;color:var(--text2);">
        <summary style="cursor:pointer;padding:8px 12px;font-weight:600;color:var(--warning,#f59e0b);list-style:none;display:flex;align-items:center;gap:6px;">
          <span>⚠ ${escHtml(t('prd_no_active_session_title')||'No active session record')}</span>
          <span style="margin-left:auto;font-size:10px;opacity:0.6;font-weight:400;">${escHtml(t('prd_collapse_hint')||'click to collapse')}</span>
        </summary>
        <div style="padding:0 12px 10px 12px;">
          <div style="margin-bottom:8px;">${escHtml(t('prd_no_active_session_hint')||'Status looks active but no spawned session was found. The LLM call may have failed silently.')}</div>
          <div style="margin-bottom:6px;font-size:11px;"><strong>${escHtml(t('prd_unstick_label')||'Unstick')}:</strong> ${escHtml(t('prd_unstick_steps')||'Cancel below, then re-trigger Plan from the lifecycle strip after verifying the LLM\'s compute node is reachable in Compute Nodes.')}</div>
          <button class="btn-secondary" style="font-size:11px;padding:3px 10px;" onclick="event.stopPropagation();automataCancel(${escHtml(idJStr)})" title="${escHtml(t('automata_action_cancel_tip')||'Cancel this automaton')}">✕ ${escHtml(t('automata_action_cancel')||'Cancel')}</button>
        </div>
      </details>`;
      return;
    }
    // Active session(s) found — render compact card with state + hook
    // status. Use first match for the inline card; full list lives in
    // the future Sessions sub-tab (#290).
    Promise.all(matches.slice(0, 3).map(s => {
      const fid = s.full_id || s.id;
      return apiFetch('/api/sessions/' + encodeURIComponent(fid) + '/status')
        .then(b => ({ sess: s, board: b }))
        .catch(() => ({ sess: s, board: null }));
    })).then(rows => {
      slot.style.display = 'block';
      slot.innerHTML = rows.map(({ sess, board }) => {
        const fid = sess.full_id || sess.id;
        const stateClass = `state-badge-${sess.state || 'unknown'}`;
        const isActive = !['killed','complete','failed'].includes(sess.state);
        const animClass = (sess.state === 'running') ? 'state-badge-running' : '';
        const hookDot = board && board.hook_health
          ? (board.hook_health === 'alive'
              ? `<span style="color:var(--success);font-size:11px;" title="Hooks alive">●</span>`
              : board.hook_health === 'stale'
                ? `<span style="color:var(--warning);font-size:11px;" title="Hooks stale (>5 min)">●</span>`
                : `<span style="color:var(--text2);font-size:11px;" title="No hooks">●</span>`)
          : '';
        const focus = board && board.last_event
          ? `<div style="font-size:11px;color:var(--text2);margin-top:4px;">${escHtml(board.last_event.event)}${board.last_event.tool ? ' · ' + escHtml(board.last_event.tool) : ''}</div>`
          : '';
        const stats = board && board.tests
          ? `<span style="margin-left:10px;font-size:11px;"><span style="color:var(--success);">${board.tests.pass||0}✓</span> / <span style="color:var(--error);">${board.tests.fail||0}✗</span></span>`
          : '';
        return `<div class="prd-active-session-row" style="background:var(--bg2);border:1px solid var(--border);border-left:3px solid var(--accent2);border-radius:6px;padding:8px 12px;cursor:pointer;margin-top:4px;" onclick="navigate('session-detail','${escHtml(fid)}')">
          <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;font-size:12px;">
            <span class="state ${stateClass} ${animClass}" style="border:1px solid currentColor;padding:1px 7px;border-radius:10px;font-size:11px;font-weight:600;">${escHtml(sess.state || 'unknown')}</span>
            <code style="font-family:var(--mono,monospace);font-size:11px;background:var(--bg3,#1f2937);padding:1px 6px;border-radius:4px;">${escHtml(sess.id || fid.split('-').pop())}</code>
            <span style="opacity:0.8;">${escHtml(sess.name || sess.task || '')}</span>
            ${hookDot}
            ${stats}
            <span style="margin-left:auto;font-size:11px;opacity:0.6;">→</span>
          </div>
          ${focus}
        </div>`;
      }).join('');
    });
  }).catch(() => { slot.style.display = 'none'; });
};

// BL246 v6.6.0 — persistent header (title + status + toolbar) shown on every sub-tab.
// BL293 (v6.22.2 — verified live 2026-05-08) — per-state button matrix.
// The audit confirmed the previous implementation IS consistent; operator's
// "buttons should be on all automata" complaint was about "why some
// buttons missing" not the actual matrix. Documented here so future readers
// don't re-litigate.
//
//                Edit  Set  Request   Clone  Delete  Run-Scan  Run-Rules
// State          Spec  ngs  Revision   Tmpl   (Hard)  (gated)   (gated)
// ─────────────  ────  ───  ────────  ─────  ──────  ────────  ─────────
// draft           ✓    ✓               ✓      ✓        ✓         ✓
// needs_review    ✓    ✓     ✓          ✓      ✓        ✓         ✓
// revisions_asked ✓    ✓     ✓          ✓      ✓        ✓         ✓
// approved                              ✓      ✓        ✓         ✓
// running                               ✓                 ✓         ✓
// completed                             ✓      ✓
// cancelled                             ✓      ✓
// archived                              ✓      ✓
//
// Run-Scan/Run-Rules are additionally gated on prd.scan_enabled /
// prd.rules_enabled (BL294 v6.22.2).
// GATE alpha.36 (operator 2026-05-10): Edit-flyout toggle. Positions
// the menu in viewport coords (escapes the tab body's overflow:hidden
// scroll) so it overlays freely above any tab/scroll bounds. Outside-
// click dismisses.
window._toggleEditMenu = function(ev) {
  ev.stopPropagation();
  const m = document.getElementById('prdEditMenu');
  if (!m) return;
  if (m.style.display === 'block') { m.style.display = 'none'; return; }
  const btn = ev.currentTarget;
  const r = btn.getBoundingClientRect();
  m.style.display = 'block';
  m.style.top = Math.round(r.top) + 'px';
  // Position the menu's right edge to the LEFT edge of the button
  // (operator: "slide out to the left, going over anything that
  // might be to the left of the edit button").
  m.style.right = Math.max(0, Math.round(window.innerWidth - r.left + 6)) + 'px';
  m.style.left = '';
  // Outside-click dismiss — single global handler that self-removes.
  setTimeout(() => {
    const off = (e) => { if (!m.contains(e.target) && e.target !== btn) { m.style.display = 'none'; document.removeEventListener('click', off, true); } };
    document.addEventListener('click', off, true);
  }, 0);
};

function _renderDetailHeader(prd, typeBadge, tplBadge) {
  const id = prd.id || '';
  const title = prd.title || '(no title)';
  const status = prd.status || 'draft';
  const idJ = JSON.stringify(id);
  // GATE alpha.36 (operator 2026-05-10): planning was missing from the
  // editable list — operator hit a planning-stuck PRD and couldn't get
  // to Edit Spec / Settings. Allow editing during planning too (the
  // operator may need to fix the spec or change LLM/effort to unblock).
  const editable = (status === 'draft' || status === 'planning' || status === 'needs_review' || status === 'revisions_asked');
  const terminal = ['completed','cancelled','archived'].includes(status);
  // GATE alpha.36 (operator 2026-05-10): action buttons regrouped into
  // two rows with clear roles:
  //   Row 1 (workflow): Cancel | Approve              ⋯ Edit-menu | Delete
  //     - Cancel + Approve = visible state-conditional action buttons
  //     - Edit-menu collapses Edit Spec / Settings / Clone-to-Template
  //       behind a single "⋯ Edit" overflow on the lower-right
  //     - Delete kept separate (red) — operator question on whether
  //       Delete needs Cancel-first: per the per-state matrix above,
  //       Delete is allowed in any non-running state. Cancel-first is
  //       NOT required: a draft that never ran can delete directly; a
  //       cancelled/completed automaton skips straight to delete for
  //       cleanup. The two are different actions: Cancel changes state,
  //       Delete removes the record. Kept distinct so the operator's
  //       intent is unambiguous.
  const editMenuItems = [];
  if (editable) {
    editMenuItems.push(`<button class="prd-edit-menu-item" onclick="document.getElementById('prdEditMenu').style.display='none';openPRDEditModal(${escHtml(idJ)},${escHtml(JSON.stringify(title))},${escHtml(JSON.stringify(prd.spec || ''))})" title="${escHtml(t('prd_edit_spec_title')||'Edit title + spec')}">✎ ${escHtml(t('prd_btn_edit_spec')||'Edit Spec')}</button>`);
    editMenuItems.push(`<button class="prd-edit-menu-item" onclick="document.getElementById('prdEditMenu').style.display='none';openPRDSettingsModal(${escHtml(idJ)})" title="${escHtml(t('prd_settings_title')||'Type, backend, effort, model, skills, guided mode')}">⚙ ${escHtml(t('prd_btn_settings')||'Settings')}</button>`);
  }
  if (!prd.is_template) {
    editMenuItems.push(`<button class="prd-edit-menu-item" onclick="document.getElementById('prdEditMenu').style.display='none';openCloneToTemplateModal(${escHtml(idJ)})" title="${escHtml(t('prd_btn_clone_template_title')||'Save this automaton as a reusable template')}">⌗ ${escHtml(t('prd_btn_clone_template')||'Clone to Template')}</button>`);
  }
  // Cancel button — shown for any non-terminal, non-running cancellable state.
  const cancelBtn = (!terminal && status !== 'running' && status !== 'cancelled')
    ? `<button class="btn-secondary prd-action-btn" onclick="automataCancel(${escHtml(idJ)})" title="${escHtml(t('automata_action_cancel_tip')||'Cancel this automaton')}">✕ ${escHtml(t('automata_action_cancel')||'Cancel')}</button>`
    : '';
  // Approve / Request Revision — state-driven primary action.
  let approveBtn = '';
  if (status === 'needs_review' || status === 'revisions_asked') {
    approveBtn = `<button class="btn-primary prd-action-btn" style="background:rgba(245,158,11,0.15);color:#f59e0b;font-weight:700;" onclick="prdActionPrompt(${escHtml(idJ)},'request_revision','note',${escHtml(JSON.stringify(t('prd_revision_prompt')||'What needs revision?'))})" title="${escHtml(t('prd_btn_request_revision_title')||'Send the automaton back for revision with a note')}">↺ ${escHtml(t('prd_btn_request_revision')||'Request Revision')}</button>`;
  }
  const editBtn = editMenuItems.length > 0
    ? `<div style="position:relative;display:inline-flex;"><button class="btn-icon prd-edit-overflow-btn" onclick="_toggleEditMenu(event)" title="${escHtml(t('prd_edit_menu_tip')||'Edit / Settings / Clone')}">⋯ ${escHtml(t('prd_btn_edit')||'Edit')}</button><div id="prdEditMenu" class="prd-edit-menu" style="display:none;">${editMenuItems.join('')}</div></div>`
    : '';
  const deleteBtn = (status !== 'running')
    ? `<button class="btn-icon prd-delete-btn" style="color:var(--error);" onclick="confirmPRDDelete(${escHtml(idJ)})" title="${escHtml(t('prd_btn_delete_title')||'Hard-delete the automaton and any descendants')}">🗑</button>`
    : '';
  // Run-scan / Run-rules — kept inline next to lifecycle since they're
  // workflow operations gated on guardrail config.
  const buttons = [];
  const canRunScans = !['archived','cancelled','completed'].includes(status);
  if (canRunScans && prd.scan_enabled) {
    buttons.push(`<button class="btn-icon prd-header-btn" style="background:rgba(96,165,250,0.15);color:var(--accent);" onclick="prdAction(${escHtml(idJ)},'scan','POST')" title="${escHtml(t('prd_btn_run_scan_title')||'Run security/secrets/dep scan')}">▶ ${escHtml(t('prd_btn_run_scan')||'Run Scan')}</button>`);
  }
  if (canRunScans && prd.rules_enabled) {
    buttons.push(`<button class="btn-icon prd-header-btn" style="background:rgba(168,85,247,0.15);color:var(--accent2);" onclick="prdAction(${escHtml(idJ)},'scan/rules','POST')" title="${escHtml(t('prd_btn_run_rules_title')||'Run rules check (after scan)')}">▶ ${escHtml(t('prd_btn_run_rules')||'Run Rules')}</button>`);
  }
  // GATE alpha.36 (operator 2026-05-10): full header restructure.
  //   Row 1: ← back · type · title (click to edit) · status pill (right)
  //   Row 2: ID badge · last-activity (right-justified)
  //   Row 3: spec snippet — the "what do you want to accomplish" text
  //   Row 4: lifecycle strip (compact, single line via .lifecycle-compact)
  //   Row 5: actions: Cancel · Approve            ⋯ Edit  · 🗑 Delete
  //   Row 6: optional Run Scan / Run Rules pills
  const lastActivity = prd.updated_at ? _fmtDate(prd.updated_at) : '';
  const specSnippet = (prd.spec || '').trim();
  const titleClickable = `<h2 style="margin:0;font-size:16px;font-weight:700;color:var(--text);cursor:pointer;flex:1;min-width:0;" title="${escHtml(t('prd_edit_title_tip')||'Click to edit title')}" onclick="openPRDEditModal(${escHtml(idJ)},${escHtml(JSON.stringify(title))},${escHtml(JSON.stringify(prd.spec || ''))})">${escHtml(title)}</h2>`;
  return `
    <div class="prd-detail-header-v2">
      <!-- GATE alpha.36 (operator 2026-05-10): row 1 ← back removed —
           the PWA banner now hosts the back chevron + title + edit
           pencil (matches session-detail). Only badges + status pill
           remain here. -->
      <div class="prd-detail-row1" style="display:flex;align-items:center;gap:8px;margin-bottom:6px;">
        ${typeBadge}${tplBadge}
        <span style="flex:1;min-width:0;"></span>
        <span style="margin-left:auto;flex-shrink:0;">${statusPill(status)}</span>
      </div>
      <div class="prd-detail-row2" style="display:flex;justify-content:flex-end;gap:10px;font-size:11px;color:var(--text2);font-family:var(--mono,monospace);margin-bottom:6px;">
        <code>${escHtml(id)}</code>
        ${lastActivity ? `<span title="${escHtml(t('prd_last_activity_tip')||'Last activity')}">${escHtml(lastActivity)}</span>` : ''}
      </div>
      ${specSnippet ? `<div class="prd-detail-spec-row" style="font-size:12px;color:var(--text2);line-height:1.4;margin-bottom:8px;padding:6px 10px;background:var(--bg2);border-left:3px solid var(--accent2,#60a5fa);border-radius:0 4px 4px 0;white-space:pre-wrap;">${escHtml(specSnippet.length > 280 ? specSnippet.slice(0, 280) + '…' : specSnippet)}</div>` : ''}
      <div class="prd-detail-actions-row lifecycle-compact">${renderLifecycleStrip(prd)}</div>
      <div id="prdActiveSessionCard" class="prd-active-session-card" style="display:none;margin-top:8px;"></div>
      <div class="prd-detail-toolbar prd-detail-toolbar-v2" style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin-top:8px;">
        ${cancelBtn}${approveBtn}${buttons.join('')}
        <span style="margin-left:auto;display:inline-flex;gap:6px;align-items:center;">${editBtn}${deleteBtn}</span>
      </div>
      ${terminal ? `<div class="prd-detail-terminal-hint" style="font-size:11px;color:var(--text2);margin-top:6px;padding:0 2px;">${escHtml(t('prd_terminal_state_hint')||`This automaton is in terminal state (${status}). Only Clone-to-Template + Delete remain.`)}</div>` : ''}
    </div>
  `;
}

// v6.13.1 (C4 + C10 + C12) — operator: "the tab structure
// (overview/stories/decisions/scans) looks like buttons not tabs,
// clean it up to look like and function like tabs". Switched to
// output-tab class for parity with the in-session tab strip
// (Tmux/Channel/Stats). Scan + Rules Check tabs render conditionally
// based on whether their respective guardrails / results exist.
function _renderDetailTabStrip(prd, currentTab) {
  const hasScan  = !!prd.scan_enabled || !!prd.last_scan_at || !!prd.scan_result;
  const hasRules = !!prd.rules_enabled || !!prd.last_rules_at || !!prd.rules_result;
  const tabs = [
    ['overview',  t('prd_tab_overview')  || 'Overview', true],
    ['stories',   t('prd_tab_stories')   || 'Stories',  true],
    ['decisions', t('prd_tab_decisions') || 'Decisions', true],
    ['scan',      t('prd_tab_scan')      || 'Scan',      hasScan],
    ['rules',     t('prd_tab_rules')     || 'Rules',     hasRules],
  ];
  return `<div class="output-tabs prd-detail-tabs">
    ${tabs.filter(t => t[2]).map(([k, label]) => `
      <button class="output-tab ${k===currentTab?'active':''}" onclick="switchAutomataDetailTab('${k}')">${escHtml(label)}</button>
    `).join('')}
  </div>`;
}

// BL246 v6.6.0 — Overview tab: lifecycle strip, metadata, progress, verdicts.
function _renderDetailOverview(prd) {
  const stories = prd.stories || prd.Story || [];
  const totalTasks = stories.reduce((n, s) => n + (s.tasks || s.Tasks || []).length, 0);
  const doneTasks  = stories.reduce((n, s) => n + (s.tasks || s.Tasks || []).filter(tk => (tk.status || tk.Status) === 'completed').length, 0);
  const doneStories = stories.filter(s => (s.status || s.Status) === 'completed').length;
  const pct = totalTasks > 0 ? Math.round(doneTasks / totalTasks * 100) : 0;
  const pctFill = pct === 100 ? 'automata-progress-fill complete' : 'automata-progress-fill';
  // v6.13.8 — lifecycle strip moved to the persistent header (always
  // visible across sub-tabs), so the Overview body no longer renders
  // its own copy.
  return `
    <dl class="prd-detail-meta">
      ${prd.backend   ? `<dt>${escHtml(t('automata_detail_backend'))}</dt><dd>${escHtml(prd.backend)}</dd>` : ''}
      ${prd.effort    ? `<dt>${escHtml(t('automata_detail_effort'))}</dt><dd>${escHtml(String(prd.effort))}</dd>` : ''}
      ${prd.model     ? `<dt>${escHtml(t('automata_detail_model'))}</dt><dd>${escHtml(prd.model)}</dd>` : ''}
      ${prd.project_dir ? `<dt>${escHtml(t('automata_detail_project'))}</dt><dd>${escHtml(prd.project_dir)}</dd>` : ''}
      ${prd.depth     ? `<dt>${escHtml(t('automata_detail_depth'))}</dt><dd>${prd.depth}</dd>` : ''}
      ${prd.guided_mode ? `<dt>${escHtml(t('automata_detail_guided_mode'))}</dt><dd>✓</dd>` : ''}
      ${prd.skills && prd.skills.length ? `<dt>${escHtml(t('automata_detail_skills'))}</dt><dd>${prd.skills.map(s => `<span class="automata-filter-badge active" style="font-size:10px;">${escHtml(s)}</span>`).join(' ')}</dd>` : ''}
      <dt>${escHtml(t('automata_detail_created'))}</dt><dd>${escHtml(_fmtDate(prd.created_at))}</dd>
    </dl>
    ${totalTasks > 0 ? `<div class="prd-detail-progress" style="margin-top:10px;">
      <div style="font-size:11px;color:var(--text2);margin-bottom:4px;">${doneStories}/${stories.length} stories · ${doneTasks}/${totalTasks} tasks · ${pct}%</div>
      <div class="automata-progress-wrap"><div class="${pctFill}" style="width:${pct}%;"></div></div>
    </div>` : ''}
    ${renderDetailVerdicts(prd)}
    ${prd.spec ? `<details style="margin-top:12px;"><summary style="cursor:pointer;font-size:12px;font-weight:600;color:var(--text2);">${escHtml(t('prd_view_spec')||'View spec')}</summary>
      <pre style="font-size:11px;background:var(--bg2);padding:8px;border-radius:4px;white-space:pre-wrap;margin-top:6px;max-height:300px;overflow:auto;">${escHtml(prd.spec)}</pre>
    </details>` : ''}
  `;
}

// BL246 v6.6.0 — Stories tab: rich per-story tree using existing renderStory()
// which already exposes Edit / Profile / Files / Approve / Reject affordances.
function _renderDetailStories(prd) {
  const stories = prd.stories || prd.Story || [];
  if (stories.length === 0) return `<div style="color:var(--text2);font-size:12px;padding:12px 0;">${escHtml(t('prd_no_stories')||'No stories yet.')}</div>`;
  return stories.map(st => renderStory(prd, st)).join('');
}

// BL246 v6.6.0 — Decisions tab with full timeline + expandable detail per row.
function _renderDetailDecisionsTab(prd) {
  const decisions = prd.decisions || prd.Decisions || [];
  if (decisions.length === 0) return `<div style="color:var(--text2);font-size:12px;padding:12px 0;">${escHtml(t('prd_no_decisions')||'No decisions recorded yet.')}</div>`;
  // v6.13.5 — the daemon Decision struct has fixed fields (kind, backend,
  // model, prompt_chars, response_chars, cost_usd, verdict_outcome,
  // actor, note) — there is NO prompt/response text payload. So surface
  // every metadata field the daemon DOES record, instead of looking
  // for prompt/response keys that don't exist.
  const rows = decisions.slice().reverse().map((d) => {
    const time     = _fmtDate(d.at || d.At);
    const kind     = d.kind || d.Kind || '?';
    const note     = d.note || d.Note || '';
    const actor    = d.actor || d.Actor || '';
    const backend  = d.backend || d.Backend || '';
    const model    = d.model || d.Model || '';
    const pChars   = d.prompt_chars || d.PromptChars || 0;
    const rChars   = d.response_chars || d.ResponseChars || 0;
    const cost     = (d.cost_usd != null ? d.cost_usd : (d.CostUSD != null ? d.CostUSD : null));
    const verdict  = d.verdict_outcome || d.VerdictOutcome || '';
    const verdictColor = verdict === 'pass' ? '#10b981' : verdict === 'warn' ? '#f59e0b' : verdict === 'block' ? '#ef4444' : 'var(--text2)';
    // Build a 2-col grid of metadata pairs only for the fields actually present.
    const pairs = [];
    if (backend || model) pairs.push([t('prd_decision_backend')||'Backend', `${escHtml(backend)}${model ? ' · ' + escHtml(model) : ''}`]);
    if (pChars || rChars) pairs.push([t('prd_decision_tokens')||'Chars', `${pChars.toLocaleString()} in · ${rChars.toLocaleString()} out`]);
    if (cost != null && cost > 0) pairs.push([t('prd_decision_cost')||'Cost', `$${cost.toFixed(4)}`]);
    if (verdict) pairs.push([t('prd_decision_verdict')||'Verdict', `<span style="color:${verdictColor};font-weight:600;">${escHtml(verdict)}</span>`]);
    const grid = pairs.length === 0 ? '' : `
      <dl class="prd-decision-meta">
        ${pairs.map(([k, v]) => `<dt>${escHtml(k)}</dt><dd>${v}</dd>`).join('')}
      </dl>`;
    return `<div class="prd-decision-card">
      <div class="prd-decision-head">
        <span class="prd-decision-kind">${escHtml(kind)}</span>
        ${actor ? `<span class="prd-decision-actor">by ${escHtml(actor)}</span>` : ''}
        <span class="prd-decision-time">${escHtml(time)}</span>
      </div>
      ${note ? `<div class="prd-decision-note">${escHtml(note)}</div>` : ''}
      ${grid}
    </div>`;
  }).join('');
  return `<div style="font-size:11px;color:var(--text2);margin-bottom:8px;">${decisions.length} ${escHtml(t('prd_decisions_count')||'decisions')}</div>${rows}`;
}

// v6.13.1 (C10) — Rules Check tab. Shows the same shape as Scan when
// rules guardrail is enabled / has results. Operator: "shouldn't there
// also be a tab for rules check (if enabled) with similar cards
// showing the rules check tests?".
function _renderDetailRulesTab(prd) {
  const id = prd.id || '';
  const idJ = JSON.stringify(id);
  const r = prd.rules_result || null;
  return `
    <div style="font-size:11px;color:var(--text2);margin-bottom:8px;line-height:1.4;">
      ${escHtml(t('prd_rules_help')||'AGENT.md / project-rules check. Verifies the Automaton spec and any produced files comply with the operator-defined rules.')}
    </div>
    <div style="display:flex;align-items:center;gap:8px;margin-bottom:8px;flex-wrap:wrap;">
      <button class="btn-icon prd-header-btn" onclick="prdAction(${escHtml(idJ)},'scan/rules','POST')" title="${escHtml(t('prd_rules_run_title')||'Run rules check')}">▶ ${escHtml(t('rules_run')||'Run Rules Check')}</button>
    </div>
    <div id="prdRulesResult_${id}" style="font-size:12px;color:var(--text2);">
      ${r ? `<pre style="margin:0;padding:8px;background:var(--bg2);border-radius:4px;font-size:11px;white-space:pre-wrap;">${escHtml(typeof r === 'string' ? r : JSON.stringify(r, null, 2))}</pre>`
          : `<span style="opacity:0.6;">${escHtml(t('rules_no_results')||'No rules check results yet')}</span>`}
    </div>
  `;
}

// BL246 v6.6.0 — Scan tab with help tooltip explaining what Run Scan does.
function _renderDetailScanTab(prd) {
  const id = prd.id || '';
  const idJ = JSON.stringify(id);
  return `
    <div style="font-size:11px;color:var(--text2);margin-bottom:8px;line-height:1.4;">
      ${escHtml(t('prd_scan_help')||'Static analysis (SAST · secrets · dependencies · LLM grader) over the Automaton spec and any associated files. Runs the configured scanners and reports a verdict + findings.')}
    </div>
    <div style="display:flex;align-items:center;gap:8px;margin-bottom:8px;flex-wrap:wrap;">
      <button class="btn-icon prd-header-btn" onclick="runPRDScan(${escHtml(idJ)})" title="${escHtml(t('prd_scan_run_title')||'Run all configured scanners against this automaton')}">▶ ${escHtml(t('scan_run')||'Run Scan')}</button>
    </div>
    <div id="prdScanResult_${id}" style="font-size:12px;color:var(--text2);">${escHtml(t('state_loading')||'Loading…')}</div>
  `;
}

// BL221 Phase 3 — scan results in PRD detail view
function loadPRDScanResult(prdId) {
  const el = document.getElementById('prdScanResult_' + prdId);
  if (!el) return;
  apiFetch('/api/autonomous/prds/' + encodeURIComponent(prdId) + '/scan').then(r => {
    if (!r) { el.textContent = t('scan_no_results') || 'No scan results yet'; return; }
    _renderScanResult(el, prdId, r);
  }).catch(() => {
    el.innerHTML = `<span style="opacity:0.6;">${escHtml(t('scan_no_results')||'No scan results yet')}</span>`;
  });
}

function _renderScanResult(el, prdId, r) {
  const verdictColor = { pass: 'var(--success,#10b981)', warn: 'var(--warning,#f59e0b)', fail: 'var(--error,#ef4444)' };
  const color = verdictColor[r.verdict] || 'var(--text2)';
  const count = (r.findings || []).length;
  const idJ = JSON.stringify(prdId);
  el.innerHTML = `
    <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;">
      <span class="scan-verdict-badge" style="background:${color};color:#fff;border-radius:4px;padding:2px 8px;font-size:11px;font-weight:600;">
        ${escHtml((r.verdict||'').toUpperCase())}
      </span>
      <span style="color:var(--text2);font-size:11px;">${count} ${escHtml(t('scan_findings')||'findings')} · ${escHtml(r.at ? new Date(r.at).toLocaleString() : '')}</span>
      ${r.verdict !== 'pass' && count > 0 ? `
        <button class="btn-icon" style="font-size:11px;padding:2px 8px;" onclick="createScanFixPRD(${idJ})">${escHtml(t('scan_fix_prd')||'Create Fix Automaton')}</button>
        <button class="btn-icon" style="font-size:11px;padding:2px 8px;" onclick="proposeScanRules(${idJ})">${escHtml(t('scan_propose_rules')||'Propose AGENT.md Rules')}</button>
      ` : ''}
    </div>
    ${r.notes ? `<div style="font-size:11px;color:var(--text2);margin-top:4px;font-style:italic;">${escHtml(r.notes)}</div>` : ''}
    ${count > 0 ? `<details style="margin-top:6px;"><summary style="cursor:pointer;font-size:11px;color:var(--accent);">Findings (${count})</summary>
      <div style="max-height:200px;overflow-y:auto;margin-top:4px;">
        ${(r.findings||[]).map(f => `
          <div style="font-size:11px;padding:2px 0;border-top:1px solid var(--border);display:flex;align-items:flex-start;gap:6px;">
            <span style="font-weight:600;color:${verdictColor[f.severity==='critical'?'fail':f.severity==='error'?'fail':'warn']||'var(--text2)'};">[${escHtml(f.severity||'')}]</span>
            <span><code>${escHtml(f.file||'')}${f.line?':'+f.line:''}</code> ${escHtml(f.message||'')} <span style="opacity:0.5;">(${escHtml(f.rule_id||'')})</span></span>
          </div>`).join('')}
      </div>
    </details>` : ''}`;
}

window.runPRDScan = function(prdId) {
  const el = document.getElementById('prdScanResult_' + prdId);
  if (el) el.innerHTML = `<span style="opacity:0.7;">${escHtml(t('scan_running')||'Running scan…')}</span>`;
  apiFetch('/api/autonomous/prds/' + encodeURIComponent(prdId) + '/scan', { method: 'POST' })
    .then(r => {
      if (!r) return;
      const resultEl = document.getElementById('prdScanResult_' + prdId);
      if (resultEl) _renderScanResult(resultEl, prdId, r);
      showToast(r.pass ? (t('scan_pass')||'Scan passed') : (t('scan_fail')||'Scan failed'), r.pass ? 'success' : 'error', 3000);
    })
    .catch(e => showToast(String(e.message||e), 'error'));
};

window.createScanFixPRD = function(prdId) {
  apiFetch('/api/autonomous/prds/' + encodeURIComponent(prdId) + '/scan/fix', { method: 'POST' })
    .then(prd => {
      showToast('Fix Automaton created: ' + (prd&&prd.id||''), 'success', 3000);
      if (prd && prd.id) renderPRDDetailView(prd.id);
    })
    .catch(e => showToast(String(e.message||e), 'error'));
};

window.proposeScanRules = function(prdId) {
  showToast('Proposing rule edits…', 'info', 2000);
  apiFetch('/api/autonomous/prds/' + encodeURIComponent(prdId) + '/scan/rules', { method: 'POST' })
    .then(data => {
      const diff = (data && data.proposed_diff) || JSON.stringify(data, null, 2);
      showModal({
        title: t('scan_propose_rules') || 'Proposed AGENT.md Changes',
        body: `<pre style="font-size:11px;max-height:300px;overflow:auto;white-space:pre-wrap;">${escHtml(diff)}</pre>`,
        confirmLabel: 'Close',
        cancelLabel: null,
        onConfirm: () => {}
      });
    })
    .catch(e => showToast(String(e.message||e), 'error'));
};

function _backToAutomataList() {
  // GATE alpha.36 (operator 2026-05-10): renderAutonomousView() alone
  // doesn't reset the PWA banner (back chevron, title, search icon)
  // OR the bottom-nav highlight. Operator hit "back goes to list but
  // bottom-nav says Sessions". Route through navigate('autonomous')
  // which handles ALL the header/nav state in one place.
  _automataDetailId = null;
  _automataDetailBreadcrumb = [];
  history.pushState({ prdDetail: null }, '', '');
  // Reset header back-button + restore the headerSearchBtn that the
  // detail view hid; navigate() does the rest (title, identity btn,
  // bottom-nav highlight, view re-mount).
  const backBtn = document.getElementById('backBtn');
  if (backBtn) { backBtn.style.display = 'none'; backBtn.onclick = null; }
  const searchBtn = document.getElementById('headerSearchBtn');
  if (searchBtn) searchBtn.style.display = 'inline-flex';
  navigate('autonomous');
}
window._backToAutomataList = _backToAutomataList;

// Handle browser back/forward to toggle between list and detail view
(function() {
  const origOnPop = window.onpopstate;
  window.onpopstate = function(e) {
    if (state.activeView === 'autonomous') {
      if (e.state && e.state.prdDetail) {
        _automataDetailBreadcrumb = e.state.bc || [];
        renderPRDDetailView(e.state.prdDetail);
        return;
      } else if (_automataDetailId) {
        _automataDetailId = null;
        _automataDetailBreadcrumb = [];
        renderAutonomousView();
        return;
      }
    }
    if (origOnPop) origOnPop.call(this, e);
  };
})();

// Update scrollToPRD to navigate to detail view instead.
window.scrollToPRD = function(id) {
  if (state.activeView === 'autonomous') {
    renderPRDDetailView(id);
    return;
  }
  const rows = document.querySelectorAll('#prdPanel .prd-row, #automataPanel .prd-row');
  for (const row of rows) {
    const code = row.querySelector('code');
    if (code && code.textContent.trim() === id) {
      row.scrollIntoView({ behavior: 'smooth', block: 'center' });
      const orig = row.style.boxShadow;
      row.style.boxShadow = '0 0 0 2px var(--accent)';
      setTimeout(() => { row.style.boxShadow = orig; }, 1200);
      return;
    }
  }
  showToast('Automaton ' + id + ' not in current filter', 'info', 2500);
};

function renderAutonomousView() {
  const view = document.getElementById('view');
  if (!view) return;
  const st = _automataState;
  const statusBadges = ['draft','planning','needs_review','approved','running','blocked'].map(s => {
    const active = st.statusFilter.has(s) ? 'active' : '';
    const label = escHtml(t('automata_status_' + s.replace('needs_review','needs_review')) || s);
    return `<button class="automata-filter-badge status-${s} ${active}" onclick="toggleAutomataStatusFilter('${s}')">${label}</button>`;
  }).join('');
  const typeBadges = ['software','research','operational','personal'].map(type => {
    const active = st.typeFilter.has(type) ? 'active' : '';
    return `<button class="automata-filter-badge type-badge ${active}" data-type="${type}" onclick="toggleAutomataTypeFilter('${type}')">${escHtml(type)}</button>`;
  }).join('');

  view.innerHTML = `
    <div class="sessions-watermark"><img src="/favicon.svg" alt="" /></div>
    <div class="view-content" style="position:relative;">
      <!-- v6.12.4 — operator: "automata tab, automata and templates
           should be like tab headers, like tmux,channel,state are
           inside a session. not buttons". Reuse the output-tabs /
           output-tab classes for visual parity with the in-session
           tab strip. The right-side action buttons keep their existing
           class so they don't pick up the tab-style background. -->
      <!-- GATE alpha.36 (operator 2026-05-10): in-view '?' button removed
           — header banner already exposes Help via headerHelpLink for the
           'autonomous' view. Action buttons reordered: Select then Filter
           then History (operator: "filter button to right of select cards").
           All action buttons share the .automata-action-btn class for
           consistent sizing + padding (defined in style.css). -->
      <div class="output-tabs automata-tabs-bar">
        <button class="output-tab ${st.tab==='automata'?'active':''}" data-tab="automata" onclick="switchAutomataTab('automata')">${escHtml(t('automata_tab_automata'))}</button>
        <button class="output-tab ${st.tab==='templates'?'active':''}" data-tab="templates" onclick="switchAutomataTab('templates')">${escHtml(t('automata_tab_templates'))}</button>
        <div style="flex:1;"></div>
        <button id="automataSelectBtn" class="automata-action-btn ${st.selectMode?'active':''}" onclick="toggleAutomataSelectMode()" title="${escHtml(t('automata_select_title')||'Select cards for batch actions')}" style="${st.tab==='templates'?'display:none;':''}">&#9745;</button>
        <button id="automataFilterBtn" class="automata-action-btn ${st.filterOpen?'active':''}" onclick="toggleAutomataFilter()" title="Filter" style="${st.tab==='templates'?'display:none;':''}">⊞</button>
        <button id="automataHistoryBtn" class="automata-action-btn ${st.historyOn?'active':''}" onclick="toggleAutomataHistory()" title="${escHtml(st.historyOn ? t('automata_history_on') : t('automata_history_off'))}" style="${st.tab==='templates'?'display:none;':''}">⏱</button>
        <button id="automataNewTmplBtn" class="btn-primary" style="font-size:12px;padding:5px 12px;${st.tab!=='templates'?'display:none;':''}" onclick="openTemplateCreateModal()">＋ ${escHtml(t('automata_tmpl_new_short')||'Template')}</button>
      </div>
      <div id="automataFilterBar" class="automata-filter-bar" style="display:${st.filterOpen?'flex':'none'};">
        <input id="automataSearch" type="text" class="form-input" placeholder="${escHtml(t('automata_filter_search'))}" value="${escHtml(st.search)}" oninput="onAutomataSearchChange(this.value)" style="flex:1;min-width:100px;font-size:12px;">
        <div class="automata-badge-group">${statusBadges}</div>
        <div class="automata-badge-group">${typeBadges}</div>
        <label style="font-size:12px;display:inline-flex;gap:4px;align-items:center;white-space:nowrap;">
          <input type="checkbox" id="automataSelectAll" onchange="toggleAutomataSelectAll(this.checked)"> All
        </label>
      </div>
      <div id="automataPanel" style="font-size:13px;color:var(--text);padding:6px 8px;">
        <div style="text-align:center;padding:32px;color:var(--text2);">${escHtml(t('common_loading'))}</div>
      </div>
    </div>
  `;
  loadAutomataPanel();
  _injectServerPickerBar(view, renderAutonomousView); // BL312 S3
}
window.renderAutonomousView = renderAutonomousView;

// alpha.30 #271 + #183 #4 — Alerts tab redesigned to mirror the dock UX:
// top bar with per-category chips + ✕all + 🔕 + sort toggle + search,
// then per-session summary cards with prompts highlighted distinct from
// alerts and responses (chronological within each session).
// alpha.33 + alerts-tab restoration (operator 2026-05-10):
// Active/Historical/System tabs + per-tab chip + sort + search persistence.
function _alertsLoadTabState(tab) {
  try {
    const raw = localStorage.getItem('cs_alerts_tab_state_' + tab);
    if (raw) return JSON.parse(raw);
  } catch (_) {}
  return { active: 'all', search: '', sort: 'session' };
}
function _alertsPersistTabState(tab, state) {
  try { localStorage.setItem('cs_alerts_tab_state_' + tab, JSON.stringify(state)); } catch (_) {}
}
window._alertsTabSel = window._alertsTabSel || (localStorage.getItem('cs_alerts_active_tab') || 'active');
// Per-tab filter state. Loaded lazily on first access.
window._alertsFilters = window._alertsFilters || {};
function _alertsCurrentFilter() {
  const tab = window._alertsTabSel;
  if (!window._alertsFilters[tab]) window._alertsFilters[tab] = _alertsLoadTabState(tab);
  return window._alertsFilters[tab];
}
// Back-compat shim — old code references window._alertsFilter.
Object.defineProperty(window, '_alertsFilter', {
  get() { return _alertsCurrentFilter(); },
  configurable: true,
});

function renderAlertsView() {
  const view = document.getElementById('view');
  if (!view) return;
  view.innerHTML = `<div class="view-content"><div id="alertsList" style="padding:12px;"><div class="spinner" style="text-align:center;padding:32px;">${escHtml(t('common_loading'))}</div></div></div>`;
  _injectServerPickerBar(view, renderAlertsView); // BL312 S3

  // BL312 S5 — use aggregated endpoint in all-servers mode
  const alertsEndpoint = state.activeServer === 'all' ? '/api/alerts/aggregated' : '/api/alerts';
  Promise.all([
    fetch(alertsEndpoint, { headers: tokenHeader() }).then(r => r.ok ? r.json() : null),
    fetch('/api/commands', { headers: tokenHeader() }).then(r => r.ok ? r.json() : []),
    fetch('/api/sessions', { headers: tokenHeader() }).then(r => r.ok ? r.json() : [])
  ]).then(([data, cmds, freshSessions]) => {
    // Update state.sessions with fresh data so active/inactive classification is accurate
    if (freshSessions && freshSessions.length > 0) {
      state.sessions = freshSessions;
    }
    const el = document.getElementById('alertsList');
    if (!el) return;
    // Normalise: aggregated returns array, single-server returns {alerts:[...]}
    const alertList = Array.isArray(data) ? data : (data && data.alerts ? data.alerts : null);
    if (!alertList || alertList.length === 0) {
      el.innerHTML = `<div style="text-align:center;color:var(--text2);padding:32px;">${escHtml(t('common_no_alerts'))}</div>`;
      return;
    }

    state.alertUnread = 0;
    state.alertSystemUnread = 0;
    updateAlertBadge();
    fetch('/api/alerts', { method: 'POST', headers: { 'Content-Type': 'application/json', ...tokenHeader() }, body: JSON.stringify({ all: true }) });

    // Group by session (BL226: source=system or no session_id → __system__)
    const groups = new Map();
    for (const a of alertList) {
      const key = (a.source === 'system' || !a.session_id) ? '__system__' : a.session_id;
      if (!groups.has(key)) groups.set(key, []);
      groups.get(key).push(a);
    }

    const liveSessions = state.sessions || [];
    const DONE = new Set(['complete', 'failed', 'killed']);

    // Separate active vs inactive session groups
    const activeTabs = [];
    const inactiveTabs = [];
    const systemAlerts = groups.get('__system__') || [];
    groups.delete('__system__');

    for (const [sessID, alerts] of groups) {
      const sess = liveSessions.find(s => s.full_id === sessID || s.id === sessID);
      const sessState = sess ? sess.state : 'unknown';
      // Sessions not found in live list or in terminal states are inactive
      const isActive = sess && !DONE.has(sessState);
      const entry = { sessID, alerts, sess, sessState, isActive };
      if (isActive) activeTabs.push(entry);
      else inactiveTabs.push(entry);
    }

    const renderAlert = (a, sessState, isFirst) => {
      const levelColor = a.level === 'error' ? 'var(--error)' : a.level === 'warn' ? 'var(--warning,#f59e0b)' : 'var(--text2)';
      const isWaiting = sessState === 'waiting_input';

      // Quick-reply dropdown only on the first (latest) alert for a waiting session
      let replyBtns = '';
      if (isFirst && isWaiting && cmds && cmds.length > 0 && a.session_id) {
        const sessId = JSON.stringify(a.session_id);
        const opts = cmds.map(c => {
          const safeVal = escHtml(c.command);
          return `<option value="${safeVal}">${escHtml(c.name)}</option>`;
        }).join('');
        replyBtns = `<div class="quick-input-row" style="margin-top:6px;"><select class="quick-cmd-select" onchange="if(this.value){alertSendCmd(${sessId},this.value);this.selectedIndex=0;}"><option value="">${t('alerts_quick_reply_ph')||'Quick reply…'}</option>${opts}</select></div>`;
      }

      return `<div class="card alert-card" style="margin-bottom:6px;border-left:3px solid ${levelColor};">
        <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:4px;">
          <strong style="color:${levelColor};font-size:12px;">${escHtml(a.level.toUpperCase())}</strong>
          <span style="font-size:11px;color:var(--text2);">${timeAgo(a.created_at)}</span>
        </div>
        <div style="font-weight:500;font-size:13px;">${escHtml(a.title)}</div>
        <div style="font-size:12px;color:var(--text2);margin-top:2px;">${escHtml(a.body)}</div>
        ${replyBtns}
      </div>`;
    };

    const renderSessionSection = (entry, collapsed) => {
      const { sessID, alerts, sess, sessState } = entry;
      const label = sess ? (sess.name || sess.id) : sessID.split('-').pop();
      const stateColor = sessState === 'waiting_input' ? 'var(--warning,#f59e0b)' : sessState === 'running' ? 'var(--success)' : 'var(--text2)';
      const stateText = sessState === 'waiting_input' ? 'waiting input' : sessState;
      const sessLink = sess ? `<span style="cursor:pointer;text-decoration:underline;" onclick="${escHtml(`navigate('session',${JSON.stringify(sessID)})`)}">${escHtml(label)}</span>` : escHtml(label);
      const badge = `<span class="state" style="font-size:10px;color:${stateColor};">${stateText}</span>`;
      const count = `<span style="font-size:11px;color:var(--text2);">${alerts.length} alert${alerts.length !== 1 ? 's' : ''}</span>`;
      const toggleId = 'alert-grp-' + sessID.replace(/[^a-z0-9]/gi, '-');

      if (collapsed) {
        return `<div class="alert-session-group" style="margin-bottom:8px;">
          <div class="settings-section-toggle" onclick="document.getElementById('${toggleId}').style.display=document.getElementById('${toggleId}').style.display==='none'?'':'none'" style="padding:8px 12px;background:var(--bg2);border-radius:var(--radius-sm);cursor:pointer;">
            <span class="settings-chevron" id="${toggleId}-chev">▶</span>
            ${sessLink} ${badge} ${count}
          </div>
          <div id="${toggleId}" style="display:none;">
            ${alerts.map((a, i) => renderAlert(a, sessState, i === 0)).join('')}
          </div>
        </div>`;
      }
      return `<div class="alert-session-group" style="margin-bottom:12px;">
        <div style="display:flex;align-items:center;gap:8px;padding:8px 12px;background:var(--bg2);border-radius:var(--radius-sm) var(--radius-sm) 0 0;border-bottom:1px solid var(--border);">
          ${sessLink} ${badge} ${count}
        </div>
        <div style="padding:4px 0;">
          ${alerts.map((a, i) => renderAlert(a, sessState, i === 0)).join('')}
        </div>
      </div>`;
    };

    const activeCount = activeTabs.length;
    const inactiveCount = inactiveTabs.length;
    const systemCount = systemAlerts.length;
    const defaultTab = activeCount > 0 ? 'active' : (inactiveCount > 0 ? 'inactive' : 'system');

    // Build active content — sub-tabs per session, showing one at a time
    let activeHtml = '';
    if (activeTabs.length === 0) {
      activeHtml = `<div style="text-align:center;color:var(--text2);padding:24px;">${t('alerts_no_active')||'No active session alerts.'}</div>`;
    } else {
      // Sub-tabs row for each active session
      let subTabsHtml = '<div style="display:flex;gap:0;margin-bottom:8px;flex-wrap:wrap;">';
      for (let i = 0; i < activeTabs.length; i++) {
        const entry = activeTabs[i];
        const label = entry.sess ? (entry.sess.name || entry.sess.id) : entry.sessID.split('-').pop();
        const isFirst = i === 0;
        subTabsHtml += `<button class="output-tab${isFirst ? ' active' : ''}" id="alertSessTab-${i}" onclick="switchAlertSessionTab(${i}, ${activeTabs.length})">${escHtml(label)}</button>`;
      }
      subTabsHtml += '</div>';
      activeHtml += subTabsHtml;

      // One panel per active session, only first visible
      for (let i = 0; i < activeTabs.length; i++) {
        const entry = activeTabs[i];
        activeHtml += `<div id="alertSessPanel-${i}" style="${i === 0 ? '' : 'display:none'}">
          ${renderSessionSection(entry, false)}
        </div>`;
      }
    }

    // Build inactive content — all collapsed
    let inactiveHtml = '';
    if (inactiveTabs.length === 0) {
      inactiveHtml = `<div style="text-align:center;color:var(--text2);padding:24px;">${t('alerts_no_inactive')||'No inactive alerts.'}</div>`;
    } else {
      for (const entry of inactiveTabs) {
        inactiveHtml += renderSessionSection(entry, true);
      }
    }

    // Build system tab content — BL226: pipeline/plugin/eBPF failures
    let systemHtml = '';
    if (systemAlerts.length === 0) {
      systemHtml = `<div style="text-align:center;color:var(--text2);padding:24px;">${t('alerts_no_system')||'No system alerts.'}</div>`;
    } else {
      systemHtml = systemAlerts.map((a, i) => renderAlert(a, '', i === 0)).join('');
    }
    const sysBadge = systemCount > 0
      ? `<span style="background:var(--error);color:#fff;border-radius:10px;font-size:10px;padding:1px 5px;margin-left:4px;">${systemCount > 99 ? '99+' : systemCount}</span>`
      : '';

    // alpha.30 #271 + #183 #4 — redesigned: top bar mirrors dock,
    // sessions as cards with summary header, prompts highlighted
    // distinct from alerts and responses.
    // alpha.33 (operator 2026-05-10): Active / Historical / System
    // tabs restored at top with per-tab filter persistence.
    const tabSel = window._alertsTabSel;
    const filt = _alertsCurrentFilter();
    // Slice the data per the selected tab.
    let allEntries;
    let systemForTab;
    if (tabSel === 'active') { allEntries = activeTabs.slice(); systemForTab = []; }
    else if (tabSel === 'historical') { allEntries = inactiveTabs.slice(); systemForTab = []; }
    else { allEntries = []; systemForTab = systemAlerts; }
    const tabBtn = (tabId, label, count) => {
      const isActive = tabSel === tabId;
      return `<button onclick="setAlertsTab('${tabId}')" class="output-tab ${isActive?'active':''}" style="font-size:13px;padding:6px 14px;">${escHtml(label)} (${count})</button>`;
    };
    const tabsRow = `<div style="display:flex;gap:0;border-bottom:1px solid var(--border);margin-bottom:8px;">
      ${tabBtn('active', t('alerts_active_tab_label')||'Active', activeTabs.length)}
      ${tabBtn('historical', t('alerts_historical_tab_label')||'Historical', inactiveTabs.length)}
      ${tabBtn('system', t('alerts_system_tab_label')||'System', systemAlerts.length)}
    </div>`;

    // Categorize each alert. `prompt` = needs-input session OR title
    // mentions "needs input"/"prompt"/"waiting"; else use level.
    const catOf = (a, sessState) => {
      if (sessState === 'waiting_input' || /\b(needs input|prompt|waiting)\b/i.test(a.title || '')) return 'prompt';
      if (a.level === 'error') return 'error';
      if (a.level === 'warn') return 'warn';
      return 'info';
    };
    const catCounts = { all: 0, prompt: 0, error: 0, warn: 0, info: 0 };
    for (const e of allEntries) {
      for (const a of e.alerts) {
        const c = catOf(a, e.sessState);
        catCounts[c]++;
        catCounts.all++;
      }
    }
    for (const a of systemForTab) {
      const c = catOf(a, '');
      catCounts[c]++;
      catCounts.all++;
    }

    const matchesFilter = (a, sessState) => {
      if (filt.active !== 'all' && catOf(a, sessState) !== filt.active) return false;
      if (filt.search) {
        const s = filt.search.toLowerCase();
        const hay = (a.title + ' ' + (a.body || '')).toLowerCase();
        if (!hay.includes(s)) return false;
      }
      return true;
    };

    const chipBtn = (key, label, n, color) => {
      const isActive = filt.active === key;
      const bg = isActive ? color : 'var(--bg2)';
      const fg = isActive ? 'var(--bg)' : 'var(--text)';
      return `<button onclick="setAlertsFilter('${key}')" style="background:${bg};color:${fg};border:1px solid ${color};border-radius:10px;padding:3px 10px;font-size:12px;margin-right:4px;cursor:pointer;">${escHtml(label)} ×${n}</button>`;
    };

    const topBar = `
      <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;padding:6px 0;border-bottom:1px solid var(--border);margin-bottom:8px;">
        <span style="font-weight:700;font-size:14px;">🔔 ${catCounts.all} ${catCounts.all === 1 ? 'alert' : 'alerts'}</span>
        <span style="display:flex;gap:0;flex-wrap:wrap;">
          ${chipBtn('all', t('alert_chip_all')||'all', catCounts.all, 'var(--text2)')}
          ${chipBtn('prompt', '🟡 ' + (t('alert_chip_prompt')||'prompts'), catCounts.prompt, 'var(--warning,#f59e0b)')}
          ${chipBtn('error', '🔴 ' + (t('alert_chip_error')||'errors'), catCounts.error, 'var(--error,#ef4444)')}
          ${chipBtn('warn', '🟠 ' + (t('alert_chip_warn')||'warn'), catCounts.warn, 'var(--warning,#f59e0b)')}
          ${chipBtn('info', '⚪ ' + (t('alert_chip_info')||'info'), catCounts.info, 'var(--text2)')}
        </span>
        <span style="margin-left:auto;display:flex;gap:6px;align-items:center;">
          <input id="alertsSearchInput" type="search" placeholder="${escHtml(t('alert_search_ph')||'Search alerts…')}" value="${escHtml(filt.search)}"
                 oninput="(function(v){const f=_alertsCurrentFilter();f.search=v;_alertsPersistTabState(window._alertsTabSel,f);renderAlertsView();})(this.value)" style="padding:3px 8px;font-size:12px;border:1px solid var(--border);border-radius:6px;background:var(--bg2);color:var(--text);width:160px;" />
          <button onclick="setAlertsSort('${filt.sort === 'session' ? 'chrono' : 'session'}')" title="${escHtml(t('alert_sort_tip')||'Toggle sort: by session ↔ chronological')}" style="padding:3px 8px;font-size:12px;border:1px solid var(--border);border-radius:6px;background:var(--bg2);color:var(--text);cursor:pointer;">${filt.sort === 'session' ? '⏷ ' + (t('alert_sort_session')||'by session') : '🕒 ' + (t('alert_sort_chrono')||'chronological')}</button>
          <button onclick="dismissAlertsAll()" title="${escHtml(t('alert_dismiss_all_tip')||'Dismiss all alerts (server-side acked already)')}" style="padding:3px 8px;font-size:12px;border:1px solid var(--border);border-radius:6px;background:var(--bg2);color:var(--text);cursor:pointer;">✕</button>
          <button onclick="muteAlertDock()" title="${escHtml(t('alert_dock_mute')||'Mute alerts for this session')}" style="padding:3px 8px;font-size:12px;border:1px solid var(--border);border-radius:6px;background:var(--bg2);color:var(--text);cursor:pointer;">🔕</button>
          <button onclick="renderAlertsView()" title="${escHtml(t('alerts_refresh_btn')||'Refresh')}" style="padding:3px 8px;font-size:12px;border:1px solid var(--border);border-radius:6px;background:var(--bg2);color:var(--text);cursor:pointer;">↻</button>
        </span>
      </div>`;

    // Per-session card render with prompts highlighted distinctly.
    const renderRow = (a, sessState) => {
      const cat = catOf(a, sessState);
      const time = new Date(a.created_at).toLocaleTimeString('en-GB', { hour12: false });
      let kindBadge, borderColor, bg;
      if (cat === 'prompt') {
        kindBadge = `<span style="background:var(--warning,#f59e0b);color:var(--bg);font-weight:700;padding:1px 6px;border-radius:3px;font-size:10px;">🟡 PROMPT</span>`;
        borderColor = 'var(--warning,#f59e0b)';
        bg = 'rgba(245,158,11,0.08)';
      } else if (cat === 'error') {
        kindBadge = `<span style="background:var(--error);color:#fff;font-weight:700;padding:1px 6px;border-radius:3px;font-size:10px;">🔴 ERROR</span>`;
        borderColor = 'var(--error)';
        bg = 'rgba(239,68,68,0.06)';
      } else {
        kindBadge = `<span style="background:var(--bg2);padding:1px 6px;border-radius:3px;font-size:10px;color:var(--text2);">⚪ ${escHtml(a.level)}</span>`;
        borderColor = 'var(--border)';
        bg = 'transparent';
      }
      let replyBtns = '';
      if (cat === 'prompt' && a.session_id && cmds && cmds.length > 0) {
        const sessId = JSON.stringify(a.session_id);
        const opts = cmds.map(c => `<option value="${escHtml(c.command)}">${escHtml(c.name)}</option>`).join('');
        replyBtns = `<select class="quick-cmd-select" onchange="if(this.value){alertSendCmd(${sessId},this.value);this.selectedIndex=0;}" style="margin-top:4px;font-size:11px;">
          <option value="">${escHtml(t('alerts_quick_reply_ph')||'Quick reply…')}</option>${opts}
        </select>`;
      }
      return `<div style="border-left:3px solid ${borderColor};background:${bg};padding:6px 10px;margin:4px 0;border-radius:0 4px 4px 0;">
        <div style="display:flex;gap:8px;align-items:center;margin-bottom:2px;">
          ${kindBadge}
          <span style="opacity:0.55;font-family:var(--mono,monospace);font-size:11px;">${time}</span>
          <span style="font-weight:600;font-size:13px;">${escHtml(a.title)}</span>
        </div>
        ${a.body ? `<div style="font-size:12px;color:var(--text2);">${escHtml(a.body)}</div>` : ''}
        ${replyBtns}
      </div>`;
    };

    // Sort sessions: waiting_input first, then running, then everything else.
    const stateRank = s => s === 'waiting_input' ? 0 : s === 'running' ? 1 : 2;
    const sortedEntries = [...allEntries].sort((a, b) => stateRank(a.sessState) - stateRank(b.sessState));

    let bodyHTML = '';
    if (filt.sort === 'chrono') {
      // Flat chronological — newest first across all sessions.
      const flat = [];
      for (const e of allEntries) {
        for (const a of e.alerts) {
          if (matchesFilter(a, e.sessState)) flat.push({ a, sessState: e.sessState, sess: e.sess, sessID: e.sessID });
        }
      }
      for (const a of systemForTab) if (matchesFilter(a, '')) flat.push({ a, sessState: '', sess: null, sessID: '__system__' });
      flat.sort((x, y) => new Date(y.a.created_at) - new Date(x.a.created_at));
      if (flat.length === 0) {
        bodyHTML = `<div style="text-align:center;color:var(--text2);padding:32px;">${escHtml(t('common_no_alerts'))}</div>`;
      } else {
        bodyHTML = flat.map(item => {
          const label = item.sess ? (item.sess.name || item.sess.id) : (item.sessID === '__system__' ? 'system' : item.sessID.split('-').pop());
          const sessLink = item.sess ? `<a onclick="navigate('session',${JSON.stringify(item.sessID)})" style="color:var(--accent2);cursor:pointer;text-decoration:underline;">${escHtml(label)}</a>` : `<span style="color:var(--text2);">${escHtml(label)}</span>`;
          return `<div style="margin-bottom:2px;"><span style="font-size:10px;color:var(--text2);">${sessLink}</span>${renderRow(item.a, item.sessState)}</div>`;
        }).join('');
      }
    } else {
      // By session — summary card per session.
      const renderSessionCard = (entry, isSystem) => {
        const visible = entry.alerts.filter(a => matchesFilter(a, entry.sessState || ''));
        if (visible.length === 0) return '';
        const label = isSystem ? (t('alert_session_system')||'System')
          : (entry.sess ? (entry.sess.name || entry.sess.id) : entry.sessID.split('-').pop());
        const stateColor = entry.sessState === 'waiting_input' ? 'var(--warning,#f59e0b)' : entry.sessState === 'running' ? 'var(--success)' : 'var(--text2)';
        const stateText = entry.sessState === 'waiting_input' ? '🟠 waiting input' : entry.sessState === 'running' ? '🟢 running' : entry.sessState ? '✅ ' + entry.sessState : '';
        const lastTime = visible.length > 0 ? new Date(visible[0].created_at).toLocaleTimeString('en-GB', { hour12: false }) : '—';
        const promptCount = visible.filter(a => catOf(a, entry.sessState) === 'prompt').length;
        const promptHint = promptCount > 0 ? ` · <span style="color:var(--warning,#f59e0b);font-weight:700;">🟡 ${promptCount}</span>` : '';
        const sessLink = (!isSystem && entry.sess) ? `<a onclick="navigate('session',${JSON.stringify(entry.sessID)})" style="color:var(--accent2);cursor:pointer;text-decoration:underline;">${escHtml(label)}</a>` : escHtml(label);
        const grpId = 'alert-grp-' + (entry.sessID || 'sys').replace(/[^a-z0-9]/gi, '-');
        return `<div style="border:1px solid var(--border);border-radius:6px;margin-bottom:10px;overflow:hidden;">
          <div onclick="document.getElementById('${grpId}').style.display=document.getElementById('${grpId}').style.display==='none'?'':'none'"
               style="padding:8px 12px;background:var(--bg2);cursor:pointer;display:flex;align-items:center;gap:8px;font-size:13px;">
            <span style="font-weight:700;">${sessLink}</span>
            ${stateText ? `<span style="color:${stateColor};font-size:11px;">${stateText}</span>` : ''}
            <span style="color:var(--text2);font-size:11px;">${visible.length} ${visible.length === 1 ? (t('alert_dock_one')||'alert') : (t('alert_dock_many')||'alerts')}${promptHint}</span>
            <span style="margin-left:auto;color:var(--text2);font-family:var(--mono,monospace);font-size:11px;">last ${lastTime}</span>
          </div>
          <div id="${grpId}" style="padding:6px 10px;">
            ${visible.map(a => renderRow(a, entry.sessState || '')).join('')}
          </div>
        </div>`;
      };
      bodyHTML = sortedEntries.map(e => renderSessionCard(e, false)).join('');
      if (systemForTab.length > 0) {
        bodyHTML += renderSessionCard({ sessID: '__system__', alerts: systemForTab, sess: null, sessState: '' }, true);
      }
      if (!bodyHTML) {
        bodyHTML = `<div style="text-align:center;color:var(--text2);padding:32px;">${escHtml(t('common_no_alerts'))}</div>`;
      }
    }

    el.innerHTML = tabsRow + topBar + bodyHTML;
  }).catch(() => {
    const el = document.getElementById('alertsList');
    if (el) el.innerHTML = `<div style="color:var(--error);padding:16px;">${t('alerts_load_error')||'Failed to load alerts.'}</div>`;
  });
}

// alpha.30 #271 + alpha.33 tabs restoration — per-tab persistence.
window.setAlertsFilter = function(cat) {
  const f = _alertsCurrentFilter();
  f.active = cat;
  _alertsPersistTabState(window._alertsTabSel, f);
  renderAlertsView();
};
window.setAlertsSort = function(mode) {
  const f = _alertsCurrentFilter();
  f.sort = mode;
  _alertsPersistTabState(window._alertsTabSel, f);
  renderAlertsView();
};
window.setAlertsTab = function(tab) {
  window._alertsTabSel = tab;
  try { localStorage.setItem('cs_alerts_active_tab', tab); } catch (_) {}
  renderAlertsView();
};
window.dismissAlertsAll = function() {
  fetch('/api/alerts', { method: 'POST', headers: { 'Content-Type': 'application/json', ...tokenHeader() }, body: JSON.stringify({ all: true, delete: true }) })
    .then(() => renderAlertsView())
    .catch(() => renderAlertsView());
};

function switchAlertSessionTab(idx, total) {
  for (let i = 0; i < total; i++) {
    const tab = document.getElementById('alertSessTab-' + i);
    const panel = document.getElementById('alertSessPanel-' + i);
    if (tab) tab.classList.toggle('active', i === idx);
    if (panel) panel.style.display = i === idx ? '' : 'none';
  }
}

function switchAlertTab(tab) {
  const activeTab = document.getElementById('alertTabActive');
  const inactiveTab = document.getElementById('alertTabInactive');
  const activePanel = document.getElementById('alertPanelActive');
  const inactivePanel = document.getElementById('alertPanelInactive');
  const systemTab = document.getElementById('alertTabSystem');
  const systemPanel = document.getElementById('alertPanelSystem');
  if (!activeTab || !inactiveTab || !activePanel || !inactivePanel) return;
  [activeTab, inactiveTab, systemTab].forEach(t => t && t.classList.remove('active'));
  [activePanel, inactivePanel, systemPanel].forEach(p => p && (p.style.display = 'none'));
  if (tab === 'active') {
    activeTab.classList.add('active');
    activePanel.style.display = '';
  } else if (tab === 'system') {
    if (systemTab) systemTab.classList.add('active');
    if (systemPanel) systemPanel.style.display = '';
  } else {
    inactiveTab.classList.add('active');
    inactivePanel.style.display = '';
  }
}

function alertSendCmd(sessID, command) {
  apiFetch('/api/command', { method: 'POST', body: { text: 'send ' + sessID.split('-').pop() + ': ' + command } })
    .then(() => { showToast('Sent: ' + command); renderAlertsView(); })
    .catch(e => showToast('Error: ' + e.message, 'error'));
}

// ── Saved Commands (in Settings) ───────────────────────────────────────────────

function pageCmd(dir) {
  settingsPagination.cmds = Math.max(0, (settingsPagination.cmds || 0) + dir);
  loadSavedCommands();
}

function loadStatsPanel() {
  const el = document.getElementById('statsPanel');
  if (!el) return;
  apiFetch('/api/stats').then(data => {
    renderStatsData(el, data);
  }).catch(() => { el.innerHTML = `<div style="color:var(--text2);font-size:12px;padding:8px;">${t('stats_unavailable')||'Stats unavailable.'}</div>`; });
  // v4.1.0 — load installed-plugins status strip into the card footer.
  loadPluginsStatus();
  // v4.1.1 — load eBPF status strip just above plugins.
  loadEBPFStatus();
  // BL172 (S11) — federated peers row.
  loadObserverPeers();
  // BL173 (S12) — cluster nodes (Shape C); shows itself only if non-empty.
  loadObserverClusterNodes();
  // v5.27.10 (BL216) — MCP channel bridge state.
  loadChannelBridge();
}

// v5.27.10 (BL216) — render /api/channel/info into the Monitor card so
// the operator can see at a glance which bridge sessions are using.
// Surfaces stale .mcp.json files with a one-click cleanup hint.
function loadChannelBridge() {
  const el = document.getElementById('channelBridgeStatus');
  if (!el) return;
  apiFetch('/api/channel/info').then(info => {
    if (!info || typeof info !== 'object') {
      el.textContent = 'unavailable';
      return;
    }
    const kindBadge = info.kind === 'go'
      ? '<span style="color:var(--success);font-weight:600;">Go</span>'
      : '<span style="color:var(--warning);font-weight:600;">JS (fallback)</span>';
    const ready = info.ready ? '✓' : '⚠';
    let html = '';
    html += `<div>Bridge: ${kindBadge} ${ready}</div>`;
    if (info.path) {
      html += `<div style="opacity:0.75;word-break:break-all;">${escHtml(info.path)}</div>`;
    }
    if (!info.ready && info.hint) {
      html += `<div style="color:var(--warning);margin-top:4px;">${escHtml(info.hint)}</div>`;
    }
    if (info.kind === 'js' && info.node_path) {
      html += `<div style="opacity:0.75;margin-top:2px;">node: ${escHtml(info.node_path)}</div>`;
    }
    // v5.28.7 — show MCP mode status (stdio/SSE) so operator can see
    // what's actually running without checking the config page separately.
    if (info.stdio_enabled || info.sse_enabled) {
      const modes = [];
      if (info.stdio_enabled) modes.push('<span style="color:var(--success);font-weight:500;">stdio</span>');
      if (info.sse_enabled) modes.push('<span style="color:var(--success);font-weight:500;">SSE</span>');
      html += `<div style="margin-top:4px;">MCP: ${modes.join(' + ')}</div>`;
    }
    if (Array.isArray(info.stale_mcp_json) && info.stale_mcp_json.length) {
      html += `<div style="margin-top:6px;color:var(--warning);">Stale .mcp.json files (point at missing channel.js):</div>`;
      info.stale_mcp_json.forEach(e => {
        html += `<div style="opacity:0.85;word-break:break-all;">• ${escHtml(e.path)} → ${escHtml(e.missing_channel_js)}</div>`;
      });
      html += `<div style="opacity:0.7;margin-top:4px;">Run <code>datawatch channel cleanup-stale-mcp-json</code> to remove.</div>`;
    }
    el.innerHTML = html;
  }).catch(() => {
    el.textContent = 'unavailable';
  });
}

// v4.1.1 — render the eBPF state from the observer's StatsResponse v2.
// Shows configured / capability / kprobe-loaded with honest messages
// so the operator knows whether a `datawatch setup ebpf` actually
// took effect.
function loadEBPFStatus() {
  const line = document.getElementById('ebpfStatusLine');
  if (!line) return;
  apiFetch('/api/stats?v=2').then(s => {
    const e = (s && s.host && s.host.ebpf) || null;
    if (!e) { line.innerHTML = '<span style="opacity:0.7;">observer disabled</span>'; return; }
    const dot = (color, label) => `<span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:${color};margin-right:6px;vertical-align:middle;"></span>${label}`;
    let head;
    if (e.kprobes_loaded) {
      head = dot('var(--success,#10b981)', 'live — per-process net wired');
    } else if (e.configured && e.capability) {
      head = dot('var(--accent2,#7c3aed)', 'configured + capability granted');
    } else if (e.configured) {
      head = dot('var(--warning,#f59e0b)', 'configured but capability missing');
    } else {
      head = dot('var(--text2)', 'off');
    }
    const msg = e.message ? `<div style="opacity:0.8;margin-top:3px;">${escHtml(e.message)}</div>` : '';
    line.innerHTML = head + msg;
  }).catch(() => {
    line.innerHTML = '<span style="opacity:0.7;">/api/stats?v=2 unavailable</span>';
  });
}

// v4.1.0 — populate the plugins-installed strip that sits at the
// bottom of the System Statistics card in Settings → Monitor.
function loadPluginsStatus() {
  const list = document.getElementById('pluginsStatusList');
  if (!list) return;
  apiFetch('/api/plugins').then(data => {
    const plugins = (data && data.plugins) || [];
    const native = (data && data.native) || [];
    const nativeRows = native.map(p => {
      const on = !!p.enabled;
      const dot = `<span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:${on?'var(--success,#10b981)':'var(--text2)'};margin-right:6px;"></span>`;
      const tag = ` <span style="opacity:0.55;font-size:11px;border:1px solid var(--text2);border-radius:3px;padding:0 4px;margin-left:4px;">native</span>`;
      const ver = p.version ? ` <span style="opacity:0.6;">v${escHtml(p.version)}</span>` : '';
      const desc = p.description ? ` &middot; <span style="opacity:0.7;">${escHtml(p.description)}</span>` : '';
      const msg = p.message ? ` &middot; <span style="opacity:0.6;font-size:12px;">${escHtml(p.message)}</span>` : '';
      return `<div style="padding:3px 0;">${dot}<strong>${escHtml(p.name)}</strong>${tag}${ver}${desc}${msg}</div>`;
    }).join('');
    const subRows = plugins.map(p => {
      const on = !!p.enabled;
      const dot = `<span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:${on?'var(--success,#10b981)':'var(--text2)'};margin-right:6px;"></span>`;
      const hooks = Array.isArray(p.hooks) && p.hooks.length
        ? ` &middot; <span style="opacity:0.7;">${p.hooks.join(', ')}</span>` : '';
      const invokes = (typeof p.invoke_count === 'number' && p.invoke_count > 0)
        ? ` &middot; <span style="opacity:0.7;">${p.invoke_count} invoke${p.invoke_count===1?'':'s'}</span>` : '';
      const err = p.last_error ? ` &middot; <span style="color:var(--error);" title="${escHtml(p.last_error)}">last-error</span>` : '';
      return `<div style="padding:3px 0;">${dot}<strong>${escHtml(p.name)}</strong>${p.version?` <span style="opacity:0.6;">v${escHtml(p.version)}</span>`:''} &middot; ${on?'enabled':'disabled'}${hooks}${invokes}${err}</div>`;
    }).join('');
    if (!nativeRows && !subRows) {
      list.innerHTML = '<span style="opacity:0.7;">none installed</span> &middot; <a href="/docs/api/plugins.md" style="color:var(--accent2);">plugin docs</a>';
      return;
    }
    list.innerHTML = nativeRows + subRows;
  }).catch(() => {
    // /api/plugins should always succeed now (native list is unconditional).
    list.innerHTML = '<span style="opacity:0.7;">plugin status unavailable</span>';
  });
}

// BL172 (S11) — federated observer peers (Shape B / C). Reads
// /api/observer/peers; renders a single line per peer with health
// dot, last-push age, and Snapshot / Remove actions. 503 (registry
// disabled) shows a calm "off" message rather than an error state.
// S13 — federated peers filter persists in localStorage.
// Values: "all" | "B" | "C" | "A" (A = agent / F10 worker).
function getPeerFilter() {
  return localStorage.getItem('cs_peer_filter') || 'all';
}
function setPeerFilter(v) {
  localStorage.setItem('cs_peer_filter', v);
  loadObserverPeers();
}

function loadObserverPeers() {
  const list = document.getElementById('observerPeersList');
  if (!list) return;
  // alpha.23b — also fetch ComputeNodes so each peer row can show
  // which Node it backs ("attached to <node>" / "(free)").
  Promise.all([
    apiFetch('/api/observer/peers').then(r => r).catch(() => ({peers:[]})),
    apiFetch('/api/compute/nodes').then(r => r).catch(() => ({nodes:[]})),
  ]).then(([data, nodesResp]) => {
    const peers = (data && data.peers) || [];
    const allNodes = (nodesResp && nodesResp.nodes) || [];
    // Build peer → [nodeNames] map. A node is "bound to" a peer when
    // node.observer_peer == peer.name OR node.name == peer.name (the
    // implicit auto-create binding).
    const peerToNodes = {};
    for (const n of allNodes) {
      const explicit = n.observer_peer || '';
      if (explicit) (peerToNodes[explicit] = peerToNodes[explicit] || []).push(n.name);
      else (peerToNodes[n.name] = peerToNodes[n.name] || []).push(n.name);
    }
    // Filter pill row — always rendered when there's at least one
    // peer of any kind, since the count distribution is what helps
    // the operator scope.
    const filter = getPeerFilter();
    const counts = { all: peers.length, A: 0, B: 0, C: 0 };
    for (const p of peers) {
      const s = (p.shape || '').toUpperCase();
      if (counts[s] !== undefined) counts[s]++;
    }
    const pillBtn = (val, label) => {
      const active = filter === val ? 'background:var(--accent2);color:var(--bg);' : '';
      return `<button class="filter-toggle-btn" style="${active}" onclick="setPeerFilter('${val}')">${label} (${counts[val]||0})</button>`;
    };
    // alpha.24 #231 — "Group by ComputeNode" toggle. When on, render
    // per-CN buckets via /api/federation/meta-peers; when off, the
    // existing flat per-peer table.
    const groupByNode = localStorage.getItem('cs_peer_group_by_node') === '1';
    const pills = peers.length > 0
      ? `<div style="display:flex;gap:4px;padding:0 0 6px;flex-wrap:wrap;align-items:center;">
          ${pillBtn('all','All')}
          ${pillBtn('A','Agents')}
          ${pillBtn('B','Standalone')}
          ${pillBtn('C','Cluster')}
          <button class="filter-toggle-btn" style="${groupByNode?'background:var(--accent2);color:var(--bg);':''}" onclick="togglePeerGroupByNode()" title="${escHtml(t('peer_group_by_node_tip')||'Group peers by their bound ComputeNode (alpha.24)')}">⊞ ${escHtml(t('peer_group_by_node')||'Group by ComputeNode')}</button>
          <button class="filter-toggle-btn" style="margin-left:auto;background:rgba(96,165,250,0.18);" onclick="showCrossHostView()" title="local + every peer with cross-peer caller attribution">↔ Cross-host view</button>
        </div>` : '';

    if (!peers.length) {
      list.innerHTML = pills + '<span style="opacity:0.7;">no peers registered</span> &middot; '
        + '<span style="opacity:0.7;">deploy <code>datawatch-stats --datawatch &lt;url&gt; --name &lt;peer&gt;</code> on a remote host, or spawn an autonomous worker (it auto-peers). <a href="/docs/api/observer-peers.md" style="color:var(--accent);">docs</a></span>';
      return;
    }
    const visible = filter === 'all' ? peers : peers.filter(p => (p.shape || '').toUpperCase() === filter);
    if (visible.length === 0) {
      list.innerHTML = pills + `<span style="opacity:0.7;">no peers match the "${escHtml(filter)}" filter</span>`;
      return;
    }
    const now = Date.now();
    const rows = visible.map(p => {
      const lastPush = p.last_push_at ? new Date(p.last_push_at).getTime() : 0;
      const ageMs = lastPush ? (now - lastPush) : Infinity;
      let dotColor = 'var(--text2)';
      let ageLabel = 'never pushed';
      if (lastPush) {
        if (ageMs < 15000) dotColor = 'var(--success,#10b981)';
        else if (ageMs < 60000) dotColor = 'var(--warning,#f59e0b)';
        else dotColor = 'var(--error,#ef4444)';
        ageLabel = 'last push ' + observerPeerAgo(ageMs);
      }
      const dot = `<span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:${dotColor};margin-right:6px;"></span>`;
      // S13 — friendlier shape labels.
      const shapeLabels = { A: 'agent', B: 'standalone', C: 'cluster' };
      const shapeKey = (p.shape || '?').toUpperCase();
      const shapeText = shapeLabels[shapeKey] || ('shape ' + (p.shape||'?'));
      const shapeTag = `<span style="opacity:0.55;font-size:11px;border:1px solid var(--text2);border-radius:3px;padding:0 4px;margin-left:4px;">${escHtml(shapeText)}</span>`;
      const ver = p.version ? ` <span style="opacity:0.6;">v${escHtml(p.version)}</span>` : '';
      const safeName = JSON.stringify(p.name || '');
      const actions = `
        <button class="btn-icon" title="Last snapshot" style="font-size:11px;padding:1px 6px;margin-left:8px;" onclick='showObserverPeerSnapshot(${safeName})'>&#128202;</button>
        <button class="btn-icon" title="Remove peer (rotates token; peer auto-re-registers)" style="font-size:11px;padding:1px 6px;" onclick='removeObserverPeer(${safeName})'>&times;</button>`;
      // alpha.23b — show attached ComputeNode(s) or "(free)".
      const bound = peerToNodes[p.name] || [];
      const attachTag = bound.length > 0
        ? `<span title="${escHtml(t('observer_attached_to')||'attached to ComputeNode')}" style="margin-left:6px;font-size:11px;color:var(--accent2);border:1px solid var(--accent2);border-radius:3px;padding:0 4px;">⇄ ${escHtml(bound.join(', '))}</span>`
        : `<span title="${escHtml(t('observer_free_tooltip')||'no ComputeNode bound to this peer')}" style="margin-left:6px;font-size:11px;color:var(--text2);border:1px dashed var(--text2);border-radius:3px;padding:0 4px;">${escHtml(t('observer_free')||'free')}</span>`;
      return `<div style="padding:4px 0;display:flex;align-items:center;flex-wrap:wrap;">${dot}<strong>${escHtml(p.name)}</strong>${shapeTag}${attachTag}${ver} &middot; <span style="opacity:0.7;">${ageLabel}</span>${actions}</div>`;
    }).join('');
    if (groupByNode) {
      // alpha.24 — render per-CN buckets, fetched from the meta-peers
      // aggregator (which merges local + future cross-instance).
      apiFetch('/api/federation/meta-peers').then(meta => {
        const byNode = (meta && meta.by_node) || {};
        const unbound = (meta && meta.unbound) || [];
        const nodeBlocks = Object.keys(byNode).sort().map(nodeName => {
          const bucket = byNode[nodeName];
          const obs = (bucket.observers || []).map(o =>
            `<div style="padding:2px 0 2px 18px;font-size:12px;">↳ <strong>${escHtml(o.peer)}</strong> <span style="opacity:0.6;font-size:11px;">(primary ${escHtml(o.primary)}${o.shape ? '; shape '+escHtml(o.shape) : ''})</span></div>`
          ).join('');
          return `<div style="border-left:2px solid var(--accent2);padding:6px 0 6px 8px;margin:6px 0;">
            <div style="font-weight:600;font-size:12px;">⇄ ${escHtml(nodeName)} <span style="opacity:0.6;font-size:11px;font-weight:400;">${bucket.observer_count} observer${bucket.observer_count===1?'':'s'} · ${bucket.primary_count} primar${bucket.primary_count===1?'y':'ies'}</span></div>
            ${obs}
          </div>`;
        }).join('');
        const unboundBlock = unbound.length > 0 ? `<div style="border-left:2px dashed var(--text2);padding:6px 0 6px 8px;margin:6px 0;">
          <div style="font-weight:600;font-size:12px;color:var(--text2);">${escHtml(t('peer_group_unbound')||'Unbound peers (no ComputeNode)')}</div>
          ${unbound.map(o => `<div style="padding:2px 0 2px 18px;font-size:12px;">↳ <strong>${escHtml(o.peer)}</strong> <span style="opacity:0.6;font-size:11px;">(primary ${escHtml(o.primary)})</span></div>`).join('')}
        </div>` : '';
        list.innerHTML = pills + nodeBlocks + unboundBlock;
      }).catch(() => { list.innerHTML = pills + rows; }); // fallback to flat view on error
    } else {
      list.innerHTML = pills + rows;
    }
  }).catch(err => {
    const msg = (err && err.status === 503) ? 'off' : 'unavailable';
    list.innerHTML = `<span style="opacity:0.7;">peer registry ${msg}</span> &middot; `
      + `<span style="opacity:0.7;">enable with <code>observer.peers.allow_register: true</code></span>`;
  });
}

// alpha.24 #231 — toggle the "Group by ComputeNode" view on the
// Federated Peers card. Persisted in localStorage.
window.togglePeerGroupByNode = function() {
  const cur = localStorage.getItem('cs_peer_group_by_node') === '1';
  localStorage.setItem('cs_peer_group_by_node', cur ? '0' : '1');
  loadObserverPeers();
};

// apiFetch returns the parsed JSON; older callers were tolerant. The
// alpha.23b enrichment of loadObserverPeers expects /api/compute/nodes
// to return {nodes: [...]} which the server already does.


// BL180 Phase 2 cross-host (v5.16.0) — modal that fetches the
// federation-aware envelope view from /api/observer/envelopes/all-peers
// and renders one collapsible block per peer. CallerAttribution rows
// with `<peer>:<envelope-id>` prefixes (cross-host) get a 🔗 badge so
// operators can see at a glance which envelopes are reached across
// peers vs. only locally.
window.showCrossHostView = function() {
  const existing = document.getElementById('crossHostModal');
  if (existing) existing.remove();
  const modal = document.createElement('div');
  modal.id = 'crossHostModal';
  modal.className = 'confirm-modal-overlay';
  modal.innerHTML = `<div class="confirm-modal" style="max-width:900px;width:90vw;max-height:85vh;overflow:auto;padding:0;">
    <div style="display:flex;justify-content:space-between;align-items:center;padding:10px 14px;border-bottom:1px solid var(--border);">
      <strong>Cross-host envelope view</strong>
      <button class="btn-icon" style="font-size:16px;" onclick="document.getElementById('crossHostModal').remove();">&times;</button>
    </div>
    <div id="crossHostBody" style="padding:12px;font-size:12px;">
      <em style="color:var(--text2);">loading /api/observer/envelopes/all-peers …</em>
    </div>
  </div>`;
  document.body.appendChild(modal);
  apiFetch('/api/observer/envelopes/all-peers').then(data => {
    const body = document.getElementById('crossHostBody');
    if (!body) return;
    const byPeer = (data && data.by_peer) || {};
    const peerNames = Object.keys(byPeer);
    if (peerNames.length === 0) {
      body.innerHTML = '<em style="opacity:0.7;">no envelopes anywhere — local observer empty + no peers pushed yet</em>';
      return;
    }
    const sections = peerNames.map(peer => {
      const envs = byPeer[peer] || [];
      const envHtml = envs.map(e => {
        const callers = (e.callers || []).map(c => {
          const isCross = (c.caller || '').includes(':') && (c.caller || '').split(':').length >= 3;
          const tag = isCross
            ? `<span title="cross-host attribution" style="background:rgba(96,165,250,0.25);color:var(--accent);font-size:9px;padding:1px 4px;border-radius:4px;margin-right:3px;">🔗 cross</span>`
            : '';
          return `<div style="font-size:10px;color:var(--text2);padding-left:12px;">${tag}<code>${escHtml(c.caller || '?')}</code> <span style="opacity:0.7;">${escHtml(c.caller_kind || '')} · ${c.conns || 0} conns</span></div>`;
        }).join('');
        const listenSummary = (e.listen_addrs || []).map(la => `${la.ip}:${la.port}`).join(', ');
        const outboundSummary = (e.outbound_edges || []).map(oe => `${oe.target_ip}:${oe.target_port}`).join(', ');
        return `<div style="padding:4px 0;border-top:1px solid var(--border);">
          <div><code style="font-size:11px;">${escHtml(e.id || '?')}</code> <span style="opacity:0.6;">${escHtml(e.kind || '')}</span> <strong>${escHtml(e.label || '')}</strong></div>
          ${listenSummary ? `<div style="font-size:10px;color:var(--text2);">listen: ${escHtml(listenSummary)}</div>` : ''}
          ${outboundSummary ? `<div style="font-size:10px;color:var(--text2);">outbound: ${escHtml(outboundSummary)}</div>` : ''}
          ${callers}
        </div>`;
      }).join('') || '<em style="opacity:0.7;font-size:10px;">no envelopes</em>';
      return `<details open style="margin-bottom:8px;">
        <summary style="cursor:pointer;font-weight:600;">${escHtml(peer)} <span style="opacity:0.6;font-weight:normal;">(${envs.length} envelopes)</span></summary>
        <div style="margin-top:4px;padding-left:6px;">${envHtml}</div>
      </details>`;
    }).join('');
    body.innerHTML = sections;
  }).catch(err => {
    const body = document.getElementById('crossHostBody');
    if (body) body.innerHTML = `<span style="color:var(--error,#ef4444);">load failed: ${escHtml(String((err && err.message) || err))}</span>`;
  });
};

// observerPeerAgo formats a millisecond delta as "Xs / Xm / Xh ago".
function observerPeerAgo(ms) {
  if (ms < 1000) return 'just now';
  if (ms < 60000) return Math.floor(ms / 1000) + 's ago';
  if (ms < 3600000) return Math.floor(ms / 60000) + 'm ago';
  return Math.floor(ms / 3600000) + 'h ago';
}

// Drill-down — fetches /api/observer/peers/{name}/stats and shows
// the host + envelope summary in a transient toast/dialog.
// BL173 task 6 — full peer snapshot in a modal with the envelope tree
// + per-envelope drill-down to the process list (via /api/observer/envelope).
// Replaces the v4.5.1 toast (which showed only the top 6 envelopes).
function showObserverPeerSnapshot(name) {
  const existing = document.getElementById('observerSnapshotModal');
  if (existing) existing.remove();
  const modal = document.createElement('div');
  modal.id = 'observerSnapshotModal';
  modal.className = 'observer-snapshot-modal';
  modal.innerHTML = `
    <div class="observer-snapshot-card">
      <div class="observer-snapshot-header">
        <div>
          <h3 style="margin:0;">Peer snapshot</h3>
          <div style="opacity:0.7;font-size:12px;" id="observerSnapPeerLine">${escHtml(name)} — loading…</div>
        </div>
        <button class="btn-icon" onclick="closeObserverSnapshot()" title="Close" style="font-size:22px;">&times;</button>
      </div>
      <div id="observerSnapBody" class="observer-snapshot-body">
        <div style="color:var(--text2);padding:18px;">Fetching /api/observer/peers/${escHtml(name)}/stats …</div>
      </div>
    </div>`;
  document.body.appendChild(modal);
  document.body.style.overflow = 'hidden';

  apiFetch('/api/observer/peers/' + encodeURIComponent(name) + '/stats').then(snap => {
    renderObserverSnapshot(name, snap);
  }).catch(err => {
    const body = document.getElementById('observerSnapBody');
    if (body) body.innerHTML = `<div style="color:var(--error);padding:18px;">Snapshot unavailable: ${escHtml(String(err && err.message || err))}</div>`;
  });
}

function closeObserverSnapshot() {
  const m = document.getElementById('observerSnapshotModal');
  if (m) m.remove();
  document.body.style.overflow = '';
}

function renderObserverSnapshot(name, snap) {
  const head = document.getElementById('observerSnapPeerLine');
  const body = document.getElementById('observerSnapBody');
  if (!body) return;
  const host = (snap && snap.host) || {};
  const env = (snap && snap.envelopes) || [];
  if (head) {
    head.innerHTML = `${escHtml(name)} · ${escHtml(host.name || '?')} · ${escHtml(host.os || '?')} ${escHtml(host.arch || '')} · uptime ${host.uptime_seconds||0}s`;
  }
  // Sort by cpu desc.
  env.sort((a, b) => (b.cpu_pct || 0) - (a.cpu_pct || 0));
  const rows = env.map((e, idx) => {
    const safeID = JSON.stringify(e.id || '');
    const cpu = (e.cpu_pct || 0).toFixed(1);
    const rss = Math.round((e.rss_bytes || 0) / 1e6);
    const fds = e.open_fds || 0;
    const procs = e.process_count || 0;
    return `<div class="observer-env-row" id="observerEnvRow-${idx}">
      <div class="observer-env-summary" onclick='toggleObserverEnvelope(${idx}, ${safeID}, "${escHtml(name)}")' title="Click to drill into process tree">
        <span class="observer-env-toggle" id="observerEnvToggle-${idx}">&#9656;</span>
        <span class="observer-env-kind">${escHtml(e.kind || '?')}</span>
        <span class="observer-env-id">${escHtml(e.id || '?')}</span>
        <span class="observer-env-stats">cpu ${cpu}%</span>
        <span class="observer-env-stats">rss ${rss} MB</span>
        <span class="observer-env-stats">${procs} procs · ${fds} fds</span>
      </div>
      <div class="observer-env-detail" id="observerEnvDetail-${idx}" style="display:none;">
        <div style="color:var(--text2);padding:8px 24px;">Loading process tree…</div>
      </div>
    </div>`;
  }).join('');
  const headerLine = `<div style="padding:6px 18px;color:var(--text2);font-size:12px;border-bottom:1px solid var(--border);">${env.length} envelope${env.length===1?'':'s'} · click any row to expand its process tree</div>`;
  body.innerHTML = headerLine + (env.length ? rows : '<div style="padding:18px;color:var(--text2);">No envelopes in this snapshot.</div>');
}

// toggleObserverEnvelope — expand/collapse the process tree for one
// envelope. Lazy-loads via /api/observer/envelope?id=… when first opened.
function toggleObserverEnvelope(idx, envID, peerName) {
  const detail = document.getElementById('observerEnvDetail-' + idx);
  const toggle = document.getElementById('observerEnvToggle-' + idx);
  if (!detail) return;
  if (detail.style.display !== 'none') {
    detail.style.display = 'none';
    if (toggle) toggle.innerHTML = '&#9656;';
    return;
  }
  detail.style.display = 'block';
  if (toggle) toggle.innerHTML = '&#9662;';
  // Already loaded?
  if (detail.dataset.loaded === '1') return;
  apiFetch('/api/observer/envelope?id=' + encodeURIComponent(envID)).then(env => {
    detail.dataset.loaded = '1';
    const procs = (env && env.processes) || [];
    if (!procs.length) {
      detail.innerHTML = '<div style="padding:10px 24px;color:var(--text2);">No process detail for this envelope.</div>';
      return;
    }
    procs.sort((a, b) => (b.cpu_pct || 0) - (a.cpu_pct || 0));
    const top = procs.slice(0, 50).map(p => {
      const cpu = (p.cpu_pct || 0).toFixed(1);
      const rss = Math.round((p.rss_bytes || 0) / 1e6);
      const cmd = p.cmdline || p.comm || '?';
      return `<div class="observer-proc-row">
        <span class="observer-proc-pid">${p.pid || '?'}</span>
        <span class="observer-proc-cpu">${cpu}%</span>
        <span class="observer-proc-rss">${rss} MB</span>
        <span class="observer-proc-cmd" title="${escHtml(cmd)}">${escHtml(cmd.length > 80 ? cmd.slice(0,80)+'…' : cmd)}</span>
      </div>`;
    }).join('');
    const more = procs.length > 50 ? `<div style="padding:6px 24px;color:var(--text2);font-size:11px;">+${procs.length-50} more</div>` : '';
    detail.innerHTML = top + more;
  }).catch(err => {
    detail.innerHTML = `<div style="padding:10px 24px;color:var(--error);">Failed to load envelope: ${escHtml(String(err && err.message || err))}</div>`;
  });
}

// Remove — DELETE /api/observer/peers/{name}. Peer auto-re-registers
// on the next push, so this effectively rotates its token.
function removeObserverPeer(name) {
  if (!confirm(`Remove peer "${name}"?\nIt will auto-re-register on next push (token rotates).`)) return;
  const token = localStorage.getItem('cs_token') || '';
  const headers = {};
  if (token) headers['Authorization'] = 'Bearer ' + token;
  fetch('/api/observer/peers/' + encodeURIComponent(name), { method: 'DELETE', headers })
    .then(r => {
      if (r.ok) {
        showToast(`Removed peer ${name}`, 'info');
        loadObserverPeers();
      } else {
        showToast(`Remove failed: ${r.status}`, 'error');
      }
    })
    .catch(() => showToast('Remove failed', 'error'));
}

// BL173 (S12) — cluster nodes from /api/observer/stats. Renders only
// when the payload's cluster.nodes is non-empty (single-node setups
// see no card). Aggregates across all peers + the local snapshot.
function loadObserverClusterNodes() {
  const block = document.getElementById('observerClusterBlock');
  const list = document.getElementById('observerClusterList');
  if (!block || !list) return;
  apiFetch('/api/observer/stats').then(snap => {
    const nodes = (snap && snap.cluster && snap.cluster.nodes) || [];
    if (!nodes.length) {
      block.style.display = 'none';
      return;
    }
    block.style.display = '';
    list.innerHTML = nodes.map(n => {
      const cpuPct = Math.round(n.cpu_pct || 0);
      const memPct = Math.round(n.mem_pct || 0);
      const ready = n.ready !== false;
      const dot = `<span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:${ready?'var(--success,#10b981)':'var(--error,#ef4444)'};margin-right:6px;"></span>`;
      const pressure = (n.pressure && n.pressure.length)
        ? ` <span style="opacity:0.7;color:var(--warning,#f59e0b);font-size:11px;">[${(n.pressure||[]).join(',')}]</span>` : '';
      const pods = (typeof n.pod_count === 'number') ? ` &middot; <span style="opacity:0.7;">${n.pod_count} pods</span>` : '';
      const bar = (label, p, color) => `
        <span style="display:inline-flex;align-items:center;gap:4px;margin-left:8px;">
          <span style="font-size:11px;opacity:0.7;">${label}</span>
          <span style="display:inline-block;width:60px;height:5px;background:var(--bg);border-radius:3px;overflow:hidden;">
            <span style="display:block;height:100%;width:${p}%;background:${color};"></span>
          </span>
          <span style="font-size:11px;opacity:0.7;">${p}%</span>
        </span>`;
      return `<div style="padding:4px 0;display:flex;align-items:center;flex-wrap:wrap;">${dot}<strong>${escHtml(n.name)}</strong>${pressure}${pods}${bar('cpu', cpuPct, 'var(--accent)')}${bar('mem', memPct, 'var(--accent2)')}</div>`;
    }).join('');
  }).catch(() => {
    block.style.display = 'none';
  });
}

function renderStatsData(el, data) {
    if (!data || !data.timestamp) { el.innerHTML = `<div style="color:var(--text2);font-size:12px;padding:8px;">${t('stats_not_available')||'Stats not available.'}</div>`; return; }
    // Preserve scroll position to prevent visible jump on real-time updates
    const scrollParent = el.closest('.settings-section') || el.parentElement;
    const savedScroll = scrollParent ? scrollParent.scrollTop : 0;
    const pageScroll = window.scrollY;
    const fmt = (bytes) => {
      if (bytes > 1e9) return (bytes/1e9).toFixed(1) + ' GB';
      if (bytes > 1e6) return (bytes/1e6).toFixed(1) + ' MB';
      if (bytes > 1e3) return (bytes/1e3).toFixed(1) + ' KB';
      return bytes + ' B';
    };
    const pct = (used, total) => total > 0 ? Math.round(100*used/total) : 0;
    const bar = (label, val, max, color, extra) => {
      const p = max > 0 ? Math.min(100, Math.round(100*val/max)) : 0;
      return `<div class="stat-card">
        <div style="display:flex;justify-content:space-between;"><span class="stat-label">${label}</span><span class="stat-value">${extra || p+'%'}</span></div>
        <div style="height:6px;background:var(--bg);border-radius:3px;margin-top:4px;overflow:hidden;">
          <div style="height:100%;width:${p}%;background:${color || 'var(--accent)'};border-radius:3px;transition:width 0.3s;"></div>
        </div>
      </div>`;
    };
    let html = '<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:8px;padding:8px;">';
    // CPU (load as % of cores)
    const cpuPct = Math.min(100, Math.round(100 * data.cpu_load_avg_1 / data.cpu_cores));
    html += bar('CPU Load', data.cpu_load_avg_1, data.cpu_cores, cpuPct > 80 ? 'var(--error)' : cpuPct > 50 ? 'var(--warning)' : 'var(--success)', data.cpu_load_avg_1.toFixed(2) + ' / ' + data.cpu_cores + ' cores');
    // Memory
    html += bar('Memory', data.mem_used, data.mem_total, pct(data.mem_used,data.mem_total) > 85 ? 'var(--error)' : 'var(--accent)', fmt(data.mem_used) + ' / ' + fmt(data.mem_total));
    // Disk
    html += bar('Disk', data.disk_used, data.disk_total, pct(data.disk_used,data.disk_total) > 90 ? 'var(--error)' : 'var(--accent2)', fmt(data.disk_used) + ' / ' + fmt(data.disk_total));
    // Swap
    if (data.swap_total > 0) html += bar('Swap', data.swap_used, data.swap_total, 'var(--warning)', fmt(data.swap_used) + ' / ' + fmt(data.swap_total));
    // GPU
    if (data.gpu_name) {
      html += bar('GPU ' + escHtml(data.gpu_name), data.gpu_util_pct, 100, data.gpu_util_pct > 80 ? 'var(--error)' : 'var(--success)', data.gpu_util_pct + '% ' + data.gpu_temp + '°C');
      if (data.gpu_mem_total_mb > 0) html += bar('GPU VRAM', data.gpu_mem_used_mb, data.gpu_mem_total_mb, 'var(--accent2)', data.gpu_mem_used_mb + ' / ' + data.gpu_mem_total_mb + ' MB');
    }
    // Network — line-per-stat layout
    const netLabel = data.ebpf_active ? 'Network (datawatch)' : 'Network (system)';
    html += `<div class="stat-card"><div class="stat-label">${netLabel}</div>
      <div style="font-size:10px;font-family:monospace;color:var(--text);line-height:1.6;">
        <div style="display:flex;justify-content:space-between;"><span style="color:var(--text2);">&#8595; Download</span><span>${fmt(data.net_rx_bytes || 0)}</span></div>
        <div style="display:flex;justify-content:space-between;"><span style="color:var(--text2);">&#8593; Upload</span><span>${fmt(data.net_tx_bytes || 0)}</span></div>
      </div></div>`;
    // Daemon — line-per-stat layout
    const up = data.uptime_seconds || 0;
    const upStr = up > 3600 ? Math.floor(up/3600) + 'h ' + Math.floor((up%3600)/60) + 'm' : Math.floor(up/60) + 'm ' + (up%60) + 's';
    html += `<div class="stat-card"><div class="stat-label">${t('stats_daemon')||'Daemon'}</div>
      <div style="font-size:10px;font-family:monospace;color:var(--text);line-height:1.6;">
        <div style="display:flex;justify-content:space-between;"><span style="color:var(--text2);">Memory</span><span>${fmt(data.daemon_rss_bytes)} RSS</span></div>
        <div style="display:flex;justify-content:space-between;"><span style="color:var(--text2);">Goroutines</span><span>${data.goroutines}</span></div>
        <div style="display:flex;justify-content:space-between;"><span style="color:var(--text2);">File descriptors</span><span>${data.open_fds || 0}</span></div>
        <div style="display:flex;justify-content:space-between;"><span style="color:var(--text2);">Uptime</span><span>${upStr}</span></div>
      </div></div>`;
    // Infrastructure
    const host = data.bound_interfaces?.[0] || '0.0.0.0';
    const httpPort = data.web_port || 8080;
    const tlsPort = data.tls_port || 0;
    const hasTLS = data.tls_enabled && tlsPort > 0;
    html += `<div class="stat-card"><div class="stat-label">${t('stats_infrastructure')||'Infrastructure'}</div>
      <div style="font-size:10px;font-family:monospace;color:var(--text);line-height:1.6;">
        <div style="display:flex;justify-content:space-between;"><span style="color:var(--text2);">HTTP</span><span>http://${host}:${httpPort}${hasTLS ? ' <span style="color:var(--text2);">(→ HTTPS)</span>' : ''}</span></div>
        ${hasTLS ? `<div style="display:flex;justify-content:space-between;"><span style="color:var(--text2);">HTTPS</span><span style="color:var(--success);">https://${host}:${tlsPort} <span style="color:var(--success);">🔒</span></span></div>` : ''}
        ${!hasTLS && data.tls_enabled ? `<div style="display:flex;justify-content:space-between;"><span style="color:var(--text2);">TLS</span><span style="color:var(--success);">https://${host}:${httpPort} 🔒</span></div>` : ''}
        ${data.mcp_sse_port ? `<div style="display:flex;justify-content:space-between;"><span style="color:var(--text2);">MCP SSE</span><span>${data.mcp_sse_host || '0.0.0.0'}:${data.mcp_sse_port}</span></div>` : ''}
        <div style="display:flex;justify-content:space-between;"><span style="color:var(--text2);">Tmux</span><span>${data.tmux_sessions || 0} sessions${data.orphaned_tmux?.length ? ' <span style="color:var(--warning);">(' + data.orphaned_tmux.length + ' orphan)</span>' : ''}</span></div>
      </div></div>`;
    // RTK Token Savings
    if (data.rtk_installed) {
      const savPct = data.rtk_avg_savings_pct ? data.rtk_avg_savings_pct.toFixed(1) + '%' : '—';
      const savTok = data.rtk_total_saved ? data.rtk_total_saved.toLocaleString() : '0';
      const savCmds = data.rtk_total_commands || 0;
      // RTK install/upgrade one-liner per upstream rtk-ai/rtk install.sh.
      const rtkInstallCmd = 'curl -fsSL https://raw.githubusercontent.com/rtk-ai/rtk/refs/heads/master/install.sh | sh';
      // BL223 — store cmd on DOM via data-cmd; avoid JSON.stringify inside
      // onclick="..." attributes (double quotes break the HTML attribute).
      const updateBadge = data.rtk_update_available
        ? ` <span class="rtk-update-badge" style="color:var(--error);font-weight:600;cursor:pointer;" title="Click to copy upgrade command" data-cmd="${escHtml(rtkInstallCmd)}">→ ${escHtml(data.rtk_latest_version)}</span>`
        : ' <span style="color:var(--success);">✓</span>';
      const upgradeRow = data.rtk_update_available
        ? `<div style="margin-top:2px;padding:4px 6px;background:var(--bg3);border-radius:4px;font-size:9px;color:var(--text2);">Upgrade: <code class="rtk-cmd-copy" style="cursor:pointer;color:var(--accent);user-select:all;word-break:break-all;" title="Click to copy" data-cmd="${escHtml(rtkInstallCmd)}">${escHtml(rtkInstallCmd)}</code></div>`
        : '';
      html += `<div class="stat-card"><div class="stat-label">${t('stats_rtk_savings')||'RTK Token Savings'}</div>
        <div style="font-size:10px;font-family:monospace;color:var(--text);line-height:1.6;">
          <div style="display:flex;justify-content:space-between;"><span style="color:var(--text2);">Version</span><span>${escHtml(data.rtk_version || '?')}${updateBadge}</span></div>
          ${upgradeRow}
          <div style="display:flex;justify-content:space-between;"><span style="color:var(--text2);">Hooks</span><span style="color:${data.rtk_hooks_active ? 'var(--success)' : 'var(--warning)'};">${data.rtk_hooks_active ? 'active' : 'inactive'}</span></div>
          <div style="display:flex;justify-content:space-between;"><span style="color:var(--text2);">Tokens saved</span><span>${savTok}</span></div>
          <div style="display:flex;justify-content:space-between;"><span style="color:var(--text2);">Avg savings</span><span>${savPct}</span></div>
          <div style="display:flex;justify-content:space-between;"><span style="color:var(--text2);">Commands</span><span>${savCmds}</span></div>
        </div></div>`;
    }
    {
      const memEnabled = data.memory_enabled;
      const memStatus = memEnabled ? '<span style="color:var(--success);">enabled</span>' : '<span style="color:var(--text2);">disabled</span>';
      html += `<div class="stat-card"><div class="stat-label">${t('stats_episodic_memory')||'Episodic Memory'}</div>
        <div style="font-size:10px;font-family:monospace;color:var(--text);line-height:1.6;">
          <div style="display:flex;justify-content:space-between;"><span style="color:var(--text2);">Status</span><span>${memStatus}</span></div>`;
      if (memEnabled) {
        const encStatus = data.memory_encrypted ? `<span style="color:var(--success);">encrypted</span> (${escHtml(data.memory_key_fingerprint || '?')})` : '<span style="color:var(--text2);">plaintext</span>';
        html += `
          <div style="display:flex;justify-content:space-between;"><span style="color:var(--text2);">Backend</span><span>${escHtml(data.memory_backend || 'sqlite')}</span></div>
          <div style="display:flex;justify-content:space-between;"><span style="color:var(--text2);">Embedder</span><span>${escHtml(data.memory_embedder || '—')}</span></div>
          <div style="display:flex;justify-content:space-between;"><span style="color:var(--text2);">Encryption</span><span>${encStatus}</span></div>
          <div style="display:flex;justify-content:space-between;"><span style="color:var(--text2);">Total</span><span>${data.memory_total_count || 0}</span></div>
          <div style="display:flex;justify-content:space-between;"><span style="color:var(--text2);">Manual</span><span>${data.memory_manual_count || 0}</span></div>
          <div style="display:flex;justify-content:space-between;"><span style="color:var(--text2);">Sessions</span><span>${data.memory_session_count || 0}</span></div>
          <div style="display:flex;justify-content:space-between;"><span style="color:var(--text2);">Learnings</span><span>${data.memory_learning_count || 0}</span></div>
          <div style="display:flex;justify-content:space-between;"><span style="color:var(--text2);">DB Size</span><span>${fmt(data.memory_db_size_bytes || 0)}</span></div>`;
      }
      html += `</div></div>`;
    }
    if (data.ollama_stats && data.ollama_stats.available) {
      const os = data.ollama_stats;
      const running = os.running_models || [];
      const totalVRAM = running.reduce((a, m) => a + (m.size_vram || 0), 0);
      html += `<div class="stat-card"><div class="stat-label">${t('stats_ollama_server')||'Ollama Server'}</div>
        <div style="font-size:10px;font-family:monospace;color:var(--text);line-height:1.6;">
          <div style="display:flex;justify-content:space-between;"><span style="color:var(--text2);">Host</span><span>${escHtml(os.host || '—')}</span></div>
          <div style="display:flex;justify-content:space-between;"><span style="color:var(--text2);">Status</span><span style="color:var(--success);">online</span></div>
          <div style="display:flex;justify-content:space-between;"><span style="color:var(--text2);">Models</span><span>${os.model_count || 0}</span></div>
          <div style="display:flex;justify-content:space-between;"><span style="color:var(--text2);">Disk Used</span><span>${fmt(os.total_size_bytes || 0)}</span></div>
          <div style="display:flex;justify-content:space-between;"><span style="color:var(--text2);">Running</span><span>${running.length}</span></div>
          <div style="display:flex;justify-content:space-between;"><span style="color:var(--text2);">VRAM Used</span><span>${fmt(totalVRAM)}</span></div>`;
      for (const m of running) {
        html += `<div style="display:flex;justify-content:space-between;padding-left:8px;"><span style="color:var(--accent2);">${escHtml(m.name)}</span><span>${fmt(m.size_vram || 0)}</span></div>`;
      }
      html += `</div></div>`;
    } else if (data.ollama_stats) {
      html += `<div class="stat-card"><div class="stat-label">${t('stats_ollama_server')||'Ollama Server'}</div>
        <div style="font-size:10px;color:var(--error);">${escHtml(data.ollama_stats.error || 'offline')}</div></div>`;
    }
    html += '</div>';

    // ── Session Statistics Card ──
    html += `<div style="font-size:11px;color:var(--text2);font-weight:600;padding:8px 8px 4px;border-top:1px solid var(--border);">${t('stats_session_stats')||'Session Statistics'}</div>`;
    // Mini donut: active sessions out of max concurrent
    const active = data.active_sessions || 0;
    const maxSess = state._maxSessions || 10; // loaded from config
    const activePct = Math.min(100, Math.round(100 * active / maxSess));
    html += `<div style="display:flex;align-items:center;gap:12px;padding:4px 8px;">
      <div style="width:48px;height:48px;border-radius:50%;background:conic-gradient(var(--success) 0% ${activePct}%, var(--border) ${activePct}% 100%);display:flex;align-items:center;justify-content:center;">
        <div style="width:32px;height:32px;border-radius:50%;background:var(--bg2);display:flex;align-items:center;justify-content:center;font-size:11px;font-weight:700;color:var(--text);">${active}</div>
      </div>
      <div style="font-size:11px;color:var(--text2);">
        <div><span style="color:var(--success);font-weight:600;">${active}</span> of ${maxSess} max</div>
      </div>
    </div>`;
    // (Orphaned tmux affordance moved to Settings → About per operator
    //  2026-04-26 — see updateAboutOrphanedTmux below. Monitor stays
    //  metric-only.)
    // eBPF status notice
    if (data.ebpf_enabled && !data.ebpf_active) {
      html += `<div style="background:rgba(245,158,11,0.1);border:1px solid rgba(245,158,11,0.3);border-radius:8px;padding:8px 12px;margin:8px;font-size:11px;">
        <strong style="color:var(--warning);">eBPF Degraded</strong>
        <div style="color:var(--text2);margin-top:2px;">${escHtml(data.ebpf_message || 'eBPF enabled but not active')}</div>
      </div>`;
    } else if (data.ebpf_enabled && data.ebpf_active) {
      html += `<div style="font-size:10px;color:var(--success);padding:4px 12px;">● eBPF active — per-session network tracking</div>`;
    }

    // Per-session stats with expandable rows
    const upDaemon = data.uptime_seconds > 3600 ? Math.floor(data.uptime_seconds/3600)+'h'+Math.floor((data.uptime_seconds%3600)/60)+'m' : Math.floor(data.uptime_seconds/60)+'m';
    const allSessions = [
      { session_id: 'daemon', name: 'datawatch', backend: 'daemon', state: 'running',
        rss_bytes: data.daemon_rss_bytes, uptime: upDaemon, pane_pid: 0 },
      ...(data.session_stats || []).sort((a,b) => (a.name||a.session_id).localeCompare(b.name||b.session_id))
    ];
    if (allSessions.length > 0) {
      html += '<div style="padding:8px;border-top:1px solid var(--border);">';
      html += `<div style="font-size:11px;color:var(--text2);font-weight:600;margin-bottom:6px;">${t('stats_sessions_section')||'Sessions'}</div>`;
      allSessions.forEach((s) => {
        const sid = s.session_id;
        const isDaemon = sid === 'daemon';
        const isOpen = _expandedSessions.has(sid);
        const memStr = s.rss_bytes > 1e6 ? (s.rss_bytes/1e6).toFixed(0) + ' MB' : Math.round(s.rss_bytes/1024) + ' KB';
        html += `<div style="border-bottom:1px solid var(--border);padding:4px 0;">
          <div style="display:flex;align-items:center;gap:6px;cursor:pointer;" onclick="_expandedSessions.has('${sid}')?_expandedSessions.delete('${sid}'):_expandedSessions.add('${sid}');loadStatsPanel()">
            <span style="font-size:8px;color:var(--text2);width:10px;">${isOpen ? '▼' : '▶'}</span>
            <span style="font-size:11px;font-weight:${isDaemon?'700':'500'};flex:1;">${escHtml(s.name || sid)}${!isDaemon ? ' <span style="color:var(--text2);font-weight:400;">(#' + escHtml(sid) + ')</span>' : ''}</span>
            <span class="state-badge-${s.state}" style="font-size:9px;padding:1px 5px;border-radius:4px;">${s.state}</span>
            <span style="font-size:10px;font-family:monospace;color:var(--text2);">${memStr}</span>
            <span style="font-size:10px;color:var(--text2);">${escHtml(s.uptime || '')}</span>
          </div>
          ${isOpen ? `<div style="padding:4px 0 4px 16px;font-size:10px;color:var(--text2);">
            <div>Backend: ${escHtml(s.backend)}${s.pane_pid ? ' · PID: ' + s.pane_pid : ''}</div>
            <div>Memory: ${memStr}${s.cpu_percent ? ' · CPU: ' + s.cpu_percent + '%' : ''}</div>
            ${(s.net_tx_bytes || s.net_rx_bytes) ?
              `<div>Network: ↓ ${fmt(s.net_rx_bytes||0)} ↑ ${fmt(s.net_tx_bytes||0)}</div>` :
              data.ebpf_enabled ? '<div>Network: eBPF tracking (no data yet)</div>' : '<div>Network: enable eBPF for per-session tracking</div>'}
          </div>` : ''}
        </div>`;
      });
      // Session count with link
      html += `<div style="font-size:10px;color:var(--text2);padding:4px 8px;text-align:center;">
        <a href="#" onclick="event.preventDefault();state.showHistory=true;navigate('sessions');setTimeout(renderSessionsView,100)" style="color:var(--accent2);">${data.total_sessions || 0} sessions in store</a>
      </div>`;
      html += '</div>';
    }
    // ── Communication Channels (expandable, split Chat / LLM) ──
    if (data.comm_stats && data.comm_stats.length > 0) {
      const fmtDur = (s) => s > 3600 ? (s/3600).toFixed(1) + 'h' : s > 60 ? Math.round(s/60) + 'm' : Math.round(s) + 's';
      const fmtAgo = (ts) => { if (!ts) return '—'; const d = Math.floor(Date.now()/1000 - ts); return d < 60 ? d + 's ago' : d < 3600 ? Math.floor(d/60) + 'm ago' : Math.floor(d/3600) + 'h ago'; };
      const chatChannels = data.comm_stats.filter(c => c.enabled && (c.type === 'messaging' || c.type === 'infra')).sort((a,b) => a.name.localeCompare(b.name));
      const llmChannels = data.comm_stats.filter(c => c.enabled && c.type === 'llm').sort((a,b) => a.name.localeCompare(b.name));
      const disabledChannels = data.comm_stats.filter(c => !c.enabled).sort((a,b) => a.name.localeCompare(b.name));

      const renderChanRow = (ch) => {
        const cid = ch.name;
        const isOpen = _expandedChannels.has(cid);
        return `<div style="border-bottom:1px solid var(--border);padding:4px 0;">
          <div style="display:flex;align-items:center;gap:6px;cursor:pointer;" onclick="_expandedChannels.has('${cid}')?_expandedChannels.delete('${cid}'):_expandedChannels.add('${cid}');loadStatsPanel()">
            <span style="font-size:8px;color:var(--text2);width:10px;">${isOpen ? '▼' : '▶'}</span>
            <span style="font-size:11px;flex:1;">${escHtml(ch.name)}</span>
            ${ch.type === 'llm' && ch.active_sessions ? `<span style="font-size:9px;font-weight:700;color:var(--bg2);background:var(--success);padding:1px 6px;border-radius:8px;min-width:16px;text-align:center;">${ch.active_sessions}</span>` : ''}
            ${ch.type === 'llm' ? `<span style="font-size:10px;font-family:monospace;color:var(--text2);">${ch.total_sessions || 0}</span>` : ''}
            ${ch.type === 'infra' && ch.connections ? `<span style="font-size:10px;font-family:monospace;color:var(--text2);">${ch.connections} conn</span>` : ''}
            ${ch.type === 'messaging' && (ch.msg_recv || ch.msg_sent) ? `<span style="font-size:10px;font-family:monospace;color:var(--text2);">${ch.msg_recv||0} in / ${ch.msg_sent||0} out</span>` : ''}
          </div>
          ${isOpen ? `<div style="padding:4px 0 4px 16px;font-size:10px;font-family:monospace;color:var(--text2);line-height:1.6;">` + (
            ch.type === 'llm' ? `
              <div style="display:flex;justify-content:space-between;"><span>Active sessions</span><span style="color:var(--text);">${ch.active_sessions || 0}</span></div>
              <div style="display:flex;justify-content:space-between;"><span>Total sessions</span><span style="color:var(--text);">${ch.total_sessions || 0}</span></div>
              <div style="display:flex;justify-content:space-between;"><span>Avg duration</span><span style="color:var(--text);">${ch.avg_duration_sec ? fmtDur(ch.avg_duration_sec) : '—'}</span></div>
              <div style="display:flex;justify-content:space-between;"><span>Avg prompts/session</span><span style="color:var(--text);">${ch.avg_prompts ? ch.avg_prompts.toFixed(1) : '—'}</span></div>
            ` : `
              <div style="display:flex;justify-content:space-between;"><span>Endpoint</span><span style="color:var(--text);">${escHtml(ch.endpoint || '—')}</span></div>
              ${ch.connections ? `<div style="display:flex;justify-content:space-between;"><span>Connections</span><span style="color:var(--text);">${ch.connections}</span></div>` : ''}
              <div style="display:flex;justify-content:space-between;"><span>Requests in</span><span style="color:var(--text);">${ch.msg_recv || 0}</span></div>
              <div style="display:flex;justify-content:space-between;"><span>Responses out</span><span style="color:var(--text);">${ch.msg_sent || 0}</span></div>
              <div style="display:flex;justify-content:space-between;"><span>Data in</span><span style="color:var(--text);">${fmt(ch.bytes_in || 0)}</span></div>
              <div style="display:flex;justify-content:space-between;"><span>Data out</span><span style="color:var(--text);">${fmt(ch.bytes_out || 0)}</span></div>
              ${ch.errors ? `<div style="display:flex;justify-content:space-between;"><span>Errors</span><span style="color:var(--error);">${ch.errors}</span></div>` : ''}
              ${ch.last_active ? `<div style="display:flex;justify-content:space-between;"><span>Last activity</span><span style="color:var(--text);">${fmtAgo(ch.last_active)}</span></div>` : ''}
            `
          ) + '</div>' : ''}
        </div>`;
      };

      // Chat channels section
      if (chatChannels.length > 0) {
        html += `<div style="font-size:11px;color:var(--text2);font-weight:600;padding:8px 8px 4px;border-top:1px solid var(--border);">${t('stats_chat_channels')||'Chat Channels'}</div>`;
        html += '<div style="padding:0 8px;">';
        chatChannels.forEach(ch => { html += renderChanRow(ch); });
        html += '</div>';
      }
      // LLM backends section
      if (llmChannels.length > 0) {
        html += `<div style="font-size:11px;color:var(--text2);font-weight:600;padding:8px 8px 4px;border-top:1px solid var(--border);">${t('stats_llm_backends')||'LLM Backends'}</div>`;
        html += '<div style="padding:0 8px;">';
        llmChannels.forEach(ch => { html += renderChanRow(ch); });
        html += '</div>';
      }
      // Disabled channels — compact summary
      if (disabledChannels.length > 0) {
        html += '<div style="padding:6px 8px 2px;font-size:10px;color:var(--text2);border-top:1px solid var(--border);">';
        html += '<span style="font-weight:600;">Inactive: </span>';
        html += disabledChannels.map(ch => escHtml(ch.name)).join(', ');
        html += '</div>';
      }
    }

    html += '<div style="text-align:center;padding:4px;font-size:10px;color:var(--text2);">● Live — updates every 5s</div>';
    el.innerHTML = html;
    // Restore scroll position after DOM update
    if (scrollParent) scrollParent.scrollTop = savedScroll;
    window.scrollTo(0, pageScroll);
    // BL223 — wire RTK copy buttons after innerHTML (avoids inline onclick+JSON.stringify)
    el.querySelectorAll('.rtk-update-badge, .rtk-cmd-copy').forEach(node => {
      node.addEventListener('click', function() {
        const cmd = this.dataset.cmd;
        if (!cmd) return;
        navigator.clipboard.writeText(cmd).then(() => {
          const orig = this.textContent;
          this.textContent = 'copied!';
          setTimeout(() => { this.textContent = orig; }, 1500);
        });
      });
    });
}

function loadDetectionFilters() {
  const el = document.getElementById('detectionFiltersList');
  if (!el) return;
  apiFetch('/api/config').then(cfg => {
    const d = cfg?.detection || {};
    const sections = [
      { key: 'prompt_patterns', label: 'Prompt Patterns', desc: 'Substrings that indicate waiting for input' },
      { key: 'completion_patterns', label: 'Completion Patterns', desc: 'Session completed markers' },
      { key: 'rate_limit_patterns', label: 'Rate Limit Patterns', desc: 'Rate limit hit markers' },
      { key: 'input_needed_patterns', label: 'Input Needed', desc: 'Explicit input-needed protocol markers' },
    ];
    // Built-in defaults for display when config is empty
    const builtinDefaults = {
      prompt_patterns: ['? ', '> ', '$ ', '# ', '[y/N]', '[Y/n]', 'Do you want to', 'Allow ', 'Trust ', '(y/n)', 'Would you like', 'Proceed?', 'Enter to confirm', '❯', 'Ask anything', '>>> '],
      completion_patterns: ['DATAWATCH_COMPLETE:'],
      rate_limit_patterns: ['DATAWATCH_RATE_LIMITED:', "You've hit your limit", 'rate limit exceeded', 'quota exceeded'],
      input_needed_patterns: ['DATAWATCH_NEEDS_INPUT:'],
    };
    // Debounce/cooldown numeric settings
    const debounce = d.prompt_debounce || 3;
    const cooldown = d.notify_cooldown || 15;
    let html = '<div style="font-size:10px;color:var(--text2);padding:4px 12px;">Global patterns applied to all backends without structured channels.</div>';
    html += `<div style="padding:6px 12px;border-bottom:1px solid var(--border);">
      <div style="font-size:11px;color:var(--text2);font-weight:600;margin-bottom:4px;">Timing</div>
      <div style="display:flex;gap:12px;align-items:center;flex-wrap:wrap;">
        <label style="font-size:10px;color:var(--text2);display:flex;align-items:center;gap:4px;">
          Prompt debounce (sec):
          <input type="number" min="0" max="60" value="${debounce}" id="det_prompt_debounce" class="form-input" style="width:50px;font-size:10px;padding:2px 4px;" onchange="saveDetTiming()" />
        </label>
        <label style="font-size:10px;color:var(--text2);display:flex;align-items:center;gap:4px;">
          Notify cooldown (sec):
          <input type="number" min="0" max="300" value="${cooldown}" id="det_notify_cooldown" class="form-input" style="width:50px;font-size:10px;padding:2px 4px;" onchange="saveDetTiming()" />
        </label>
      </div>
      <div style="font-size:9px;color:var(--text2);margin-top:2px;">Debounce: wait N sec after prompt detected before alerting. Cooldown: min sec between repeat alerts.</div>
    </div>`;
    for (const s of sections) {
      const patterns = d[s.key] || [];
      const defaults = builtinDefaults[s.key] || [];
      const isUsingDefaults = patterns.length === 0;
      const displayPatterns = isUsingDefaults ? defaults : patterns;
      const id = 'det_' + s.key;
      const items = displayPatterns.map((p, i) =>
        `<div class="det-item" style="display:flex;align-items:center;gap:4px;padding:2px 0;">
          <span style="flex:1;font-size:10px;font-family:monospace;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;${isUsingDefaults ? 'opacity:0.5;' : ''}" title="${escHtml(p)}">${escHtml(p)}</span>
          ${!isUsingDefaults ? `<button class="btn-icon" style="font-size:9px;color:var(--error);padding:1px 3px;" onclick="removeDetPattern('${s.key}',${i})">&#10005;</button>` : ''}
        </div>`
      ).join('');
      html += `<div style="padding:6px 12px;border-bottom:1px solid var(--border);">
        <div style="display:flex;justify-content:space-between;align-items:center;">
          <div style="font-size:11px;color:var(--text2);font-weight:600;">${s.label}</div>
          <span style="font-size:9px;color:var(--text2);">${isUsingDefaults ? defaults.length + ' defaults' : patterns.length + ' custom'}</span>
        </div>
        <div id="${id}" style="max-height:120px;overflow-y:auto;margin:4px 0;">${items}</div>
        <div style="display:flex;gap:4px;margin-top:4px;">
          <input type="text" class="form-input" id="${id}_add" placeholder="Add pattern..." style="flex:1;font-size:10px;padding:2px 6px;" />
          <button class="btn-secondary" style="font-size:10px;padding:2px 8px;" onclick="addDetPattern('${s.key}')">Add</button>
        </div>
      </div>`;
    }
    el.innerHTML = html;
  }).catch(() => { el.innerHTML = '<div style="color:var(--error);font-size:12px;padding:8px;">Failed to load.</div>'; });
}

function addDetPattern(key) {
  const input = document.getElementById('det_' + key + '_add');
  if (!input || !input.value.trim()) return;
  apiFetch('/api/config').then(cfg => {
    const patterns = (cfg?.detection?.[key] || []).slice();
    patterns.push(input.value.trim());
    return apiFetch('/api/config', { method: 'PUT', body: JSON.stringify({ ['detection.' + key]: patterns }) });
  }).then(() => { showToast('Pattern added', 'success', 1500); loadDetectionFilters(); })
    .catch(err => showToast('Failed: ' + err.message, 'error'));
}

function saveDetTiming() {
  const debounce = parseInt(document.getElementById('det_prompt_debounce')?.value) || 3;
  const cooldown = parseInt(document.getElementById('det_notify_cooldown')?.value) || 15;
  apiFetch('/api/config', { method: 'PUT', body: JSON.stringify({
    'detection.prompt_debounce': debounce,
    'detection.notify_cooldown': cooldown,
  })}).then(() => showToast('Detection timing saved', 'success', 1500))
    .catch(err => showToast('Failed: ' + err.message, 'error'));
}

function removeDetPattern(key, index) {
  apiFetch('/api/config').then(cfg => {
    const patterns = (cfg?.detection?.[key] || []).slice();
    patterns.splice(index, 1);
    return apiFetch('/api/config', { method: 'PUT', body: JSON.stringify({ ['detection.' + key]: patterns }) });
  }).then(() => { showToast('Pattern removed', 'success', 1500); loadDetectionFilters(); })
    .catch(err => showToast('Failed: ' + err.message, 'error'));
}

function loadSchedulesList() {
  const el = document.getElementById('schedulesList');
  if (!el) return;
  apiFetch('/api/schedules').then(items => {
    if (!items || items.length === 0) {
      el.innerHTML = '<div style="color:var(--text2);font-size:12px;padding:8px;">No scheduled events.</div>';
      return;
    }
    // Show most recent first, paginated (10 per page)
    const page = settingsPagination.schedules || 0;
    const perPage = 10;
    const sorted = items.sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
    const pageItems = sorted.slice(page * perPage, (page + 1) * perPage);
    const totalPages = Math.ceil(sorted.length / perPage);
    const hasMultiple = pageItems.length > 1;
    let html = hasMultiple ? `<div style="display:flex;justify-content:space-between;align-items:center;padding:4px 8px;border-bottom:1px solid var(--border);">
      <label style="font-size:10px;display:flex;align-items:center;gap:4px;color:var(--text2);"><input type="checkbox" id="schedSelectAll" onchange="toggleAllScheduleCheckboxes(this.checked)"> Select all</label>
      <button class="btn-secondary" style="font-size:10px;padding:2px 8px;" onclick="deleteSelectedSchedules()">Delete selected</button>
    </div>` : '';
    html += pageItems.map(sc => {
      const when = _fmtScheduleTime(sc.run_at);
      const stateClass = sc.state === 'pending' ? 'color:var(--warning)' : sc.state === 'done' ? 'color:var(--success)' : 'color:var(--text2)';
      const label = sc.type === 'new_session' && sc.deferred_session
        ? 'NEW: ' + escHtml(sc.deferred_session.name || sc.command)
        : escHtml(sc.session_id) + ': ' + escHtml(sc.command);
      const actions = [];
      if (sc.state === 'pending') {
        actions.push(`<button class="btn-icon" style="font-size:10px;" onclick="editSchedulePrompt('${sc.id}','${escHtml(sc.command).replace(/'/g,"\\'")}','${sc.run_at||''}')" title="Edit">&#9998;</button>`);
      }
      actions.push(`<button class="btn-icon" style="font-size:10px;color:var(--error);" onclick="deleteScheduleEntry('${sc.id}')" title="Delete">&#128465;</button>`);
      return `<div class="settings-row" style="justify-content:space-between;font-size:12px;">
        ${hasMultiple ? `<input type="checkbox" class="sched-checkbox" data-id="${sc.id}" style="margin-right:6px;">` : ''}
        <div style="flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;" title="${escHtml(sc.command)}">${label}</div>
        <div style="display:flex;align-items:center;gap:6px;">
          <span style="font-size:10px;color:var(--text2);">${when}</span>
          <span style="font-size:10px;${stateClass};font-weight:600;text-transform:uppercase;">${escHtml(sc.state)}</span>
          ${actions.join('')}
        </div>
      </div>`;
    }).join('');
    if (totalPages > 1) {
      html += `<div style="display:flex;justify-content:center;gap:8px;padding:6px;">
        ${page > 0 ? `<button class="btn-link" style="font-size:11px;" onclick="settingsPagination.schedules=${page - 1};loadSchedulesList()">&#9664; Prev</button>` : ''}
        <span style="font-size:11px;color:var(--text2);">Page ${page + 1}/${totalPages}</span>
        ${page < totalPages - 1 ? `<button class="btn-link" style="font-size:11px;" onclick="settingsPagination.schedules=${page + 1};loadSchedulesList()">Next &#9654;</button>` : ''}
      </div>`;
    }
    el.innerHTML = html;
  }).catch(() => { el.innerHTML = '<div style="color:var(--error);font-size:12px;padding:8px;">Failed to load schedules.</div>'; });
}

function editSchedulePrompt(id, currentCmd, currentRunAt) {
  const newCmd = prompt('Edit command:', currentCmd);
  if (newCmd === null) return; // cancelled
  const newTime = prompt('New time (ISO, or empty to keep):', currentRunAt || '');
  const body = { id, command: newCmd || currentCmd };
  if (newTime) body.run_at = newTime;
  apiFetch('/api/schedules', {
    method: 'PUT',
    body: JSON.stringify(body),
  }).then(() => { showToast('Schedule updated', 'success', 1500); loadSchedulesList(); })
    .catch(e => showToast('Update failed: ' + e.message, 'error'));
}

function deleteScheduleEntry(id) {
  apiFetch('/api/schedules?id=' + encodeURIComponent(id), { method: 'DELETE' })
    .then(() => { showToast('Deleted', 'success', 1500); loadSchedulesList(); })
    .catch(e => showToast('Delete failed: ' + e.message, 'error'));
}

function toggleAllScheduleCheckboxes(checked) {
  document.querySelectorAll('.sched-checkbox').forEach(cb => cb.checked = checked);
}

function deleteSelectedSchedules() {
  const ids = Array.from(document.querySelectorAll('.sched-checkbox:checked')).map(cb => cb.dataset.id);
  if (ids.length === 0) { showToast('No items selected', 'warning'); return; }
  showConfirmModal(`Delete ${ids.length} scheduled event(s)?`, () => {
    Promise.all(ids.map(id => apiFetch('/api/schedules?id=' + encodeURIComponent(id), { method: 'DELETE' })))
      .then(() => { showToast(`Deleted ${ids.length} events`, 'success', 1500); loadSchedulesList(); })
      .catch(e => showToast('Delete failed: ' + e.message, 'error'));
  });
}

function loadSavedCommands() {
  const el = document.getElementById('savedCmdsList');
  if (!el) return;
  fetch('/api/commands', { headers: tokenHeader() })
    .then(r => r.ok ? r.json() : [])
    .then(cmds => {
      if (!cmds || cmds.length === 0) {
        el.innerHTML = '<div style="color:var(--text2);font-size:13px;">No saved commands. Run <code>datawatch seed</code> to populate defaults.</div>';
        return;
      }
      const ps = getPageSize('cmds');
      const page = Math.min(settingsPagination.cmds || 0, Math.max(0, Math.ceil(cmds.length / ps) - 1));
      settingsPagination.cmds = page;
      const pageCmds = cmds.slice(page * ps, page * ps + ps);
      el.innerHTML = renderPageControls('cmds', page, cmds.length, ps, 'pageCmd') +
        '<div>' + pageCmds.map(cmd => {
        const id = 'cmd-edit-' + cmd.name.replace(/[^a-z0-9]/gi, '_');
        return `<div class="settings-list-row">
          <div class="settings-list-view" id="${id}-view">
            <div class="settings-list-info">
              <strong>${escHtml(cmd.name)}</strong>
              <span class="settings-list-detail">${escHtml(cmd.command)}</span>
              ${cmd.seeded ? '<span class="settings-list-tag">(seeded)</span>' : ''}
            </div>
            <div class="settings-list-actions">
              <button class="btn-icon" title="Edit" onclick="showCmdEdit('${escHtml(cmd.name)}')">✎</button>
              <button class="btn-icon btn-icon-del" title="Delete" onclick="deleteSavedCmd('${escHtml(cmd.name)}')">✕</button>
            </div>
          </div>
          <div class="settings-list-edit" id="${id}-edit" style="display:none;">
            <input class="settings-input" id="${id}-name" value="${escHtml(cmd.name)}" placeholder="Name" style="width:120px;" />
            <input class="settings-input" id="${id}-val" value="${escHtml(cmd.command)}" placeholder="Command" style="flex:1;" />
            <button class="btn-secondary" style="font-size:12px;" onclick="saveCmdEdit('${escHtml(cmd.name)}','${id}')">Save</button>
            <button class="btn-icon" onclick="hideCmdEdit('${id}')">✕</button>
          </div>
        </div>`;
      }).join('') + '</div>';
    })
    .catch(() => { el.innerHTML = '<div style="color:var(--error);font-size:13px;">Failed to load commands.</div>'; });
}

function deleteSavedCmd(name) {
  fetch('/api/commands?name=' + encodeURIComponent(name), { method: 'DELETE', headers: tokenHeader() })
    .then(r => r.ok ? loadSavedCommands() : showToast('Delete failed', 'error'))
    .catch(() => showToast('Delete failed', 'error'));
}

function showCmdEdit(name) {
  const id = 'cmd-edit-' + name.replace(/[^a-z0-9]/gi, '_');
  const view = document.getElementById(id + '-view');
  const edit = document.getElementById(id + '-edit');
  if (view) view.style.display = 'none';
  if (edit) edit.style.display = 'flex';
}

function hideCmdEdit(id) {
  const view = document.getElementById(id + '-view');
  const edit = document.getElementById(id + '-edit');
  if (view) view.style.display = 'flex';
  if (edit) edit.style.display = 'none';
}

function saveCmdEdit(oldName, id) {
  const nameEl = document.getElementById(id + '-name');
  const valEl = document.getElementById(id + '-val');
  if (!nameEl || !valEl) return;
  apiFetch('/api/commands', {
    method: 'PUT',
    body: JSON.stringify({ old_name: oldName, name: nameEl.value.trim(), command: valEl.value.trim() }),
  })
    .then(() => { loadSavedCommands(); showToast('Command updated', 'success', 2000); })
    .catch(err => showToast('Update failed: ' + err.message, 'error'));
}

function createSavedCmd() {
  const name = (document.getElementById('newCmdName') || {}).value || '';
  const command = (document.getElementById('newCmdValue') || {}).value || '';
  if (!name || !command) { showToast('Name and command required', 'error'); return; }
  fetch('/api/commands', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', ...tokenHeader() },
    body: JSON.stringify({ name, command }),
  })
    .then(r => {
      if (r.ok) {
        document.getElementById('newCmdName').value = '';
        document.getElementById('newCmdValue').value = '';
        loadSavedCommands();
        showToast('Command saved', 'success', 2000);
      } else {
        r.text().then(t => showToast(t || 'Save failed', 'error'));
      }
    })
    .catch(() => showToast('Save failed', 'error'));
}

// ── Filters (in Settings) ─────────────────────────────────────────────────────

function pageFilter(dir) {
  settingsPagination.filters = Math.max(0, (settingsPagination.filters || 0) + dir);
  loadFilters();
}

function loadFilters() {
  const el = document.getElementById('filtersList');
  if (!el) return;
  fetch('/api/filters', { headers: tokenHeader() })
    .then(r => r.ok ? r.json() : [])
    .then(filters => {
      if (!filters || filters.length === 0) {
        el.innerHTML = '<div style="color:var(--text2);font-size:13px;">No filters. Run <code>datawatch seed</code> to populate defaults.</div>';
        return;
      }
      const ps = getPageSize('filters');
      const page = Math.min(settingsPagination.filters || 0, Math.max(0, Math.ceil(filters.length / ps) - 1));
      settingsPagination.filters = page;
      const pageFilters = filters.slice(page * ps, page * ps + ps);
      el.innerHTML = renderPageControls('filters', page, filters.length, ps, 'pageFilter') +
        '<div>' + pageFilters.map(f => {
        const fid = 'flt-' + f.id;
        const actions = ['alert','send_input','detect_prompt','schedule'];
        return `<div class="settings-list-row">
          <div class="settings-list-view" id="${fid}-view">
            <div class="settings-list-info">
              <span class="state state-${f.enabled ? 'running' : 'failed'}" style="font-size:10px;margin-right:6px;">${f.enabled ? 'on' : 'off'}</span>
              <code class="settings-list-detail">${escHtml(f.pattern)}</code>
              <span class="settings-list-tag">${escHtml(f.action)}${f.value ? ' → ' + escHtml(f.value) : ''}</span>
            </div>
            <div class="settings-list-actions">
              <button class="btn-icon" title="${f.enabled ? 'Disable' : 'Enable'}" onclick="toggleFilter('${escHtml(f.id)}',${!f.enabled})">${f.enabled ? '⏸' : '▶'}</button>
              <button class="btn-icon" title="Edit" onclick="showFilterEdit('${escHtml(f.id)}')">✎</button>
              <button class="btn-icon btn-icon-del" title="Delete" onclick="deleteFilter('${escHtml(f.id)}')">✕</button>
            </div>
          </div>
          <div class="settings-list-edit" id="${fid}-edit" style="display:none;">
            <input class="settings-input" id="${fid}-pat" value="${escHtml(f.pattern)}" placeholder="Pattern (regex)" style="flex:2;" />
            <select class="settings-input" id="${fid}-act" style="flex:1;">${actions.map(a => `<option value="${a}"${a===f.action?' selected':''}>${a}</option>`).join('')}</select>
            <input class="settings-input" id="${fid}-val" value="${escHtml(f.value||'')}" placeholder="Value (optional)" style="flex:1;" />
            <button class="btn-secondary" style="font-size:12px;" onclick="saveFilterEdit('${escHtml(f.id)}')">Save</button>
            <button class="btn-icon" onclick="hideFilterEdit('${escHtml(f.id)}')">✕</button>
          </div>
        </div>`;
      }).join('') + '</div>';
    })
    .catch(() => { el.innerHTML = '<div style="color:var(--error);font-size:13px;">Failed to load filters.</div>'; });
}

function toggleFilter(id, enable) {
  fetch('/api/filters', { method: 'PATCH', headers: { 'Content-Type': 'application/json', ...tokenHeader() }, body: JSON.stringify({ id, enabled: enable }) })
    .then(r => r.ok ? loadFilters() : showToast('Update failed', 'error'))
    .catch(() => showToast('Update failed', 'error'));
}

function deleteFilter(id) {
  fetch('/api/filters?id=' + encodeURIComponent(id), { method: 'DELETE', headers: tokenHeader() })
    .then(r => r.ok ? loadFilters() : showToast('Delete failed', 'error'))
    .catch(() => showToast('Delete failed', 'error'));
}

function showFilterEdit(id) {
  const fid = 'flt-' + id;
  const v = document.getElementById(fid + '-view');
  const e = document.getElementById(fid + '-edit');
  if (v) v.style.display = 'none';
  if (e) e.style.display = 'flex';
}

function hideFilterEdit(id) {
  const fid = 'flt-' + id;
  const v = document.getElementById(fid + '-view');
  const e = document.getElementById(fid + '-edit');
  if (v) v.style.display = 'flex';
  if (e) e.style.display = 'none';
}

function saveFilterEdit(id) {
  const fid = 'flt-' + id;
  const pattern = (document.getElementById(fid + '-pat') || {}).value || '';
  const action = (document.getElementById(fid + '-act') || {}).value || '';
  const value = (document.getElementById(fid + '-val') || {}).value || '';
  if (!pattern || !action) { showToast('Pattern and action required', 'error'); return; }
  apiFetch('/api/filters', {
    method: 'PATCH',
    body: JSON.stringify({ id, pattern, action, value, enabled: true }),
  })
    .then(() => { loadFilters(); showToast('Filter updated', 'success', 2000); })
    .catch(err => showToast('Update failed: ' + err.message, 'error'));
}

function createFilter() {
  const pattern = (document.getElementById('newFilterPattern') || {}).value || '';
  const action = (document.getElementById('newFilterAction') || {}).value || '';
  const value = (document.getElementById('newFilterValue') || {}).value || '';
  if (!pattern || !action) { showToast('Pattern and action required', 'error'); return; }
  fetch('/api/filters', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', ...tokenHeader() },
    body: JSON.stringify({ pattern, action, value }),
  })
    .then(r => {
      if (r.ok) {
        document.getElementById('newFilterPattern').value = '';
        document.getElementById('newFilterValue').value = '';
        loadFilters();
        showToast('Filter saved', 'success', 2000);
      } else {
        r.text().then(t => showToast(t || 'Save failed', 'error'));
      }
    })
    .catch(() => showToast('Save failed', 'error'));
}

// ── Back button ──────────────────────────────────────────────────────────────
document.addEventListener('DOMContentLoaded', () => {
  const backBtn = document.getElementById('backBtn');
  if (backBtn) {
    backBtn.addEventListener('click', () => {
      navigate('sessions');
    });
  }

  registerServiceWorker();
  // Load i18n bundle before rendering — non-blocking on the WS connect.
  // navigate() reads from t() so the bundle must be present before the
  // first render. Falls through to English on fetch failure.
  initI18n().finally(() => {
    document.documentElement.setAttribute('lang', window._i18n.current);
    connect();
    let _initView = localStorage.getItem('cs_active_view');
    const _initSession = localStorage.getItem('cs_active_session');
    // BL247-followup v6.7.3 — Monitor sub-tab dropped; its content + a
    // Federated Peers card live in the top-level Observer view.
    // Operators with cs_settings_tab='monitor' (or those who briefly
    // landed on the v6.7.2 redirect) get bounced to the Observer view.
    const _initSettingsTab = localStorage.getItem('cs_settings_tab');
    if (_initSettingsTab === 'monitor') {
      _initView = 'observer';
      localStorage.setItem('cs_active_view', 'observer');
      localStorage.removeItem('cs_settings_tab');
    }
    navigate(_initView || 'sessions', _initSession || undefined);
  });

  // Load initial unread alert count
  fetch('/api/alerts', { headers: tokenHeader() })
    .then(r => r.ok ? r.json() : null)
    .then(data => { if (data) { state.alertUnread = data.unread_count || 0; updateAlertBadge(); } })
    .catch(() => {});

  // v5.26.8 — cache whisper-enabled so mic-button affordances on
  // textareas + CSV-expand modals only render when transcription is
  // actually wired. Operator-reported: mic should only show if
  // whisper is configured.
  fetch('/api/config', { headers: tokenHeader() })
    .then(r => r.ok ? r.json() : null)
    .then(cfg => {
      state._whisperEnabled = !!(cfg && cfg.whisper && cfg.whisper.enabled);
    })
    .catch(() => { state._whisperEnabled = false; });

  // v5.26.8 — hide the Autonomous tab when autonomous.enabled=false.
  // Operator-reported: tabs for disabled subsystems shouldn't render
  // at all. The button starts display:none in index.html; JS unhides
  // when /api/autonomous/config returns enabled:true. If the request
  // fails (auth issue, daemon down) we leave it hidden — better to
  // be invisible than to show a tab that 503s on click.
  fetch('/api/autonomous/config', { headers: tokenHeader() })
    .then(r => r.ok ? r.json() : null)
    .then(cfg => {
      const btn = document.getElementById('navBtnAutonomous');
      if (btn && cfg && cfg.enabled === true) btn.style.display = '';
      // BL313 — Dashboard is part of the autonomous subsystem; gate it on the same flag.
      const dashBtn = document.getElementById('navBtnDashboard');
      if (dashBtn && cfg && cfg.enabled === true) dashBtn.style.display = '';
    })
    .catch(() => {});

  // BL247-followup v6.7.2 — Observer view folded into Settings → Monitor
  // (Federated Peers card). The standalone nav button + view path were
  // removed; the BL220-G1 visibility check that previously revealed the
  // nav button is no longer needed because the Monitor card is always
  // present in Settings, and its loader degrades gracefully when
  // /api/observer/stats is unreachable.

  // BL238 — Plugins, Routing, Orchestrator moved to Settings sub-tabs; nav visibility checks removed.

  // Periodically refresh time-ago labels while on sessions view
  setInterval(() => {
    if (state.activeView === 'sessions') {
      renderSessionsView();
    }
  }, 30000);
});

// Make navigate global so onclick attributes work
window.navigate = navigate;
window.submitNewSession = submitNewSession;
window.sendSessionInput = sendSessionInput;
window.saveToken = saveToken;
window.requestNotificationPermission = requestNotificationPermission;
window.startLinking = startLinking;
window.renderAlertsView = renderAlertsView;
