// renderObserverPeersCard paints the per-Monitor card content into a
// target element by id. Replaces the body of the old standalone view.
function renderObserverPeersCard(targetId) {
  const el = document.getElementById(targetId || 'observerPeersPanel');
  if (!el) return;
  el.innerHTML = `<div style="text-align:center;padding:16px;color:var(--text2);">${escHtml(t('common_loading'))}</div>`;
  Promise.all([
    apiFetch('/api/observer/stats').catch(() => null),
    apiFetch('/api/observer/peers').catch(() => ({ peers: [] })),
    apiFetch('/api/observer/config').catch(() => null),
  ]).then(([stats, peersData, cfg]) => {
    if (!el) return;
    const peers = (peersData && peersData.peers) || [];
    const statsRow = stats ? `<div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:12px;">${
      Object.entries(stats).filter(([,v]) => typeof v !== 'object').map(([k, v]) =>
        `<div style="background:var(--bg2);border:1px solid var(--border);border-radius:8px;padding:8px 12px;font-size:12px;min-width:80px;">
          <div style="opacity:0.6;font-size:10px;text-transform:uppercase;letter-spacing:0.5px;">${escHtml(k)}</div>
          <div style="font-weight:600;">${escHtml(String(v))}</div>
        </div>`).join('')
    }</div>` : '';
    const cfgRow = cfg && Object.keys(cfg).length ? `<div style="background:var(--bg2);border:1px solid var(--border);border-radius:8px;padding:10px 12px;margin-bottom:12px;font-size:12px;">
      <div style="font-size:11px;font-weight:600;text-transform:uppercase;letter-spacing:0.5px;opacity:0.6;margin-bottom:6px;">Config</div>
      ${Object.entries(cfg).map(([k, v]) => {
        const display = (v !== null && typeof v === 'object')
          ? `<span style="opacity:0.5;font-size:10px;">{${Object.keys(v).join(', ')}}</span>`
          : `<strong>${escHtml(String(v))}</strong>`;
        return `<div style="display:flex;justify-content:space-between;padding:2px 0;"><span style="opacity:0.7;">${escHtml(k)}</span>${display}</div>`;
      }).join('')}
    </div>` : '';
    const now = Date.now();
    const peerRows = peers.length === 0
      ? '<div style="opacity:0.7;padding:8px 0;">no peers registered</div>'
      : peers.map(p => {
          const lastPush = p.last_push_at ? new Date(p.last_push_at).getTime() : 0;
          const ageMs = lastPush ? (now - lastPush) : Infinity;
          const dotColor = lastPush ? (ageMs < 15000 ? 'var(--success,#10b981)' : ageMs < 60000 ? 'var(--warning,#f59e0b)' : 'var(--error,#ef4444)') : 'var(--text2)';
          const shapeText = ({A:'agent',B:'standalone',C:'cluster'}[(p.shape||'').toUpperCase()]) || (p.shape||'?');
          const ageLabel = lastPush ? observerPeerAgo(ageMs) : 'never';
          const safeName = JSON.stringify(p.name || '');
          return `<div style="padding:6px 0;border-top:1px solid var(--border);display:flex;align-items:center;flex-wrap:wrap;">
            <span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:${dotColor};margin-right:6px;flex-shrink:0;"></span>
            <strong>${escHtml(p.name)}</strong>
            <span style="opacity:0.55;font-size:10px;border:1px solid var(--text2);border-radius:3px;padding:0 4px;margin-left:4px;">${escHtml(shapeText)}</span>
            <span style="opacity:0.6;font-size:11px;margin-left:6px;">${escHtml(ageLabel)}</span>
            <div style="margin-left:auto;">
              <button class="btn-icon" style="font-size:11px;padding:1px 6px;" onclick='showObserverPeerSnapshot(${safeName})' title="Snapshot">&#128202;</button>
              <button class="btn-icon" style="font-size:11px;padding:1px 6px;" onclick='removeObserverPeer(${safeName})' title="Remove">&times;</button>
            </div>
          </div>`;
        }).join('');
    el.innerHTML = statsRow + cfgRow
      + `<div style="font-size:11px;font-weight:600;text-transform:uppercase;letter-spacing:0.5px;opacity:0.6;margin-bottom:6px;">Peers (${peers.length})
          <span class="live-dot" title="Auto-refreshing every 8s — no need to click refresh" style="display:inline-block;width:7px;height:7px;border-radius:50%;background:var(--success,#10b981);margin-left:6px;animation:livePulse 2s ease-in-out infinite;vertical-align:middle;"></span>
          <span style="opacity:0.5;font-weight:400;font-size:10px;margin-left:4px;">live</span>
        </div>`
      + peerRows;
  }).catch(err => {
    if (el) el.innerHTML = `<div style="color:var(--error);padding:16px;">${escHtml(String(err.message||err))}</div>`;
  });
}
window.renderObserverPeersCard = renderObserverPeersCard;

// v7.0.0-alpha.11 (#210) — operator: "observer/federated-peers must be
// live (no refresh buttons)". 8s poll while the Observer view is the
// active route and the peers panel is in DOM. Cheap (3 GETs total —
// stats + peers + config) and reuses the existing render path. The
// Pipelines + Orchestrator-Graphs panels in Settings → Automata follow
// the same pattern when their tab is the active settings sub-tab.
setInterval(() => {
  if (state.activeView !== 'observer') return;
  const el = document.getElementById('observerPeersPanel');
  if (!el) return;
  // Skip if a snapshot drill-down popover is open, so operators don't
  // lose their place mid-look.
  if (document.querySelector('.peer-snapshot-popover, .observer-peer-popover')) return;
  renderObserverPeersCard();
}, 8000);

setInterval(() => {
  if (state.activeView !== 'settings') return;
  const stab = localStorage.getItem('cs_settings_tab') || '';
  if (stab !== 'automata') return;
  // Skip if a modal/dialog is open over either panel.
  if (document.querySelector('.modal-open, .pipeline-detail-popover, .orchestrator-graph-popover')) return;
  if (typeof window.loadPipelinesPanel === 'function' && document.getElementById('pipelinesPanel')) {
    window.loadPipelinesPanel();
  }
  if (typeof window.loadOrchestratorPanel === 'function' && document.getElementById('orchestratorPanel')) {
    window.loadOrchestratorPanel();
  }
}, 8000);

// ── BL220-G2 Plugins panel ────────────────────────────────────────────────────

// BL219 — loadToolingPanel: shows per-backend artifact status in Settings → General.
function loadToolingPanel() {
  const el = document.getElementById('toolingStatusPanel');
  if (!el) return;
  apiFetch('/api/tooling/status').then(data => {
    const backends = Array.isArray(data.backends) ? data.backends : (data.status ? [data.status] : []);
    if (backends.length === 0) {
      el.innerHTML = '<div style="opacity:0.7;font-size:12px;padding:8px 12px;">No backends configured.</div>';
      return;
    }
    el.innerHTML = backends.map(b => {
      const present = (b.present||[]).join(', ') || 'none';
      const ignored = b.ignored ? '✓' : '⚠ not ignored';
      return `<div style="padding:6px 12px;border-top:1px solid var(--border);font-size:12px;display:flex;gap:8px;align-items:center;">
        <code style="width:90px;color:var(--accent);">${escHtml(b.backend)}</code>
        <span style="flex:1;color:var(--text2);">present: ${escHtml(present)}</span>
        <span style="font-size:11px;color:${b.ignored?'var(--ok, #4caf50)':'var(--warn, #ff9800)'};">${ignored}</span>
        <button class="btn-secondary" style="font-size:10px;padding:2px 6px;" onclick="toolingGitignore(${JSON.stringify(b.backend)})">gitignore</button>
        <button class="btn-secondary" style="font-size:10px;padding:2px 6px;color:var(--error);" onclick="toolingCleanup(${JSON.stringify(b.backend)})">cleanup</button>
      </div>`;
    }).join('');
  }).catch(() => { el.innerHTML = '<span style="color:var(--error);font-size:12px;padding:8px 12px;">Failed to load tooling status.</span>'; });
}
window.loadToolingPanel = loadToolingPanel;
window.toolingGitignore = function(backend) {
  apiFetch('/api/tooling/gitignore', { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify({ backend }) })
    .then(d => { showToast(`gitignore: ${d.patterns_added||0} pattern(s) added`, 'success', 2500); loadToolingPanel(); })
    .catch(e => showToast(String(e.message||e), 'error'));
};
window.toolingCleanup = function(backend) {
  apiFetch('/api/tooling/cleanup', { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify({ backend }) })
    .then(d => { showToast(`cleanup: ${(d.removed||[]).length} file(s) removed`, 'success', 2500); loadToolingPanel(); })
    .catch(e => showToast(String(e.message||e), 'error'));
};

// BL274 (v6.16.0) — Docs-as-MCP-Interface PWA panel.
// Search box + pending-trust queue + trusted-sources list + YAML export.
function docsSearchRun() {
  const el = document.getElementById('docsSearchInput');
  const out = document.getElementById('docsSearchResults');
  if (!el || !out) return;
  const q = (el.value || '').trim();
  if (!q) { out.innerHTML = ''; return; }
  out.innerHTML = '<em>Searching…</em>';
  apiFetch('/api/docs/search?q=' + encodeURIComponent(q) + '&limit=10').then(d => {
    const hits = (d && d.hits) || [];
    if (!hits.length) { out.innerHTML = '<em>No matches.</em>'; return; }
    out.innerHTML = hits.map(h => {
      const link = `/diagrams.html#docs/${escHtml(h.path)}${h.anchor ? '#' + escHtml(h.anchor) : ''}`;
      return `<div style="border-bottom:1px solid var(--border);padding:6px 0;">
        <a href="${link}" target="_blank" rel="noopener" style="color:var(--accent);font-weight:600;">${escHtml(h.title)}${h.heading ? ' — ' + escHtml(h.heading) : ''}</a>
        <span style="font-size:10px;opacity:0.7;margin-left:6px;">${escHtml(h.source)} · ${escHtml(h.index_kind)} · ${h.score.toFixed(2)}</span>
        <div style="margin-top:2px;">${escHtml(h.excerpt)}</div>
      </div>`;
    }).join('');
  }).catch(e => { out.innerHTML = `<span style="color:var(--error);">${escHtml(String(e.message||e))}</span>`; });
}
window.docsSearchRun = docsSearchRun;

function loadDocsTrustPanel() {
  const trustEl = document.getElementById('docsTrustedList');
  const pendEl  = document.getElementById('docsPendingList');
  if (!trustEl || !pendEl) return;
  apiFetch('/api/docs/trust').then(d => {
    const t = (d && d.trusted) || [];
    trustEl.innerHTML = t.map(e => {
      const removable = e.source !== 'core';
      return `<div style="display:flex;align-items:center;gap:6px;padding:2px 0;">
        <code style="flex:1;">${escHtml(e.source)}</code>
        <span style="font-size:10px;opacity:0.7;">${escHtml(e.granted_by||'')}</span>
        ${removable ? `<button class="btn-secondary" style="font-size:10px;padding:1px 6px;" onclick="docsTrustRemove(${JSON.stringify(e.source)})">×</button>` : ''}
      </div>`;
    }).join('');
  }).catch(()=>{ trustEl.textContent = 'failed'; });
  apiFetch('/api/docs/trust/pending').then(d => {
    const p = (d && d.pending) || [];
    if (!p.length) { pendEl.innerHTML = '<em style="opacity:0.6;">none</em>'; return; }
    // BL274 S6 — bulk-select pending-trust UX. Deferred from S4/S5 polish.
    // Each row gets a checkbox; the toolbar above the rows enables Trust /
    // Dismiss for every checked source in one round-trip via POST
    // /api/docs/trust/{accept,dismiss} (which already accept arrays).
    const toolbar = `<div style="display:flex;gap:6px;padding:4px 0;align-items:center;border-bottom:1px solid var(--border);margin-bottom:4px;">
      <label style="display:flex;align-items:center;gap:4px;font-size:11px;cursor:pointer;">
        <input type="checkbox" id="docsPendingSelectAll" onchange="docsTrustToggleAll(this.checked)" />
        <span>${escHtml(t('docs_pending_select_all')||'select all')}</span>
      </label>
      <span style="flex:1;"></span>
      <button class="btn-success" style="font-size:10px;padding:2px 8px;" onclick="docsTrustBulkAccept()">${escHtml(t('docs_pending_bulk_trust')||'Trust selected')}</button>
      <button class="btn-secondary" style="font-size:10px;padding:2px 8px;" onclick="docsTrustBulkDismiss()">${escHtml(t('docs_pending_bulk_dismiss')||'Dismiss selected')}</button>
    </div>`;
    const rows = p.map(e => `<div class="docs-pending-row" style="display:flex;align-items:center;gap:6px;padding:2px 0;">
      <input type="checkbox" class="docs-pending-cb" data-source="${escHtml(e.source)}" />
      <code style="flex:1;">${escHtml(e.source)}</code>
      <span style="font-size:10px;opacity:0.7;">${escHtml(e.detail||'')}</span>
      <button class="btn-success" style="font-size:10px;padding:1px 6px;" onclick="docsTrustAccept(${JSON.stringify(e.source)})">${escHtml(t('docs_accept_btn')||'Trust')}</button>
      <button class="btn-secondary" style="font-size:10px;padding:1px 6px;" onclick="docsTrustDismiss(${JSON.stringify(e.source)})">${escHtml(t('docs_dismiss_btn')||'Dismiss')}</button>
    </div>`).join('');
    pendEl.innerHTML = toolbar + rows;
  }).catch(()=>{ pendEl.textContent = 'failed'; });
}

// BL274 S6 — bulk-trust helpers.
function docsTrustToggleAll(checked) {
  document.querySelectorAll('.docs-pending-cb').forEach(cb => { cb.checked = checked; });
}
window.docsTrustToggleAll = docsTrustToggleAll;
function docsTrustSelectedSources() {
  return Array.from(document.querySelectorAll('.docs-pending-cb:checked')).map(cb => cb.dataset.source);
}
function docsTrustBulkAccept() {
  const sources = docsTrustSelectedSources();
  if (!sources.length) { showToast('Select one or more sources first', 'info', 2000); return; }
  apiFetch('/api/docs/trust/accept', {
    method: 'POST', headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ sources }),
  }).then(d => { showToast('Trusted ' + (d && d.added || sources.length) + ' source(s)', 'success', 2000); loadDocsTrustPanel(); })
    .catch(e => showToast(String(e.message||e), 'error'));
}
window.docsTrustBulkAccept = docsTrustBulkAccept;
function docsTrustBulkDismiss() {
  const sources = docsTrustSelectedSources();
  if (!sources.length) { showToast('Select one or more sources first', 'info', 2000); return; }
  apiFetch('/api/docs/trust/dismiss', {
    method: 'POST', headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ sources }),
  }).then(d => { showToast('Dismissed ' + (d && d.dismissed || sources.length) + ' source(s)', 'success', 2000); loadDocsTrustPanel(); })
    .catch(e => showToast(String(e.message||e), 'error'));
}
window.docsTrustBulkDismiss = docsTrustBulkDismiss;
window.loadDocsTrustPanel = loadDocsTrustPanel;

function docsTrustRemove(source) {
  apiFetch('/api/docs/trust/' + encodeURIComponent(source), { method: 'DELETE' })
    .then(()=>{ showToast('Untrusted ' + source, 'success', 1500); loadDocsTrustPanel(); })
    .catch(e => showToast(String(e.message||e), 'error'));
}
window.docsTrustRemove = docsTrustRemove;

function docsTrustAccept(source) {
  apiFetch('/api/docs/trust/accept', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ sources: [source] }),
  }).then(()=>{ showToast('Trusted ' + source, 'success', 1500); loadDocsTrustPanel(); })
    .catch(e => showToast(String(e.message||e), 'error'));
}
window.docsTrustAccept = docsTrustAccept;

function docsTrustDismiss(source) {
  apiFetch('/api/docs/trust/dismiss', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ sources: [source] }),
  }).then(()=>{ showToast('Dismissed ' + source, 'success', 1500); loadDocsTrustPanel(); })
    .catch(e => showToast(String(e.message||e), 'error'));
}
window.docsTrustDismiss = docsTrustDismiss;

function docsTrustExport() {
  apiFetch('/api/docs/trust/export').then(d => {
    showModal({
      title: 'Trust list — YAML for config.yaml',
      body: `<pre style="background:var(--bg2);padding:10px;border-radius:4px;font-size:11px;white-space:pre-wrap;">${escHtml(d.yaml_snippet || '')}</pre>
        <div style="font-size:11px;color:var(--text2);margin-top:6px;">Paste this into your config.yaml's docs_search.trust block to make runtime trust survive a wipe.</div>`,
    });
  }).catch(e => showToast(String(e.message||e), 'error'));
}
window.docsTrustExport = docsTrustExport;

// BL267 (v6.15.0) — Vault status row + nav badge updater. Renders into
// the Secrets card whenever the active backend is Vault. Hidden when
// /api/secrets/vault/status returns {backend_active:false}.
function loadVaultStatusRow() {
  const el = document.getElementById('vaultStatusRow');
  if (!el) return;
  apiFetch('/api/secrets/vault/status')
    .then(d => {
      if (!d || !d.backend_active) {
        el.style.display = 'none';
        _setVaultBadge(false, '');
        return;
      }
      const st = d.status || {};
      const reachable = !!st.reachable;
      const dot = `<span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:${reachable ? 'var(--success)' : 'var(--error)'};margin-right:6px;"></span>`;
      const last = st.last_success ? new Date(st.last_success).toLocaleTimeString() : '—';
      const err = st.last_error ? `<div style="color:var(--error);font-size:11px;margin-top:2px;">${escHtml(st.last_error)}</div>` : '';
      const reqID = st.last_request_id ? ` <span style="opacity:0.6;">req=${escHtml(st.last_request_id)}</span>` : '';
      el.innerHTML = `
        <div class="settings-row" style="flex-direction:column;align-items:flex-start;gap:2px;">
          <div style="display:flex;align-items:center;width:100%;">
            ${dot}<strong>${escHtml(t('vault_status_label')||'Vault')}</strong>
            <span style="opacity:0.7;margin-left:6px;font-size:11px;">${escHtml(st.address||'')}</span>
            <span style="margin-left:auto;font-size:11px;color:var(--text2);">${reachable ? (t('vault_reachable')||'reachable') : (t('vault_unreachable')||'unreachable')} · last=${escHtml(last)}${reqID}</span>
          </div>
          <div style="font-size:11px;color:var(--text2);">${escHtml(t('vault_meta_label')||'mount')}=${escHtml(st.kv_mount||'')} · ${escHtml(t('vault_path_prefix')||'prefix')}=${escHtml(st.path_prefix||'')} · ${escHtml(t('vault_path_layout')||'layout')}=${escHtml(st.path_layout||'')}${st.namespace?(' · ns='+escHtml(st.namespace)):''}
          </div>
          ${err}
        </div>`;
      el.style.display = '';
      _setVaultBadge(!reachable, st.last_error || '');
    })
    .catch(() => { el.style.display = 'none'; _setVaultBadge(false, ''); });
}
window.loadVaultStatusRow = loadVaultStatusRow;

// Settings nav badge for Vault: shows a red dot when Vault is the
// active backend AND unreachable. Re-uses the existing peerStaleBadge
// element shape (red circle, top-right of the nav button).
function _setVaultBadge(unreachable, errMsg) {
  const settingsNav = document.querySelector('[data-view="settings"] .nav-icon');
  if (!settingsNav) return;
  let badge = document.getElementById('vaultUnreachableBadge');
  if (unreachable) {
    if (!badge) {
      badge = document.createElement('span');
      badge.id = 'vaultUnreachableBadge';
      badge.style.cssText = 'position:absolute;top:-6px;right:-8px;background:var(--error,#ef4444);color:#fff;font-size:9px;border-radius:8px;padding:1px 4px;line-height:1.4;cursor:pointer;';
      badge.title = 'Vault unreachable';
      badge.innerHTML = '!';
      badge.onclick = (e) => { e.stopPropagation(); navigate('settings'); };
      settingsNav.appendChild(badge);
    }
    if (errMsg) badge.title = 'Vault unreachable: ' + errMsg;
  } else if (badge) {
    badge.remove();
  }
}

// BL242 — Secrets panel.
function loadSecretsPanel() {
  const el = document.getElementById('secretsListPanel');
  if (!el) return;
  loadVaultStatusRow();
  apiFetch('/api/secrets')
    .then(d => {
      const list = d.secrets || [];
      if (!list.length) {
        el.innerHTML = `<span style="color:var(--text2);">${t('secrets_none') || 'No secrets stored.'}</span>`;
        return;
      }
      el.innerHTML = list.map(s => {
        const tags = s.tags && s.tags.length ? `<span style="color:var(--text2);font-size:11px;margin-left:6px;">[${escHtml(s.tags.join(','))}]</span>` : '';
        const desc = s.description ? `<span style="color:var(--text2);font-size:11px;margin-left:6px;">${escHtml(s.description)}</span>` : '';
        const scopeBadges = s.scopes && s.scopes.length
          ? s.scopes.map(sc => `<span style="background:var(--warn-dim,#3a2e0a);color:var(--warn,#f0a000);border-radius:3px;padding:1px 5px;font-size:10px;margin-left:3px;">${escHtml(sc)}</span>`).join('')
          : `<span style="color:var(--text2);font-size:10px;margin-left:4px;">${t('secrets_scopes_universal') || '(universal)'}</span>`;
        return `<div style="display:flex;align-items:center;gap:6px;padding:3px 0;border-bottom:1px solid var(--border1);">
          <span style="flex:1;font-family:monospace;">${escHtml(s.name)}${tags}${desc}${scopeBadges}</span>
          <button class="btn-secondary" style="font-size:11px;padding:2px 8px;" onclick="deleteSecret(${escHtml(JSON.stringify(s.name))})">${t('secrets_delete_btn') || 'Delete'}</button>
        </div>`;
      }).join('');
    })
    .catch(e => { el.innerHTML = `<span style="color:var(--error);">${escHtml(String(e.message||e))}</span>`; });
}
window.loadSecretsPanel = loadSecretsPanel;

// BL243 — populate Tailscale config fields from daemon config
function loadTailscaleConfig() {
  apiFetch('/api/config')
    .then(cfg => {
      const ts = cfg.tailscale || {};
      const enableEl = document.getElementById('cfgTailscaleEnabled');
      if (enableEl) enableEl.checked = !!ts.enabled;
      const coordEl = document.getElementById('cfgTailscaleCoordinator');
      if (coordEl) coordEl.value = ts.coordinator_url || '';
      const imgEl = document.getElementById('cfgTailscaleImage');
      if (imgEl) imgEl.value = ts.image || '';
      // auth_key and api_key: show placeholder if set (never display value)
      const authEl = document.getElementById('cfgTailscaleAuthKey');
      if (authEl) authEl.placeholder = ts.auth_key ? '(set)' : t('tailscale_authkey_placeholder') || 'pre-auth key or ${secret:name}';
      const apiEl = document.getElementById('cfgTailscaleAPIKey');
      if (apiEl) apiEl.placeholder = ts.api_key ? '(set)' : t('tailscale_apikey_placeholder') || 'admin API key or ${secret:name}';
    })
    .catch(() => {});
}
window.loadTailscaleConfig = loadTailscaleConfig;

// BL243 — Tailscale mesh status panel
function loadTailscaleStatus() {
  const el = document.getElementById('tailscaleStatusPanel');
  if (!el) return;
  el.innerHTML = `<span style="color:var(--text2);">${t('tailscale_loading') || 'Loading…'}</span>`;
  apiFetch('/api/tailscale/status')
    .then(d => {
      if (d.error) {
        el.innerHTML = `<span style="color:var(--error);">${escHtml(d.error)}</span>`;
        return;
      }
      const backendBadge = `<span style="background:var(--accent-dim,#0d2a3a);color:var(--accent2);border-radius:3px;padding:1px 6px;font-size:11px;">${escHtml(d.backend||'unknown')}</span>`;
      const enabledBadge = d.enabled
        ? `<span style="color:var(--ok,#4caf50);font-weight:600;">${t('tailscale_enabled') || 'Enabled'}</span>`
        : `<span style="color:var(--text2);">${t('tailscale_disabled') || 'Disabled'}</span>`;
      const coordHtml = d.coordinator_url
        ? `<div class="settings-row"><div class="settings-label">${t('tailscale_coordinator_label')||'Coordinator'}</div><div class="settings-value" style="font-family:monospace;font-size:12px;">${escHtml(d.coordinator_url)}</div></div>`
        : '';
      const nodes = d.nodes || [];
      const nodesHtml = nodes.length
        ? `<div style="margin-top:6px;"><div style="font-size:11px;font-weight:600;color:var(--text2);margin-bottom:4px;">${t('tailscale_nodes_label')||'Nodes'} (${nodes.length})</div>` +
          nodes.map(n => {
            const onlineDot = n.online
              ? `<span style="color:var(--ok,#4caf50);">●</span>`
              : `<span style="color:var(--text2);">○</span>`;
            const tags = n.tags && n.tags.length ? ` <span style="color:var(--text2);font-size:10px;">[${escHtml(n.tags.join(','))}]</span>` : '';
            return `<div style="padding:2px 0;font-size:12px;">${onlineDot} <span style="font-family:monospace;">${escHtml(n.name)}</span> <span style="color:var(--text2);">${escHtml(n.ip||'')}</span>${tags}</div>`;
          }).join('') + '</div>'
        : `<div style="color:var(--text2);font-size:12px;margin-top:6px;">${t('tailscale_no_nodes')||'No nodes found (api_key required)'}</div>`;
      el.innerHTML = `
        <div class="settings-row"><div class="settings-label">${t('tailscale_status_label')||'Status'}</div><div class="settings-value">${enabledBadge} ${backendBadge}</div></div>
        ${coordHtml}
        ${nodesHtml}`;
    })
    .catch(e => { el.innerHTML = `<span style="color:var(--error);">${escHtml(String(e.message||e))}</span>`; });
}
window.loadTailscaleStatus = loadTailscaleStatus;

// BL243 Phase 2 — generate headscale pre-auth key
function generateTailscaleAuthKey() {
  const el = document.getElementById('tailscaleStatusPanel');
  if (el) el.innerHTML = `<span style="color:var(--text2);">${t('tailscale_loading') || 'Loading…'}</span>`;
  apiFetch('/api/tailscale/auth/key', {
    method: 'POST',
    headers: {'Content-Type':'application/json'},
    body: JSON.stringify({ reusable: false, ephemeral: false, expiry_hours: 24 }),
  }).then(d => {
    if (!el) return;
    if (d.error) { el.innerHTML = `<span style="color:var(--error);">${escHtml(d.error)}</span>`; return; }
    const key = d.key || '';
    el.innerHTML = `
      <div style="font-size:12px;color:var(--text2);margin-bottom:4px;">${t('tailscale_generated_key_label') || 'Generated pre-auth key (copy now):'}</div>
      <input type="text" value="${escHtml(key)}" readonly style="font-family:monospace;font-size:12px;width:100%;background:var(--bg2);color:var(--text);border:1px solid var(--border);border-radius:4px;padding:4px 8px;"
        onclick="this.select()" />
      ${d.expires_at ? `<div style="font-size:11px;color:var(--text2);margin-top:4px;">${t('tailscale_key_expires') || 'Expires'}: ${escHtml(d.expires_at)}</div>` : ''}`;
  }).catch(e => { if (el) el.innerHTML = `<span style="color:var(--error);">${escHtml(String(e.message||e))}</span>`; });
}
window.generateTailscaleAuthKey = generateTailscaleAuthKey;

// BL243 Phase 3 — generate ACL policy (no push)
function tailscaleACLGenerate() {
  const el = document.getElementById('tailscaleStatusPanel');
  if (el) el.innerHTML = `<span style="color:var(--text2);">${t('tailscale_loading') || 'Loading…'}</span>`;
  apiFetch('/api/tailscale/acl/generate', { method: 'POST' })
    .then(d => {
      if (!el) return;
      if (d.error) { el.innerHTML = `<span style="color:var(--error);">${escHtml(d.error)}</span>`; return; }
      el.innerHTML = `
        <div style="font-size:12px;color:var(--text2);margin-bottom:4px;">${t('tailscale_acl_generated_label') || 'Generated ACL policy (review before pushing):'}</div>
        <textarea readonly style="font-family:monospace;font-size:11px;width:100%;height:160px;background:var(--bg2);color:var(--text);border:1px solid var(--border);border-radius:4px;padding:4px 8px;resize:vertical;">${escHtml(d.policy||'')}</textarea>`;
    })
    .catch(e => { if (el) el.innerHTML = `<span style="color:var(--error);">${escHtml(String(e.message||e))}</span>`; });
}
window.tailscaleACLGenerate = tailscaleACLGenerate;

// BL243 Phase 3 — auto-generate ACL from config and push to headscale
function tailscaleACLGenerateAndPush() {
  const el = document.getElementById('tailscaleStatusPanel');
  if (el) el.innerHTML = `<span style="color:var(--text2);">${t('tailscale_loading') || 'Loading…'}</span>`;
  apiFetch('/api/tailscale/acl/push', { method: 'POST' })
    .then(d => {
      if (!el) return;
      if (d.error) { el.innerHTML = `<span style="color:var(--error);">${escHtml(d.error)}</span>`; return; }
      el.innerHTML = `
        <div style="color:var(--ok,#4caf50);font-size:13px;font-weight:600;margin-bottom:4px;">${t('tailscale_acl_pushed_label') || 'ACL pushed successfully.'}</div>
        ${d.generated_policy ? `<textarea readonly style="font-family:monospace;font-size:11px;width:100%;height:140px;background:var(--bg2);color:var(--text);border:1px solid var(--border);border-radius:4px;padding:4px 8px;resize:vertical;">${escHtml(d.generated_policy)}</textarea>` : ''}`;
    })
    .catch(e => { if (el) el.innerHTML = `<span style="color:var(--error);">${escHtml(String(e.message||e))}</span>`; });
}
window.tailscaleACLGenerateAndPush = tailscaleACLGenerateAndPush;

window.saveSecret = function() {
  const name = (document.getElementById('newSecretName')||{}).value || '';
  const value = (document.getElementById('newSecretValue')||{}).value || '';
  const tagsRaw = (document.getElementById('newSecretTags')||{}).value || '';
  const desc = (document.getElementById('newSecretDesc')||{}).value || '';
  const scopesRaw = (document.getElementById('newSecretScopes')||{}).value || '';
  if (!name) { showToast(t('secrets_name_required') || 'Name required', 'error'); return; }
  const tags = tagsRaw.split(',').map(t => t.trim()).filter(Boolean);
  const scopes = scopesRaw.split(',').map(s => s.trim()).filter(Boolean);
  apiFetch('/api/secrets', {
    method: 'POST',
    headers: {'Content-Type':'application/json'},
    body: JSON.stringify({ name, value, tags, scopes, description: desc })
  })
    .then(() => {
      showToast(t('secrets_saved') || 'Secret saved', 'success', 1500);
      ['newSecretName','newSecretValue','newSecretTags','newSecretDesc','newSecretScopes'].forEach(id => {
        const el = document.getElementById(id); if (el) el.value = '';
      });
      loadSecretsPanel();
    })
    .catch(e => showToast(String(e.message||e), 'error'));
};

window.deleteSecret = function(name) {
  apiFetch('/api/secrets/'+encodeURIComponent(name), { method: 'DELETE' })
    .then(() => { showToast(t('secrets_deleted') || 'Secret deleted', 'success', 1500); loadSecretsPanel(); })
    .catch(e => showToast(String(e.message||e), 'error'));
};

// BL238 — loadPluginsPanel: populates #pluginsPanelBody inside Settings → Plugins sub-tab.
function loadPluginsPanel() {
  const el = document.getElementById('pluginsPanelBody');
  if (!el) return;
  el.innerHTML = '<div style="text-align:center;padding:24px;color:var(--text2);font-size:13px;">Loading…</div>';
  apiFetch('/api/plugins').then(data => {
    const panel = document.getElementById('pluginsPanelBody');
    if (!panel) return;
    const native = (data && data.native) || [];
    const subs = (data && data.plugins) || [];
    const renderPlugin = (p, isNative) => {
      const on = !!p.enabled;
      const dot = `<span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:${on?'var(--success,#10b981)':'var(--text2)'};margin-right:6px;flex-shrink:0;"></span>`;
      const tag = isNative ? `<span style="opacity:0.55;font-size:10px;border:1px solid var(--text2);border-radius:3px;padding:0 4px;margin-left:4px;">native</span>` : '';
      const ver = p.version ? ` <span style="opacity:0.6;font-size:11px;">v${escHtml(p.version)}</span>` : '';
      const desc = p.description ? `<div style="opacity:0.6;font-size:11px;margin-top:2px;">${escHtml(p.description)}</div>` : '';
      const lastErr = p.last_error ? `<div style="color:var(--error);font-size:11px;margin-top:2px;" title="${escHtml(p.last_error)}">⚠ last error</div>` : '';
      // BL244 — Manifest v2.1 optional sections.
      const commCmds = (p.comm_commands && p.comm_commands.length)
        ? `<div style="font-size:11px;margin-top:3px;opacity:0.8;"><strong>${escHtml(t('plugin_detail_comm_commands'))}:</strong> ${p.comm_commands.map(c=>escHtml(c.name)).join(', ')}</div>` : '';
      const cliSubs = (p.cli_subcommands && p.cli_subcommands.length)
        ? `<div style="font-size:11px;margin-top:2px;opacity:0.8;"><strong>${escHtml(t('plugin_detail_cli_subcommands'))}:</strong> ${p.cli_subcommands.map(c=>escHtml(c.name)).join(', ')}</div>` : '';
      const mobileSec = (p.mobile && p.mobile.endpoints && p.mobile.endpoints.length)
        ? `<div style="font-size:11px;margin-top:2px;opacity:0.8;"><strong>${escHtml(t('plugin_detail_mobile'))}:</strong> ${p.mobile.endpoints.map(ep=>escHtml(ep.name)).join(', ')}</div>` : '';
      const sessInj = (p.session_injection && p.session_injection.types && p.session_injection.types.length)
        ? `<div style="font-size:11px;margin-top:2px;opacity:0.8;"><strong>${escHtml(t('plugin_detail_session_injection'))}:</strong> ${p.session_injection.types.map(ty=>escHtml(ty)).join(', ')}</div>` : '';
      const acts = isNative ? '' : `<button class="btn-icon" style="font-size:11px;padding:2px 8px;white-space:nowrap;" onclick="pluginAction('${escHtml(p.name)}','${on?'disable':'enable'}')">${on?'Disable':'Enable'}</button>`;
      return `<div style="padding:8px 0;border-top:1px solid var(--border);display:flex;align-items:flex-start;gap:8px;">
        <div style="flex:1;">${dot}<strong>${escHtml(p.name)}</strong>${tag}${ver}${desc}${lastErr}${commCmds}${cliSubs}${mobileSec}${sessInj}</div>
        ${acts}
      </div>`;
    };
    panel.innerHTML = `<button class="btn-primary" style="font-size:12px;padding:6px 16px;margin-bottom:12px;" onclick="pluginReload()">Reload plugins</button>`
      + (native.length ? `<div style="font-size:11px;font-weight:600;text-transform:uppercase;letter-spacing:0.5px;opacity:0.6;margin-bottom:4px;">Native</div>${native.map(p=>renderPlugin(p,true)).join('')}` : '')
      + `<div style="font-size:11px;font-weight:600;text-transform:uppercase;letter-spacing:0.5px;opacity:0.6;margin-top:12px;margin-bottom:4px;">Subprocess</div>`
      + (subs.length ? subs.map(p=>renderPlugin(p,false)).join('') : '<div style="opacity:0.7;">no subprocess plugins installed</div>');
  }).catch(err => {
    const panel = document.getElementById('pluginsPanelBody');
    if (panel) panel.innerHTML = `<div style="color:var(--error);padding:16px;">${escHtml(String(err.message||err))}</div>`;
  });
}
window.loadPluginsPanel = loadPluginsPanel;

// BL238 — renderPluginsView redirects to Settings → Plugins sub-tab.
function renderPluginsView() {
  _settingsTab = 'plugins';
  localStorage.setItem('cs_settings_tab', 'plugins');
  navigate('settings');
}
window.renderPluginsView = renderPluginsView;
window.pluginAction = function(name, action) {
  apiFetch(`/api/plugins/${encodeURIComponent(name)}/${action}`, { method: 'POST' })
    .then(() => { showToast(`Plugin ${escHtml(name)} ${action}d`, 'success', 2000); loadPluginsPanel(); })
    .catch(e => showToast(String(e.message||e), 'error'));
};
window.pluginReload = function() {
  apiFetch('/api/plugins/reload', { method: 'POST' })
    .then(d => { showToast(`Reloaded: ${d.count||0} plugin(s)`, 'success', 2000); loadPluginsPanel(); })
    .catch(e => showToast(String(e.message||e), 'error'));
};

// ── BL220-G3 Routing rules editor ────────────────────────────────────────────

// BL238 — loadRoutingPanel: populates #routingPanelBody inside Settings → Routing sub-tab.
function loadRoutingPanel() {
  const el = document.getElementById('routingPanelBody');
  if (!el) return;
  el.innerHTML = '<div style="text-align:center;padding:24px;color:var(--text2);font-size:13px;">Loading…</div>';
  apiFetch('/api/routing-rules').then(data => {
    const panel = document.getElementById('routingPanelBody');
    if (!panel) return;
    const rules = (data && data.rules) || [];
    const inp = (id, ph) => `<input id="${id}" type="text" placeholder="${ph}" style="width:100%;box-sizing:border-box;margin-bottom:6px;font-size:13px;padding:6px 8px;background:var(--bg);border:1px solid var(--border);border-radius:6px;color:var(--text);">`;
    panel.innerHTML = `
      <div style="background:var(--bg2);border:1px solid var(--border);border-radius:8px;padding:10px 12px;margin-bottom:10px;">
        <div style="font-size:11px;font-weight:600;text-transform:uppercase;letter-spacing:0.5px;opacity:0.6;margin-bottom:8px;">Add rule</div>
        ${inp('routingPattern','Pattern (regex)')}${inp('routingBackend','Backend name')}${inp('routingDesc','Description (optional)')}
        <button class="btn-primary" style="font-size:12px;padding:6px 16px;" onclick="routingAddRule()">Add</button>
      </div>
      <div style="background:var(--bg2);border:1px solid var(--border);border-radius:8px;padding:10px 12px;margin-bottom:10px;">
        <div style="font-size:11px;font-weight:600;text-transform:uppercase;letter-spacing:0.5px;opacity:0.6;margin-bottom:8px;">Test routing</div>
        <div style="display:flex;gap:6px;">
          <input id="routingTestTask" type="text" placeholder="Task text…" style="flex:1;font-size:13px;padding:6px 8px;background:var(--bg);border:1px solid var(--border);border-radius:6px;color:var(--text);">
          <button class="btn-primary" style="font-size:12px;padding:6px 12px;" onclick="routingTest()">Test</button>
        </div>
        <div id="routingTestResult" style="margin-top:6px;font-size:12px;color:var(--text2);"></div>
      </div>
      <div style="font-size:11px;font-weight:600;text-transform:uppercase;letter-spacing:0.5px;opacity:0.6;margin-bottom:6px;">Rules (${rules.length})</div>
      ${rules.length === 0
        ? '<div style="opacity:0.7;padding:4px 0;">no rules — tasks route to the default backend</div>'
        : rules.map((r, i) => `<div style="padding:8px 0;border-top:1px solid var(--border);display:flex;align-items:flex-start;gap:8px;">
            <div style="flex:1;">
              <code style="font-size:12px;">${escHtml(r.pattern||'')}</code>
              <span style="margin-left:6px;font-size:11px;background:rgba(96,165,250,0.18);color:var(--accent);padding:1px 6px;border-radius:4px;">${escHtml(r.backend||'')}</span>
              ${r.description ? `<div style="opacity:0.6;font-size:11px;margin-top:2px;">${escHtml(r.description)}</div>` : ''}
            </div>
            <button class="btn-icon" style="font-size:13px;color:var(--error);" onclick="routingDeleteRule(${i})">&times;</button>
          </div>`).join('')}`;
    panel._rules = rules;
  }).catch(err => {
    const panel = document.getElementById('routingPanelBody');
    if (panel) panel.innerHTML = `<div style="color:var(--error);padding:16px;">${escHtml(String(err.message||err))}</div>`;
  });
}
window.loadRoutingPanel = loadRoutingPanel;

// BL247 — renderRoutingView redirects to Settings → Comms tab (routing is now a card there).
function renderRoutingView() {
  _settingsTab = 'comms';
  localStorage.setItem('cs_settings_tab', 'comms');
  navigate('settings');
}
window.renderRoutingView = renderRoutingView;
window.routingAddRule = function() {
  const pattern = (document.getElementById('routingPattern')||{}).value||'';
  const backend = (document.getElementById('routingBackend')||{}).value||'';
  const desc = (document.getElementById('routingDesc')||{}).value||'';
  if (!pattern || !backend) { showToast('Pattern and backend are required', 'error'); return; }
  const el = document.getElementById('routingPanelBody');
  const rules = [...((el&&el._rules)||[]), { pattern, backend, description: desc }];
  apiFetch('/api/routing-rules', { method: 'POST', body: JSON.stringify({ rules }) })
    .then(() => { showToast('Rule added', 'success', 2000); loadRoutingPanel(); })
    .catch(e => showToast(String(e.message||e), 'error'));
};
window.routingDeleteRule = function(idx) {
  const el = document.getElementById('routingPanelBody');
  const rules = ((el&&el._rules)||[]).filter((_,i)=>i!==idx);
  apiFetch('/api/routing-rules', { method: 'POST', body: JSON.stringify({ rules }) })
    .then(() => { showToast('Rule deleted', 'success', 2000); loadRoutingPanel(); })
    .catch(e => showToast(String(e.message||e), 'error'));
};
window.routingTest = function() {
  const task = (document.getElementById('routingTestTask')||{}).value||'';
  if (!task) return;
  const res = document.getElementById('routingTestResult');
  if (res) res.textContent = 'testing…';
  apiFetch('/api/routing-rules/test', { method: 'POST', body: JSON.stringify({ task }) })
    .then(d => { if (res) res.innerHTML = d.matched
      ? `<span style="color:var(--success,#10b981);">✓ routes to <strong>${escHtml(d.backend)}</strong></span>`
      : '<span style="opacity:0.7;">no match — uses default backend</span>'; })
    .catch(e => { if (res) res.textContent = 'error: ' + String(e.message||e); });
};

// ── BL220-G15 Orchestrator panel ──────────────────────────────────────────────

// BL238 — loadOrchestratorPanel: populates #orchestratorPanelBody inside Settings → Orchestrator sub-tab.
function loadOrchestratorPanel() {
  const el = document.getElementById('orchestratorPanelBody');
  if (!el) return;
  // BL261 v6.7.7 — wrap all states in the standard card-content inset.
  el.innerHTML = '<div style="padding:6px 12px;text-align:center;color:var(--text2);font-size:13px;">Loading…</div>';
  apiFetch('/api/orchestrator/graphs').then(data => {
    const panel = document.getElementById('orchestratorPanelBody');
    if (!panel) return;
    const graphs = (data && data.graphs) || [];
    const statusColor = { pending:'var(--text2)', running:'var(--accent,#6366f1)', done:'var(--success,#10b981)', failed:'var(--error,#ef4444)', cancelled:'var(--warning,#f59e0b)' };
    panel.innerHTML = `<div style="padding:6px 12px;">
      <div style="background:var(--bg2);border:1px solid var(--border);border-radius:8px;padding:10px 12px;margin-bottom:10px;">
        <div style="font-size:11px;font-weight:600;text-transform:uppercase;letter-spacing:0.5px;opacity:0.6;margin-bottom:8px;">New Automaton graph</div>
        <input id="orchTitle" type="text" placeholder="Title (required)" style="width:100%;box-sizing:border-box;margin-bottom:6px;font-size:13px;padding:6px 8px;background:var(--bg);border:1px solid var(--border);border-radius:6px;color:var(--text);">
        <input id="orchDir" type="text" placeholder="Project directory (optional)" style="width:100%;box-sizing:border-box;margin-bottom:8px;font-size:13px;padding:6px 8px;background:var(--bg);border:1px solid var(--border);border-radius:6px;color:var(--text);">
        <button class="btn-primary" style="font-size:12px;padding:6px 16px;" onclick="orchCreateGraph()">Create</button>
      </div>
      <div style="font-size:11px;font-weight:600;text-transform:uppercase;letter-spacing:0.5px;opacity:0.6;margin-bottom:6px;">
        Graphs (${graphs.length})
          <span class="live-dot" title="Auto-refreshing every 8s" style="display:inline-block;width:7px;height:7px;border-radius:50%;background:var(--success,#10b981);margin-left:6px;animation:livePulse 2s ease-in-out infinite;vertical-align:middle;"></span>
          <span style="opacity:0.5;font-weight:400;font-size:10px;margin-left:4px;">live</span>
      </div>
      ${graphs.length === 0
        ? '<div style="opacity:0.7;padding:4px 0;">no graphs — create one above</div>'
        : graphs.map(g => {
            const color = statusColor[g.status||'pending'] || 'var(--text2)';
            const prdCount = (g.prd_ids||g.nodes||[]).length;
            const safeId = JSON.stringify(g.id||'');
            return `<div style="padding:8px 0;border-top:1px solid var(--border);display:flex;align-items:flex-start;gap:8px;">
              <div style="flex:1;">
                <div style="display:flex;align-items:center;gap:6px;">
                  <span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:${color};flex-shrink:0;"></span>
                  <strong>${escHtml(g.title||g.id||'untitled')}</strong>
                  <span style="opacity:0.6;font-size:11px;">${escHtml(g.status||'pending')}</span>
                </div>
                ${prdCount ? `<div style="opacity:0.6;font-size:11px;margin-top:2px;">${prdCount} automat${prdCount===1?'on':'a'}</div>` : ''}
                <div style="opacity:0.5;font-size:10px;font-family:monospace;">${escHtml(g.id||'')}</div>
              </div>
              <div style="display:flex;gap:4px;align-items:center;">
                <button class="btn-icon" style="font-size:11px;padding:2px 8px;" onclick='orchRunGraph(${safeId})' title="Run">▶</button>
                <button class="btn-icon" style="font-size:11px;padding:2px 8px;color:var(--error);" onclick='orchDeleteGraph(${safeId})' title="Cancel">&times;</button>
              </div>
            </div>`;
          }).join('')}</div>`;
  }).catch(err => {
    const panel = document.getElementById('orchestratorPanelBody');
    if (panel) panel.innerHTML = `<div style="padding:6px 12px;"><div style="color:var(--error);">${escHtml(String(err.message||'Orchestrator unavailable — set orchestrator.enabled: true'))}</div></div>`;
  });
}
window.loadOrchestratorPanel = loadOrchestratorPanel;

// ── BL221 (v6.2.0) Phase 3 — Settings → Automata tab ─────────────────────────

function loadAutomataSettingsPanel() {
  const scanEl = document.getElementById('automataSettingsScanPanel');
  const aEl = document.getElementById('automataSettingsAutonomousPanel');
  if (!scanEl && !aEl) return;

  // Load scan config
  if (scanEl) {
    apiFetch('/api/autonomous/scan/config').then(sc => {
      if (!sc) { scanEl.innerHTML = '<em style="color:var(--text2);">autonomous disabled</em>'; return; }
      const toggleRow = (key, label, val) => `
        <div class="settings-row" style="justify-content:space-between;">
          <div class="settings-label">${escHtml(label)}</div>
          <label class="toggle"><input type="checkbox" ${val?'checked':''} onchange="saveAutomataScanField('${key}',this.checked)"><span class="slider"></span></label>
        </div>`;
      const selectRow = (key, label, val, opts) => `
        <div class="settings-row" style="justify-content:space-between;">
          <div class="settings-label">${escHtml(label)}</div>
          <select class="form-input" style="width:auto;font-size:12px;" onchange="saveAutomataScanField('${key}',this.value)">
            ${opts.map(o=>`<option value="${o}" ${val===o?'selected':''}>${escHtml(o)}</option>`).join('')}
          </select>
        </div>`;
      const numRow = (key, label, val) => `
        <div class="settings-row" style="justify-content:space-between;">
          <div class="settings-label">${escHtml(label)}</div>
          <input type="number" min="0" value="${val||0}" style="width:80px;font-size:12px;" class="form-input"
            onchange="saveAutomataScanField('${key}',+this.value)">
        </div>`;
      scanEl.innerHTML = `
        <div class="settings-subsection">
          ${toggleRow('enabled', t('scan_config_enabled')||'Scan enabled', sc.enabled)}
          ${toggleRow('sast_enabled', t('scan_config_sast')||'SAST scanner', sc.sast_enabled)}
          ${toggleRow('secrets_enabled', t('scan_config_secrets')||'Secrets scanner', sc.secrets_enabled)}
          ${toggleRow('deps_enabled', t('scan_config_deps')||'Dependency scanner', sc.deps_enabled)}
          ${selectRow('fail_on_severity', t('scan_config_fail_on')||'Fail on severity', sc.fail_on_severity||'error', ['info','warning','error','critical'])}
          ${numRow('max_findings', 'Max findings (0=unlimited)', sc.max_findings)}
          ${toggleRow('rules_grader_enabled', t('scan_config_grader')||'LLM rules grader', sc.rules_grader_enabled)}
          ${toggleRow('fix_loop_enabled', t('scan_config_fix_loop')||'Auto-fix loop', sc.fix_loop_enabled)}
          ${numRow('fix_loop_max_retries', t('scan_config_fix_retries')||'Fix loop max retries', sc.fix_loop_max_retries)}
        </div>`;
    }).catch(() => {
      if (scanEl) scanEl.innerHTML = '<em style="color:var(--text2);">not available</em>';
    });
  }

  // Load autonomous general config
  if (aEl) {
    apiFetch('/api/autonomous/config').then(ac => {
      if (!ac) { aEl.innerHTML = '<em style="color:var(--text2);">autonomous disabled</em>'; return; }
      aEl.innerHTML = `
        <div class="settings-row" style="justify-content:space-between;">
          <div class="settings-label">Poll interval (s)</div>
          <input type="number" min="5" value="${ac.poll_interval_seconds||30}" style="width:80px;font-size:12px;" class="form-input"
            onchange="saveGeneralField('autonomous.poll_interval_seconds',+this.value)">
        </div>
        <div class="settings-row" style="justify-content:space-between;">
          <div class="settings-label">Max parallel tasks</div>
          <input type="number" min="1" value="${ac.max_parallel_tasks||3}" style="width:80px;font-size:12px;" class="form-input"
            onchange="saveGeneralField('autonomous.max_parallel_tasks',+this.value)">
        </div>
        <div class="settings-row" style="justify-content:space-between;">
          <div class="settings-label">Auto-fix retries</div>
          <input type="number" min="0" value="${ac.auto_fix_retries||0}" style="width:80px;font-size:12px;" class="form-input"
            onchange="saveGeneralField('autonomous.auto_fix_retries',+this.value)">
        </div>`;
    }).catch(() => {
      if (aEl) aEl.innerHTML = '<em style="color:var(--text2);">not available</em>';
    });
  }
}
window.loadAutomataSettingsPanel = loadAutomataSettingsPanel;

// ── BL303 S2 — Guardrail Library + Profiles panel (Settings → Automata) ──

function loadGuardrailLibraryPanel(el) {
  el.innerHTML = `<div style="padding:6px 12px;color:var(--text2);">${escHtml(t('state_loading')||'Loading…')}</div>`;
  apiFetch('/api/autonomous/guardrails').then(items => {
    if (!items || items.length === 0) {
      el.innerHTML = `<div style="padding:6px 12px;color:var(--text2);font-size:12px;">${escHtml(t('guardrail_library_empty')||'No guardrails registered')}</div>`;
      return;
    }
    const rows = items.map(g => `
      <div style="display:flex;gap:8px;align-items:baseline;padding:3px 12px;font-size:12px;">
        <span style="font-weight:600;flex:0 0 auto;width:160px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;" title="${escHtml(g.name)}">${escHtml(g.name)}</span>
        <span style="background:var(--accent2);color:#fff;font-size:10px;padding:1px 6px;border-radius:8px;flex:0 0 auto;">${escHtml(g.type||'scan')}</span>
        <span style="color:var(--text2);flex:1;">${escHtml(g.description||'')}</span>
      </div>`).join('');
    el.innerHTML = `<div style="padding:6px 0;">${rows}</div>`;
  }).catch(() => {
    el.innerHTML = `<div style="padding:6px 12px;color:var(--error);font-size:12px;">Failed to load guardrail library</div>`;
  });
}

function loadGuardrailProfilesPanel() {
  const panel = document.getElementById('automataGuardrailProfilesPanel');
  if (!panel) return;
  panel.innerHTML = `<div style="padding:6px 12px;color:var(--text2);">${escHtml(t('state_loading')||'Loading…')}</div>`;

  // Also refresh the library listing inside the scan section
  const libEl = document.getElementById('automataSettingsScanPanel');
  if (libEl) loadGuardrailLibraryPanel(libEl);

  apiFetch('/api/autonomous/guardrail_profiles').then(profiles => {
    const addBtn = `<button class="btn-primary" style="font-size:12px;padding:4px 10px;" onclick="guardrailProfileOpenCreate()">${escHtml(t('guardrail_profile_create')||'New Profile')}</button>`;
    if (!profiles || profiles.length === 0) {
      panel.innerHTML = `<div style="padding:6px 12px;"><div style="text-align:center;padding:16px 8px;color:var(--text2);font-size:12px;">
        ${escHtml(t('guardrail_profile_empty')||'No profiles yet')}
        <div style="margin-top:10px;">${addBtn}</div>
      </div></div>`;
      return;
    }
    const rows = profiles.map(p => {
      const tags = (p.guardrails||[]).map(g => `<span style="background:var(--card-bg);border:1px solid var(--border);border-radius:4px;font-size:10px;padding:1px 5px;margin-right:3px;">${escHtml(g)}</span>`).join('');
      const idJ = escHtml(JSON.stringify(p.id));
      return `<div style="display:flex;align-items:center;gap:8px;padding:6px 12px;border-bottom:1px solid var(--border);font-size:12px;">
        <div style="flex:1;min-width:0;">
          <div style="font-weight:600;">${escHtml(p.name)}</div>
          ${p.description ? `<div style="color:var(--text2);font-size:11px;">${escHtml(p.description)}</div>` : ''}
          <div style="margin-top:3px;">${tags||'<span style="color:var(--text2);font-size:11px;">(no guardrails)</span>'}</div>
        </div>
        <button class="btn-secondary" style="font-size:11px;padding:2px 8px;" onclick="guardrailProfileDelete(${idJ})">&times;</button>
      </div>`;
    }).join('');
    panel.innerHTML = `<div style="padding:6px 0;">${rows}</div>
      <div style="padding:6px 12px;">${addBtn}</div>`;
  }).catch(() => {
    panel.innerHTML = `<div style="padding:6px 12px;color:var(--error);font-size:12px;">Failed to load guardrail profiles</div>`;
  });
}
window.loadGuardrailProfilesPanel = loadGuardrailProfilesPanel;

function guardrailProfileOpenCreate() {
  const name = prompt(t('guardrail_profile_name')||'Profile name');
  if (!name) return;
  const csv = prompt(t('guardrail_profile_guardrails')||'Guardrails (comma-separated)', '');
  const guardrails = (csv||'').split(',').map(s=>s.trim()).filter(Boolean);
  apiFetch('/api/autonomous/guardrail_profiles', {
    method: 'POST',
    headers: {'Content-Type':'application/json'},
    body: JSON.stringify({name, guardrails})
  }).then(() => {
    loadGuardrailProfilesPanel();
  }).catch(e => showError('Create profile failed: ' + e));
}
window.guardrailProfileOpenCreate = guardrailProfileOpenCreate;

function guardrailProfileDelete(id) {
  if (!confirm(t('guardrail_profile_delete_confirm')||'Delete this guardrail profile?')) return;
  apiFetch('/api/autonomous/guardrail_profiles/' + id, {method: 'DELETE'}).then(() => {
    loadGuardrailProfilesPanel();
  }).catch(e => showError('Delete profile failed: ' + e));
}
window.guardrailProfileDelete = guardrailProfileDelete;

// ── BL255 v6.7.0 — Skill Registries panel (Settings → Automata) ──────────

function loadSkillsPanel() {
  const panel = document.getElementById('automataSettingsSkillsPanel');
  if (!panel) return;
  // BL261 v6.7.7 — wrap all states in the standard card-content inset.
  panel.innerHTML = `<div style="padding:6px 12px;color:var(--text2);">${escHtml(t('state_loading')||'Loading…')}</div>`;
  apiFetch('/api/skills/registries').then(data => {
    _renderSkillsRegistries(panel, (data && data.registries) || []);
  }).catch(err => {
    panel.innerHTML = `<div style="padding:6px 12px;color:var(--error);">Failed to load skill registries: ${escHtml(String(err))}</div>`;
  });
}
window.loadSkillsPanel = loadSkillsPanel;

function _renderSkillsRegistries(panel, registries) {
  const addDefaultBtn = `<button class="btn-secondary" style="font-size:12px;padding:4px 10px;" onclick="skillsAddDefault()" title="${escHtml(t('skills_add_default_title')||'Idempotently add the built-in PAI registry')}">${escHtml(t('skills_btn_add_default')||'+ Add default (PAI)')}</button>`;
  const addBtn = `<button class="btn-primary" style="font-size:12px;padding:4px 10px;" onclick="skillsOpenAddModal()" title="${escHtml(t('skills_btn_add_title')||'Add a new skill registry')}">${escHtml(t('skills_btn_add')||'+ Add registry')}</button>`;

  if (!registries || registries.length === 0) {
    // BL261 v6.7.7 — wrap empty state in standard card-content inset.
    panel.innerHTML = `<div style="padding:6px 12px;"><div style="text-align:center;padding:16px 8px;color:var(--text2);font-size:12px;">
      ${escHtml(t('skills_empty')||'No skill registries configured. Add the built-in PAI registry to get started.')}
      <div style="margin-top:10px;display:flex;gap:6px;justify-content:center;">${addDefaultBtn}${addBtn}</div>
    </div></div>`;
    return;
  }

  const rows = registries.map(r => {
    const ts = r.last_synced_at && new Date(r.last_synced_at).getFullYear() > 2000
      ? new Date(r.last_synced_at).toLocaleString()
      : (t('skills_never_synced')||'never synced');
    const errBadge = r.last_sync_error
      ? `<span style="color:var(--error);font-size:10px;margin-left:4px;" title="${escHtml(r.last_sync_error)}">⚠ ${escHtml(t('skills_last_error')||'last error')}</span>`
      : '';
    const builtin = r.is_builtin ? `<span style="font-size:9px;background:var(--accent2);color:#fff;padding:1px 6px;border-radius:8px;margin-left:4px;">${escHtml(t('skills_badge_builtin')||'built-in')}</span>` : '';
    const enabled = r.enabled !== false;
    const statusDot = enabled
      ? `<span style="color:var(--success);" title="${escHtml(t('skills_enabled')||'enabled')}">●</span>`
      : `<span style="color:var(--text2);" title="${escHtml(t('skills_disabled')||'disabled')}">○</span>`;
    // BL255-followup v6.7.1 — escHtml the JSON string so embedded `"` becomes
    // &quot; and the inline onclick handler stays valid (same fix pattern as
    // renderPRDActions in v5.26.3).
    const idJ = escHtml(JSON.stringify(r.name));
    return `<div class="settings-row" style="flex-direction:column;align-items:stretch;padding:8px;border-bottom:1px solid var(--border);">
      <div style="display:flex;align-items:center;gap:6px;flex-wrap:wrap;">
        ${statusDot}
        <strong style="font-size:13px;">${escHtml(r.name)}</strong>${builtin}
        <span style="font-size:11px;color:var(--text2);">${escHtml(r.url||'')}</span>
        ${errBadge}
      </div>
      <div style="font-size:10px;color:var(--text2);margin:2px 0 6px 16px;">${escHtml(t('skills_branch')||'branch')}: <code>${escHtml(r.branch||'main')}</code> · ${escHtml(t('skills_synced_label')||'synced')}: ${escHtml(ts)}${r.description ? ' · ' + escHtml(r.description) : ''}</div>
      <div style="display:flex;flex-wrap:wrap;gap:4px;margin-left:16px;">
        <button class="btn-secondary" style="font-size:11px;padding:3px 8px;" onclick="skillsConnect(${idJ})">${escHtml(t('skills_btn_connect')||'Connect')}</button>
        <button class="btn-secondary" style="font-size:11px;padding:3px 8px;" onclick="skillsBrowse(${idJ})">${escHtml(t('skills_btn_browse')||'Browse')}</button>
        <button class="btn-secondary" style="font-size:11px;padding:3px 8px;" onclick="skillsOpenEditModal(${idJ})">${escHtml(t('skills_btn_edit')||'Edit')}</button>
        <button class="btn-secondary" style="font-size:11px;padding:3px 8px;color:var(--error);border-color:var(--error);" onclick="skillsDeleteRegistry(${idJ})">${escHtml(t('skills_btn_delete')||'Delete')}</button>
      </div>
    </div>`;
  }).join('');

  // Synced skills summary
  const syncedSection = `<div id="skillsSyncedSection" style="margin-top:10px;padding-top:10px;border-top:1px solid var(--border);">
    <div style="font-size:12px;font-weight:600;color:var(--text2);margin-bottom:4px;">${escHtml(t('skills_synced_section')||'Synced skills')}</div>
    <div id="skillsSyncedList" style="font-size:11px;color:var(--text2);">${escHtml(t('state_loading')||'Loading…')}</div>
  </div>`;

  // BL261 v6.7.7 — wrap populated state in standard card-content inset.
  panel.innerHTML = `<div style="padding:6px 12px;"><div>${rows}</div>
    <div style="display:flex;gap:6px;margin-top:8px;">${addDefaultBtn}${addBtn}</div>
    ${syncedSection}</div>`;
  loadSyncedSkillsList();
}

function loadSyncedSkillsList() {
  const el = document.getElementById('skillsSyncedList');
  if (!el) return;
  apiFetch('/api/skills').then(data => {
    const synced = (data && data.skills) || [];
    if (synced.length === 0) {
      el.innerHTML = `<em>${escHtml(t('skills_no_synced')||'No skills synced yet. Use the Browse button on a registry to select skills to sync.')}</em>`;
      return;
    }
    el.innerHTML = synced.map(s => {
      const m = s.manifest || {};
      const tags = (m.tags || []).map(t => `<span style="background:rgba(96,165,250,0.1);padding:1px 4px;border-radius:3px;margin-right:2px;font-size:9px;">${escHtml(t)}</span>`).join('');
      return `<div style="padding:3px 0;border-bottom:1px solid var(--border);">
        <div><strong>${escHtml(s.name)}</strong> <span style="opacity:0.6;font-size:10px;">${escHtml(s.registry)}</span> ${tags}</div>
        ${m.description ? `<div style="opacity:0.7;font-size:10px;">${escHtml(m.description)}</div>` : ''}
      </div>`;
    }).join('');
  }).catch(() => { el.textContent = t('state_failed_to_load')||'Failed to load'; });
}

window.skillsAddDefault = function() {
  apiFetch('/api/skills/registries/add-default', { method: 'POST' })
    .then(() => { showToast(t('skills_added_default')||'Default registry added', 'success', 2000); loadSkillsPanel(); })
    .catch(e => showToast(String(e.message||e), 'error', 3000));
};

window.skillsConnect = function(name) {
  showToast(t('skills_connecting')||'Connecting to registry…', 'info', 2000);
  apiFetch('/api/skills/registries/' + encodeURIComponent(name) + '/connect', { method: 'POST' })
    .then(data => {
      const n = (data && data.available && data.available.length) || 0;
      showToast((t('skills_connected')||'Connected; available skills:') + ' ' + n, 'success', 3000);
      loadSkillsPanel();
    })
    .catch(e => showToast((t('skills_connect_failed')||'Connect failed') + ': ' + String(e.message||e), 'error', 4000));
};

window.skillsBrowse = function(name) {
  apiFetch('/api/skills/registries/' + encodeURIComponent(name) + '/available')
    .then(data => _skillsRenderBrowseModal(name, (data && data.available) || []))
    .catch(e => showToast(String(e.message||e), 'error', 3000));
};

function _skillsRenderBrowseModal(registryName, available) {
  if (!available || available.length === 0) {
    showModal({
      title: t('skills_browse_empty_title') || 'No available skills',
      body: `<div style="font-size:12px;color:var(--text2);">${escHtml(t('skills_browse_empty_body')||'No skills found in this registry. Use the Connect button first to populate the cache.')}</div>`,
      confirmLabel: t('btn_close')||'Close',
      cancelLabel: null,
      onConfirm: () => {},
    });
    return;
  }
  const rows = available.map((s, i) => {
    const m = s.manifest || {};
    const desc = m.description ? `<div style="font-size:10px;color:var(--text2);">${escHtml(m.description)}</div>` : '';
    const reqs = (m.requires || []).length ? `<div style="font-size:10px;color:var(--accent);">requires: ${(m.requires||[]).map(escHtml).join(', ')}</div>` : '';
    const checked = s.synced ? 'checked' : '';
    const mark = s.synced ? '<span style="color:var(--success);font-size:10px;">✓ synced</span>' : '';
    return `<div style="padding:4px 6px;border-bottom:1px solid var(--border);display:flex;gap:6px;align-items:flex-start;">
      <input type="checkbox" id="skillsBrowseSel_${i}" data-skill="${escHtml(s.name)}" ${checked} style="margin-top:2px;">
      <div style="flex:1;min-width:0;">
        <div style="font-size:12px;"><strong>${escHtml(s.name)}</strong> ${mark}</div>
        ${desc}${reqs}
      </div>
    </div>`;
  }).join('');
  showModal({
    title: (t('skills_browse_title')||'Available skills in') + ' ' + registryName,
    body: `<div style="max-height:400px;overflow-y:auto;">${rows}</div>
      <div style="margin-top:8px;display:flex;gap:6px;justify-content:flex-end;">
        <button class="btn-secondary" style="font-size:11px;padding:4px 10px;" onclick="_skillsBrowseSelectAll(true)">${escHtml(t('skills_select_all')||'Select all')}</button>
        <button class="btn-secondary" style="font-size:11px;padding:4px 10px;" onclick="_skillsBrowseSelectAll(false)">${escHtml(t('skills_select_none')||'None')}</button>
        <button class="btn-primary" style="font-size:11px;padding:4px 10px;" onclick="_skillsBrowseSyncSelected(${escHtml(JSON.stringify(registryName))})">${escHtml(t('skills_btn_sync_selected')||'Sync selected')}</button>
      </div>`,
    confirmLabel: t('btn_close')||'Close',
    cancelLabel: null,
    onConfirm: () => {},
  });
}

window._skillsBrowseSelectAll = function(state) {
  document.querySelectorAll('input[id^="skillsBrowseSel_"]').forEach(cb => { cb.checked = !!state; });
};

window._skillsBrowseSyncSelected = function(registryName) {
  const selected = [];
  document.querySelectorAll('input[id^="skillsBrowseSel_"]:checked').forEach(cb => {
    const n = cb.getAttribute('data-skill');
    if (n) selected.push(n);
  });
  if (selected.length === 0) {
    showToast(t('skills_no_selection')||'No skills selected', 'warning', 2000);
    return;
  }
  apiFetch('/api/skills/registries/' + encodeURIComponent(registryName) + '/sync', {
    method: 'POST',
    body: JSON.stringify({ skills: selected }),
  }).then(data => {
    const n = (data && data.synced && data.synced.length) || 0;
    showToast((t('skills_synced')||'Synced') + ' ' + n + ' ' + (t('skills_count_skills')||'skill(s)'), 'success', 3000);
    document.getElementById('genericModal')?.remove();
    loadSkillsPanel();
  }).catch(e => showToast(String(e.message||e), 'error', 4000));
};

window.skillsOpenAddModal = function() {
  showModal({
    title: t('skills_add_modal_title')||'Add skill registry',
    body: `<div style="display:flex;flex-direction:column;gap:8px;">
      <input id="skillsAddName" type="text" class="form-input" placeholder="${escHtml(t('skills_field_name')||'Registry name (e.g. my-skills)')}" style="font-size:13px;">
      <input id="skillsAddURL" type="text" class="form-input" placeholder="${escHtml(t('skills_field_url')||'Git URL')}" style="font-size:13px;">
      <input id="skillsAddBranch" type="text" class="form-input" value="main" placeholder="${escHtml(t('skills_field_branch')||'Branch')}" style="font-size:13px;">
      <input id="skillsAddAuth" type="text" class="form-input" placeholder="${escHtml(t('skills_field_auth')||'Auth ${secret:name} (private repos only)')}" style="font-size:13px;">
      <input id="skillsAddDesc" type="text" class="form-input" placeholder="${escHtml(t('skills_field_desc')||'Description (optional)')}" style="font-size:13px;">
      <div style="font-size:10px;color:var(--text2);">${escHtml(t('skills_secrets_rule_hint')||'Per the Secrets-Store Rule, auth tokens for private repos must be ${secret:name} references — plaintext is rejected.')}</div>
    </div>`,
    confirmLabel: t('btn_create')||'Create',
    onConfirm: () => {
      const body = {
        name: document.getElementById('skillsAddName').value.trim(),
        url: document.getElementById('skillsAddURL').value.trim(),
        branch: document.getElementById('skillsAddBranch').value.trim() || 'main',
        auth_secret_ref: document.getElementById('skillsAddAuth').value.trim(),
        description: document.getElementById('skillsAddDesc').value.trim(),
        kind: 'git',
        enabled: true,
      };
      if (!body.name || !body.url) { showToast(t('skills_required')||'Name and URL required', 'error'); return false; }
      apiFetch('/api/skills/registries', { method: 'POST', body: JSON.stringify(body) })
        .then(() => { showToast(t('skills_added')||'Registry added', 'success', 2000); loadSkillsPanel(); })
        .catch(e => showToast(String(e.message||e), 'error', 3000));
    },
  });
};

window.skillsOpenEditModal = function(name) {
  apiFetch('/api/skills/registries/' + encodeURIComponent(name)).then(reg => {
    showModal({
      title: (t('skills_edit_modal_title')||'Edit registry') + ' ' + name,
      body: `<div style="display:flex;flex-direction:column;gap:8px;">
        <input id="skillsEditURL" type="text" class="form-input" value="${escHtml(reg.url||'')}" placeholder="${escHtml(t('skills_field_url')||'Git URL')}" style="font-size:13px;">
        <input id="skillsEditBranch" type="text" class="form-input" value="${escHtml(reg.branch||'main')}" placeholder="${escHtml(t('skills_field_branch')||'Branch')}" style="font-size:13px;">
        <input id="skillsEditAuth" type="text" class="form-input" value="${escHtml(reg.auth_secret_ref||'')}" placeholder="${escHtml(t('skills_field_auth')||'Auth ${secret:name}')}" style="font-size:13px;">
        <input id="skillsEditDesc" type="text" class="form-input" value="${escHtml(reg.description||'')}" placeholder="${escHtml(t('skills_field_desc')||'Description')}" style="font-size:13px;">
      </div>`,
      confirmLabel: t('btn_save')||'Save',
      onConfirm: () => {
        const body = {
          name: name,
          url: document.getElementById('skillsEditURL').value.trim(),
          branch: document.getElementById('skillsEditBranch').value.trim(),
          auth_secret_ref: document.getElementById('skillsEditAuth').value.trim(),
          description: document.getElementById('skillsEditDesc').value.trim(),
          kind: 'git',
          enabled: true,
        };
        apiFetch('/api/skills/registries/' + encodeURIComponent(name), { method: 'PUT', body: JSON.stringify(body) })
          .then(() => { showToast(t('skills_updated')||'Registry updated', 'success', 2000); loadSkillsPanel(); })
          .catch(e => showToast(String(e.message||e), 'error', 3000));
      },
    });
  }).catch(e => showToast(String(e.message||e), 'error', 3000));
};

window.skillsDeleteRegistry = function(name) {
  if (!confirm((t('skills_confirm_delete')||'Delete registry ') + name + '? ' + (t('skills_confirm_delete_cascade')||'This removes all synced skills from this registry.'))) return;
  apiFetch('/api/skills/registries/' + encodeURIComponent(name), { method: 'DELETE' })
    .then(() => { showToast(t('skills_deleted')||'Registry deleted', 'success', 2000); loadSkillsPanel(); })
    .catch(e => showToast(String(e.message||e), 'error', 3000));
};

window.saveAutomataScanField = function(key, value) {
  apiFetch('/api/autonomous/scan/config', {
    method: 'PUT',
    body: JSON.stringify({ [key]: value })
  }).catch(e => showToast(String(e.message||e), 'error'));
};

// BL247 — renderOrchestratorView redirects to Settings → Automata tab (orchestrator is now a card there).
function renderOrchestratorView() {
  _settingsTab = 'automata';
  localStorage.setItem('cs_settings_tab', 'automata');
  navigate('settings');
}
window.renderOrchestratorView = renderOrchestratorView;
