// ── BL220 Bundle F — Session Analytics ───────────────────────────────────────

function loadAnalyticsPanel() {
  const el = document.getElementById('analyticsPanel');
  if (!el) return;
  const ranges = [7, 14, 30, 90];
  const selId = 'analyticsRange';
  el.innerHTML = `<div style="display:flex;gap:6px;align-items:center;margin-bottom:8px;">
    <label style="font-size:11px;">Range:</label>
    <select id="${selId}" onchange="loadAnalyticsPanel()" style="font-size:11px;background:var(--bg2);border:1px solid var(--border);border-radius:4px;color:var(--text);padding:2px 4px;">
      ${ranges.map(d => `<option value="${d}"${d===7?' selected':''}>${d}d</option>`).join('')}
    </select>
    <span id="analyticsSuccessRate" style="font-size:11px;color:var(--text2);margin-left:4px;"></span>
  </div>
  <div id="analyticsBuckets" style="font-size:11px;color:var(--text2);">Loading…</div>`;
  const range = (document.getElementById(selId)||{}).value || '7';
  apiFetch(`/api/analytics?range=${range}d`).then(data => {
    const rate = document.getElementById('analyticsSuccessRate');
    if (rate && data.success_rate != null)
      rate.textContent = `Success rate: ${(data.success_rate * 100).toFixed(1)}%`;
    const buckets = data.buckets || [];
    const bucketsEl = document.getElementById('analyticsBuckets');
    if (!bucketsEl) return;
    if (buckets.length === 0) { bucketsEl.textContent = t('stats_no_sessions_range') || 'No sessions in range.'; return; }
    // API fields: session_count, completed, failed, killed (not total/errors)
    const maxTotal = Math.max(...buckets.map(b => b.session_count || 0), 1);
    bucketsEl.innerHTML = `<table style="width:100%;border-collapse:collapse;font-size:11px;">
      <thead><tr style="opacity:0.5;">
        <th style="text-align:left;padding:2px 4px;">Date</th>
        <th style="text-align:right;padding:2px 4px;">Total</th>
        <th style="text-align:right;padding:2px 4px;">OK</th>
        <th style="text-align:right;padding:2px 4px;">Err</th>
        <th style="text-align:left;padding:2px 4px 2px 8px;">Bar</th>
      </tr></thead><tbody>${
      buckets.map(b => {
        const total = b.session_count || 0;
        const errors = (b.failed || 0) + (b.killed || 0);
        const ok = total - errors;
        const pct = Math.round((total / maxTotal) * 100);
        const errPct = total ? Math.round((errors / total) * 100) : 0;
        const barColor = errPct > 20 ? 'var(--error,#ef4444)' : errPct > 5 ? 'var(--warning,#f59e0b)' : 'var(--success,#10b981)';
        return `<tr style="border-top:1px solid var(--border);">
          <td style="padding:3px 4px;">${escHtml(b.date||'')}</td>
          <td style="text-align:right;padding:3px 4px;">${total}</td>
          <td style="text-align:right;padding:3px 4px;color:var(--success,#10b981);">${ok}</td>
          <td style="text-align:right;padding:3px 4px;color:var(--error,#ef4444);">${errors}</td>
          <td style="padding:3px 4px 3px 8px;"><div style="height:8px;width:${pct}%;background:${barColor};border-radius:2px;max-width:120px;"></div></td>
        </tr>`;
      }).join('')}</tbody></table>`;
  }).catch(() => {
    const bucketsEl = document.getElementById('analyticsBuckets');
    if (bucketsEl) bucketsEl.innerHTML = '<span style="color:var(--error);">Failed to load analytics.</span>';
  });
}
window.loadAnalyticsPanel = loadAnalyticsPanel;

// ── BL220 Bundle F — Audit Log browser ───────────────────────────────────────

function loadAuditPanel() {
  const el = document.getElementById('auditPanel');
  if (!el) return;
  const actor = (document.getElementById('auditActorFilter')||{}).value||'';
  const action = (document.getElementById('auditActionFilter')||{}).value||'';
  const limit = (document.getElementById('auditLimitFilter')||{}).value||'5';
  const qp = new URLSearchParams({ limit });
  if (actor) qp.set('actor', actor);
  if (action) qp.set('action', action);
  const loadingHtml = el._filters ? '' : `
    <div style="display:flex;gap:4px;flex-wrap:wrap;margin-bottom:8px;align-items:center;">
      <input id="auditActorFilter" type="text" placeholder="Actor filter" style="flex:1;min-width:70px;font-size:11px;padding:3px 6px;background:var(--bg);border:1px solid var(--border);border-radius:4px;color:var(--text);" />
      <input id="auditActionFilter" type="text" placeholder="Action filter" style="flex:1;min-width:70px;font-size:11px;padding:3px 6px;background:var(--bg);border:1px solid var(--border);border-radius:4px;color:var(--text);" />
      <select id="auditLimitFilter" style="font-size:11px;background:var(--bg2);border:1px solid var(--border);border-radius:4px;color:var(--text);padding:3px 4px;">
        <option value="5" selected>5</option><option value="20">20</option><option value="50">50</option><option value="100">100</option>
      </select>
      <button class="btn-secondary" style="font-size:11px;" onclick="loadAuditPanel()">Load</button>
    </div>
    <div id="auditEntries" style="font-size:11px;color:var(--text2);">Loading…</div>`;
  if (!el._filters) { el.innerHTML = loadingHtml; el._filters = true; }
  const entriesEl = document.getElementById('auditEntries');
  if (entriesEl) entriesEl.textContent = t('state_loading') || 'Loading…';
  apiFetch(`/api/audit?${qp}`).then(data => {
    const entries = (data && data.entries) || [];
    const target = document.getElementById('auditEntries');
    if (!target) return;
    if (entries.length === 0) { target.textContent = t('audit_no_entries_range') || 'No audit entries in range.'; return; }
    target.innerHTML = entries.map(e => {
      const ts = e.ts ? new Date(e.ts).toLocaleString() : '';
      const details = e.details && Object.keys(e.details).length
        ? `<div style="opacity:0.6;margin-top:1px;font-family:monospace;">${escHtml(JSON.stringify(e.details))}</div>` : '';
      const sessLink = e.session_id
        ? `<span style="opacity:0.5;font-size:10px;font-family:monospace;margin-left:4px;">${escHtml(e.session_id.slice(-8))}</span>` : '';
      return `<div style="padding:4px 0;border-top:1px solid var(--border);">
        <div style="display:flex;gap:6px;align-items:baseline;flex-wrap:wrap;">
          <span style="opacity:0.5;white-space:nowrap;">${escHtml(ts)}</span>
          <strong>${escHtml(e.action||'')}</strong>
          <span style="opacity:0.7;">${escHtml(e.actor||'')}</span>${sessLink}
        </div>${details}
      </div>`;
    }).join('');
  }).catch(() => {
    const target = document.getElementById('auditEntries');
    if (target) target.innerHTML = '<span style="color:var(--error);">Failed to load audit log.</span>';
  });
}
window.loadAuditPanel = loadAuditPanel;

// ── BL220 Bundle F — Pipeline manager ────────────────────────────────────────

function loadPipelinesPanel() {
  const el = document.getElementById('pipelinesPanel');
  if (!el) return;
  // BL261 v6.7.7 — wrap all states (loading/populated/empty/error) in the
  // standard card-content inset (padding:6px 12px) so content does not sit
  // flush against the card edge. Same pattern as v6.7.6 templates/aliases fix.
  el.innerHTML = '<div style="padding:6px 12px;color:var(--text2);font-size:12px;">Loading…</div>';
  apiFetch('/api/pipelines').then(data => {
    const pipelines = Array.isArray(data) ? data : [];
    const stateColor = { pending:'var(--text2)', running:'var(--accent,#6366f1)', completed:'var(--success,#10b981)', failed:'var(--error,#ef4444)', cancelled:'var(--text2)' };
    el.innerHTML = `<div style="padding:6px 12px;"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px;">
      <span style="font-size:11px;opacity:0.7;">${pipelines.length} pipeline${pipelines.length===1?'':'s'}</span>
      <span class="live-dot" title="Auto-refreshing every 8s" style="display:inline-block;width:7px;height:7px;border-radius:50%;background:var(--success,#10b981);margin-left:6px;animation:livePulse 2s ease-in-out infinite;vertical-align:middle;"></span>
      <span style="opacity:0.5;font-weight:400;font-size:10px;margin-left:4px;">live</span>
    </div>` + (pipelines.length === 0
      ? '<div style="opacity:0.7;font-size:12px;">No pipelines — start one via REST or CLI.</div>'
      : pipelines.map(p => {
          const color = stateColor[p.state||'pending'] || 'var(--text2)';
          const tasksDone = (p.tasks||[]).filter(t=>t.state==='completed').length;
          const safeId = JSON.stringify(p.id||'');
          const canCancel = p.state === 'running' || p.state === 'pending';
          return `<div style="padding:8px 0;border-top:1px solid var(--border);">
            <div style="display:flex;align-items:center;gap:6px;">
              <span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:${color};flex-shrink:0;"></span>
              <strong style="font-size:12px;">${escHtml(p.name||p.id||'')}</strong>
              <span style="opacity:0.6;font-size:10px;">${escHtml(p.state||'')}</span>
              ${(p.tasks||[]).length ? `<span style="opacity:0.5;font-size:10px;margin-left:auto;">${tasksDone}/${p.tasks.length} tasks</span>` : ''}
              ${canCancel ? `<button class="btn-icon" style="font-size:11px;padding:2px 6px;color:var(--error);" onclick='pipelineCancel(${safeId})'>Cancel</button>` : ''}
            </div>
            <div style="opacity:0.5;font-size:10px;font-family:monospace;">${escHtml(p.id||'')}</div>
          </div>`;
        }).join('')) + '</div>';
  }).catch(() => { el.innerHTML = '<div style="padding:6px 12px;"><span style="color:var(--error);font-size:12px;">Failed to load pipelines.</span></div>'; });
}
window.loadPipelinesPanel = loadPipelinesPanel;
window.pipelineCancel = function(id) {
  apiFetch(`/api/pipeline?id=${encodeURIComponent(id)}&action=cancel`, { method: 'POST' })
    .then(() => { showToast('Pipeline cancelled', 'success', 2000); loadPipelinesPanel(); })
    .catch(e => showToast(String(e.message||e), 'error'));
};

// ── BL220 Bundle F — Knowledge Graph browser ──────────────────────────────────

function loadKgPanel() {
  const el = document.getElementById('kgPanel');
  if (!el) return;
  if (!el._init) {
    el._init = true;
    el.innerHTML = `
      <div style="display:flex;gap:4px;margin-bottom:8px;align-items:center;">
        <input id="kgEntityInput" type="text" placeholder="Entity to query…" class="form-input" style="flex:1;font-size:11px;" />
        <button class="btn-primary" style="font-size:11px;" onclick="kgQuery()">Query</button>
      </div>
      <div style="display:flex;gap:4px;margin-bottom:10px;align-items:center;">
        <input id="kgSubject" type="text" placeholder="Subject" class="form-input" style="flex:1;font-size:11px;" />
        <input id="kgPredicate" type="text" placeholder="Predicate" class="form-input" style="flex:1;font-size:11px;" />
        <input id="kgObject" type="text" placeholder="Object" class="form-input" style="flex:1;font-size:11px;" />
        <button class="btn-secondary" style="font-size:11px;" onclick="kgAddTriple()">Add triple</button>
      </div>
      <div id="kgResults" style="font-size:11px;color:var(--text2);"></div>`;
  }
}
window.loadKgPanel = loadKgPanel;
window.kgQuery = function() {
  const entity = (document.getElementById('kgEntityInput')||{}).value||'';
  if (!entity) return;
  const res = document.getElementById('kgResults');
  if (res) res.textContent = t('state_querying') || 'Querying…';
  apiFetch(`/api/memory/kg/query?entity=${encodeURIComponent(entity)}`).then(data => {
    if (!res) return;
    const triples = Array.isArray(data) ? data : (data?.triples || []);
    if (triples.length === 0) { res.textContent = t('kg_no_triples_for_entity') || 'No triples found for this entity.'; return; }
    res.innerHTML = `<div style="font-size:10px;opacity:0.6;margin-bottom:4px;">${triples.length} triple${triples.length===1?'':'s'}</div>`
      + triples.map(t => `<div style="padding:3px 0;border-top:1px solid var(--border);font-family:monospace;">
        <span style="color:var(--accent);">${escHtml(t.subject||'')}</span>
        <span style="opacity:0.6;margin:0 4px;">${escHtml(t.predicate||'')}</span>
        <span>${escHtml(t.object||'')}</span>
        ${t.valid_from ? `<span style="opacity:0.4;font-size:10px;margin-left:4px;">${escHtml(t.valid_from)}</span>` : ''}
      </div>`).join('');
  }).catch(e => { if (res) res.innerHTML = `<span style="color:var(--error);">${escHtml(String(e.message||e))}</span>`; });
};
window.kgAddTriple = function() {
  const subject = (document.getElementById('kgSubject')||{}).value||'';
  const predicate = (document.getElementById('kgPredicate')||{}).value||'';
  const object = (document.getElementById('kgObject')||{}).value||'';
  if (!subject || !predicate || !object) { showToast('Subject, predicate, object all required', 'error'); return; }
  apiFetch('/api/memory/kg/add', { method: 'POST', headers: {'Content-Type':'application/json'},
    body: JSON.stringify({ subject, predicate, object, source: 'pwa' }) })
    .then(() => { showToast('Triple added', 'success', 2000); kgQuery(); })
    .catch(e => showToast(String(e.message||e), 'error'));
};

// ── BL257 Phase 1 v6.8.0 — Identity / Telos card ────────────────────────
//
// Settings → Agents → Identity. Operator edits role, north-star goals,
// current projects, values, current focus, context notes; PUT writes
// the full document so empty fields clear. The daemon injects the
// non-empty fields into every spawned session's L0 wake-up layer.

function loadIdentityPanel() {
  const panel = document.getElementById('identityPanel');
  if (!panel) return;
  panel.innerHTML = `<div style="color:var(--text2);">${escHtml(t('identity_loading')||'Loading…')}</div>`;
  apiFetch('/api/identity').then(id => {
    _renderIdentityForm(panel, id || {});
  }).catch(err => {
    panel.innerHTML = `<div style="color:var(--error);">${escHtml(t('identity_load_error')||'Failed to load identity')}: ${escHtml(String(err.message||err))}</div>`;
  });
}
window.loadIdentityPanel = loadIdentityPanel;

function _renderIdentityForm(panel, id) {
  const role = id.role || '';
  const goals = (id.north_star_goals || []).join('\n');
  const projects = (id.current_projects || []).join('\n');
  const values = (id.values || []).join('\n');
  const focus = id.current_focus || '';
  const notes = id.context_notes || '';
  panel.innerHTML = `
    <div style="font-size:11px;color:var(--text2);margin-bottom:6px;">${escHtml(t('identity_intro')||'Operator self-description injected into every LLM session via wake-up L0.')}</div>
    <div style="display:flex;flex-direction:column;gap:6px;">
      <label style="font-size:11px;color:var(--text2);">${escHtml(t('identity_field_role')||'Role')}</label>
      <input id="idRole" type="text" value="${escHtml(role)}" placeholder="${escHtml(t('identity_field_role_ph')||'e.g. platform engineer')}" style="font-size:12px;padding:6px 8px;background:var(--bg);border:1px solid var(--border);border-radius:6px;color:var(--text);" />

      <label style="font-size:11px;color:var(--text2);">${escHtml(t('identity_field_goals')||'North-Star Goals (one per line)')}</label>
      <textarea id="idGoals" rows="3" style="font-size:12px;padding:6px 8px;background:var(--bg);border:1px solid var(--border);border-radius:6px;color:var(--text);font-family:inherit;">${escHtml(goals)}</textarea>

      <label style="font-size:11px;color:var(--text2);">${escHtml(t('identity_field_projects')||'Current Projects (one per line)')}</label>
      <textarea id="idProjects" rows="3" style="font-size:12px;padding:6px 8px;background:var(--bg);border:1px solid var(--border);border-radius:6px;color:var(--text);font-family:inherit;">${escHtml(projects)}</textarea>

      <label style="font-size:11px;color:var(--text2);">${escHtml(t('identity_field_values')||'Values (one per line)')}</label>
      <textarea id="idValues" rows="3" style="font-size:12px;padding:6px 8px;background:var(--bg);border:1px solid var(--border);border-radius:6px;color:var(--text);font-family:inherit;">${escHtml(values)}</textarea>

      <label style="font-size:11px;color:var(--text2);">${escHtml(t('identity_field_focus')||'Current Focus')}</label>
      <input id="idFocus" type="text" value="${escHtml(focus)}" placeholder="${escHtml(t('identity_field_focus_ph')||'what you are focused on right now')}" style="font-size:12px;padding:6px 8px;background:var(--bg);border:1px solid var(--border);border-radius:6px;color:var(--text);" />

      <label style="font-size:11px;color:var(--text2);">${escHtml(t('identity_field_notes')||'Context Notes')}</label>
      <textarea id="idNotes" rows="4" style="font-size:12px;padding:6px 8px;background:var(--bg);border:1px solid var(--border);border-radius:6px;color:var(--text);font-family:inherit;">${escHtml(notes)}</textarea>

      <div style="display:flex;gap:6px;margin-top:6px;">
        <button class="btn-primary" style="font-size:12px;padding:6px 14px;" onclick="saveIdentity()">${escHtml(t('identity_btn_save')||'Save')}</button>
        <button class="btn-secondary" style="font-size:12px;padding:6px 14px;" onclick="loadIdentityPanel()">${escHtml(t('identity_btn_reset')||'Reset')}</button>
      </div>
    </div>`;
}

window.saveIdentity = function() {
  const linesOf = id => {
    const v = (document.getElementById(id)||{}).value || '';
    return v.split('\n').map(s => s.trim()).filter(s => s.length > 0);
  };
  const body = {
    role: ((document.getElementById('idRole')||{}).value || '').trim(),
    north_star_goals: linesOf('idGoals'),
    current_projects: linesOf('idProjects'),
    values: linesOf('idValues'),
    current_focus: ((document.getElementById('idFocus')||{}).value || '').trim(),
    context_notes: ((document.getElementById('idNotes')||{}).value || '').trim()
  };
  apiFetch('/api/identity', { method: 'PUT', headers: {'Content-Type':'application/json'},
    body: JSON.stringify(body) })
    .then(() => { showToast(t('identity_saved_toast')||'Identity saved', 'success', 2000); loadIdentityPanel(); })
    .catch(e => showToast(String(e.message||e), 'error'));
};

// ── BL257 Phase 2 v6.8.1 — Identity Wizard ──────────────────────────────
//
// 6-step interview triggered by the robot icon in the PWA header. Each
// step asks for one identity field with the existing answer pre-filled
// (so the wizard doubles as an "edit" flow). Final step PUTs the
// assembled document. Modal state lives in module-scope identityWizard.

const identityWizard = {
  step: 0,
  values: { role: '', north_star_goals: [], current_projects: [], values: [], current_focus: '', context_notes: '' },
  steps: [
    { field: 'role',              kind: 'text',     labelKey: 'identity_field_role',     phKey: 'identity_field_role_ph' },
    { field: 'north_star_goals',  kind: 'list',     labelKey: 'identity_field_goals' },
    { field: 'current_projects',  kind: 'list',     labelKey: 'identity_field_projects' },
    { field: 'values',            kind: 'list',     labelKey: 'identity_field_values' },
    { field: 'current_focus',     kind: 'text',     labelKey: 'identity_field_focus',    phKey: 'identity_field_focus_ph' },
    { field: 'context_notes',     kind: 'longtext', labelKey: 'identity_field_notes' }
  ]
};

window.openIdentityWizard = function() {
  // Pre-fetch existing identity to pre-fill the wizard.
  apiFetch('/api/identity').then(id => {
    if (id) {
      identityWizard.values = {
        role: id.role || '',
        north_star_goals: id.north_star_goals || [],
        current_projects: id.current_projects || [],
        values: id.values || [],
        current_focus: id.current_focus || '',
        context_notes: id.context_notes || ''
      };
    }
    identityWizard.step = 0;
    _renderIdentityWizard();
  }).catch(() => {
    // No prior identity — start blank.
    identityWizard.step = 0;
    _renderIdentityWizard();
  });
};

function _renderIdentityWizard() {
  // Capture current step value into state before re-render.
  let modal = document.getElementById('identityWizardModal');
  if (!modal) {
    modal = document.createElement('div');
    modal.id = 'identityWizardModal';
    modal.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.5);display:flex;align-items:center;justify-content:center;z-index:1000;';
    document.body.appendChild(modal);
  }
  const idx = identityWizard.step;
  const total = identityWizard.steps.length;
  const step = identityWizard.steps[idx];
  const cur = identityWizard.values[step.field];
  const value = step.kind === 'list' ? (Array.isArray(cur) ? cur.join('\n') : '') : (cur || '');
  const label = escHtml(t(step.labelKey)||step.field);
  const ph = step.phKey ? escHtml(t(step.phKey)||'') : '';
  let inputHtml = '';
  if (step.kind === 'text') {
    inputHtml = `<input id="wizInput" type="text" value="${escHtml(value)}" placeholder="${ph}" style="width:100%;box-sizing:border-box;font-size:14px;padding:8px 10px;background:var(--bg);border:1px solid var(--border);border-radius:6px;color:var(--text);" autofocus />`;
  } else if (step.kind === 'longtext') {
    inputHtml = `<textarea id="wizInput" rows="6" style="width:100%;box-sizing:border-box;font-size:13px;padding:8px 10px;background:var(--bg);border:1px solid var(--border);border-radius:6px;color:var(--text);font-family:inherit;" autofocus>${escHtml(value)}</textarea>`;
  } else {
    inputHtml = `<textarea id="wizInput" rows="5" placeholder="${escHtml(t('identity_wizard_one_per_line')||'one per line')}" style="width:100%;box-sizing:border-box;font-size:13px;padding:8px 10px;background:var(--bg);border:1px solid var(--border);border-radius:6px;color:var(--text);font-family:inherit;" autofocus>${escHtml(value)}</textarea>`;
  }
  const isLast = idx === total - 1;
  const nextLabel = isLast ? (t('identity_wizard_finish')||'Save & Finish') : (t('identity_wizard_next')||'Next →');
  const backDisabled = idx === 0 ? 'disabled' : '';
  modal.innerHTML = `
    <div style="background:var(--bg2,#1f2937);border:1px solid var(--border);border-radius:10px;padding:20px;max-width:520px;width:90%;color:var(--text);box-shadow:0 8px 30px rgba(0,0,0,0.4);">
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px;">
        <strong style="font-size:15px;">${escHtml(t('identity_wizard_title')||'Identity Wizard')}</strong>
        <button onclick="closeIdentityWizard()" style="background:transparent;border:none;color:var(--text2);font-size:18px;cursor:pointer;">&times;</button>
      </div>
      <div style="font-size:11px;color:var(--text2);margin-bottom:12px;">${escHtml(t('identity_wizard_step')||'Step')} ${idx+1} / ${total}</div>
      <div style="font-size:13px;font-weight:600;margin-bottom:6px;">${label}</div>
      <div>${inputHtml}</div>
      <div style="display:flex;gap:6px;margin-top:14px;justify-content:space-between;">
        <button class="btn-secondary" ${backDisabled} onclick="identityWizardBack()" style="font-size:12px;padding:6px 14px;${backDisabled?'opacity:0.4;':''}">${escHtml(t('identity_wizard_back')||'← Back')}</button>
        <button class="btn-primary" onclick="identityWizardNext()" style="font-size:12px;padding:6px 14px;">${escHtml(nextLabel)}</button>
      </div>
    </div>`;
  setTimeout(() => { const el = document.getElementById('wizInput'); if (el) el.focus(); }, 30);
}

function _captureWizardStep() {
  const step = identityWizard.steps[identityWizard.step];
  const el = document.getElementById('wizInput');
  if (!el) return;
  const raw = (el.value || '').trim();
  if (step.kind === 'list') {
    identityWizard.values[step.field] = raw.split('\n').map(s => s.trim()).filter(s => s.length > 0);
  } else {
    identityWizard.values[step.field] = raw;
  }
}

window.identityWizardBack = function() {
  _captureWizardStep();
  if (identityWizard.step > 0) { identityWizard.step--; _renderIdentityWizard(); }
};

window.identityWizardNext = function() {
  _captureWizardStep();
  const total = identityWizard.steps.length;
  if (identityWizard.step < total - 1) {
    identityWizard.step++;
    _renderIdentityWizard();
    return;
  }
  // Last step → submit.
  apiFetch('/api/identity', { method: 'PUT', headers: {'Content-Type':'application/json'},
    body: JSON.stringify(identityWizard.values) })
    .then(() => {
      showToast(t('identity_saved_toast')||'Identity saved', 'success', 2000);
      closeIdentityWizard();
      if (typeof loadIdentityPanel === 'function') loadIdentityPanel();
    })
    .catch(e => showToast(String(e.message||e), 'error'));
};

window.closeIdentityWizard = function() {
  const m = document.getElementById('identityWizardModal');
  if (m) m.remove();
};

// ── BL258 v6.9.0 — Algorithm Mode 7-phase strip ─────────────────────────
//
// Renders into the Settings → Agents → Algorithm card. Lists every
// session currently in Algorithm Mode and shows a 7-step phase
// indicator strip (Observe → Improve) with current highlighted.
// Operator-driven advance: each row has Advance / Edit / Abort / Reset.

const ALGO_PHASES = ['observe','orient','decide','act','measure','learn','improve'];

function loadAlgorithmPanel() {
  const panel = document.getElementById('algorithmPanel');
  if (!panel) return;
  panel.innerHTML = `<div style="color:var(--text2);">${escHtml(t('algorithm_loading')||'Loading…')}</div>`;
  apiFetch('/api/algorithm').then(data => {
    _renderAlgorithmPanel(panel, (data && data.sessions) || []);
  }).catch(err => {
    panel.innerHTML = `<div style="color:var(--error);">${escHtml(String(err.message||err))}</div>`;
  });
}
window.loadAlgorithmPanel = loadAlgorithmPanel;

function _renderAlgorithmPanel(panel, sessions) {
  const intro = `<div style="font-size:11px;color:var(--text2);margin-bottom:8px;">${escHtml(t('algorithm_intro')||'7-phase Observe→Improve harness. Operator-driven advance.')}</div>`;
  if (!sessions || sessions.length === 0) {
    panel.innerHTML = `<div style="padding:6px 12px;">${intro}<div style="text-align:center;padding:12px;color:var(--text2);font-size:12px;">${escHtml(t('algorithm_empty')||'No sessions in Algorithm Mode. Use the API to start one.')}</div></div>`;
    return;
  }
  const rows = sessions.map(s => _renderAlgorithmRow(s)).join('');
  panel.innerHTML = `<div style="padding:6px 12px;">${intro}${rows}</div>`;
}

function _renderAlgorithmRow(s) {
  const cur = s.current || 'observe';
  const idx = ALGO_PHASES.indexOf(cur);
  const strip = ALGO_PHASES.map((p, i) => {
    const active = i === idx;
    const done = i < idx;
    const color = active ? 'var(--accent,#6366f1)' : (done ? 'var(--success,#10b981)' : 'var(--text2)');
    const bg = active ? 'rgba(99,102,241,0.15)' : (done ? 'rgba(16,185,129,0.1)' : 'transparent');
    return `<span title="${escHtml(p)}" style="display:inline-block;padding:2px 6px;font-size:10px;border-radius:4px;color:${color};background:${bg};border:1px solid ${color};margin-right:2px;">${escHtml(p.charAt(0).toUpperCase()+p.slice(1,3))}</span>`;
  }).join('');
  const idJ = escHtml(JSON.stringify(s.session_id));
  const aborted = s.aborted ? `<span style="color:var(--error);font-size:10px;margin-left:4px;">${escHtml(t('algorithm_aborted')||'aborted')}</span>` : '';
  const histN = (s.history||[]).length;
  return `<div style="padding:8px 0;border-bottom:1px solid var(--border);">
    <div style="display:flex;align-items:center;gap:6px;margin-bottom:4px;">
      <strong style="font-size:12px;font-family:monospace;">${escHtml(s.session_id)}</strong>${aborted}
      <span style="font-size:10px;color:var(--text2);margin-left:auto;">${histN} ${escHtml(t('algorithm_history_count')||'phase outputs')}</span>
    </div>
    <div style="margin-bottom:4px;">${strip}</div>
    <div style="display:flex;flex-wrap:wrap;gap:4px;">
      <input id="algoOut-${escHtml(s.session_id)}" type="text" placeholder="${escHtml(t('algorithm_output_ph')||'phase output (optional)')}" style="flex:1;min-width:180px;font-size:11px;padding:3px 6px;background:var(--bg);border:1px solid var(--border);border-radius:4px;color:var(--text);" />
      <button class="btn-primary" style="font-size:11px;padding:3px 8px;" onclick="algorithmAdvance(${idJ})">${escHtml(t('algorithm_btn_advance')||'Advance')}</button>
      <button class="btn-secondary" style="font-size:11px;padding:3px 8px;" onclick="algorithmEdit(${idJ})">${escHtml(t('algorithm_btn_edit')||'Edit')}</button>
      <button class="btn-secondary" style="font-size:11px;padding:3px 8px;color:var(--warning,#f59e0b);" onclick="algorithmAbort(${idJ})">${escHtml(t('algorithm_btn_abort')||'Abort')}</button>
      <button class="btn-secondary" style="font-size:11px;padding:3px 8px;color:var(--error);" onclick="algorithmReset(${idJ})">${escHtml(t('algorithm_btn_reset')||'Reset')}</button>
    </div>
  </div>`;
}

function _algoOutFor(id) {
  const el = document.getElementById('algoOut-' + id);
  return el ? (el.value || '').trim() : '';
}

window.algorithmAdvance = function(id) {
  apiFetch('/api/algorithm/' + encodeURIComponent(id) + '/advance', {
    method: 'POST', headers: {'Content-Type':'application/json'},
    body: JSON.stringify({output: _algoOutFor(id)})
  }).then(() => loadAlgorithmPanel()).catch(e => showToast(String(e.message||e), 'error'));
};
window.algorithmEdit = function(id) {
  const out = _algoOutFor(id);
  if (!out) { showToast(t('algorithm_edit_empty')||'Edit requires output text in the field above', 'warning', 3000); return; }
  apiFetch('/api/algorithm/' + encodeURIComponent(id) + '/edit', {
    method: 'POST', headers: {'Content-Type':'application/json'},
    body: JSON.stringify({output: out})
  }).then(() => loadAlgorithmPanel()).catch(e => showToast(String(e.message||e), 'error'));
};
window.algorithmAbort = function(id) {
  if (!confirm((t('algorithm_confirm_abort')||'Abort algorithm for ') + id + '?')) return;
  apiFetch('/api/algorithm/' + encodeURIComponent(id) + '/abort', { method: 'POST' })
    .then(() => loadAlgorithmPanel()).catch(e => showToast(String(e.message||e), 'error'));
};
window.algorithmReset = function(id) {
  if (!confirm((t('algorithm_confirm_reset')||'Reset algorithm state for ') + id + '?')) return;
  apiFetch('/api/algorithm/' + encodeURIComponent(id), { method: 'DELETE' })
    .then(() => loadAlgorithmPanel()).catch(e => showToast(String(e.message||e), 'error'));
};

// ── BL259 Phase 1 v6.10.0 — Evals card ──────────────────────────────────
//
// Lists configured eval suites (read from ~/.datawatch/evals/*.yaml on
// the daemon) and lets the operator run them ad-hoc. Recent runs are
// shown below with pass/fail badges.

function loadEvalsPanel() {
  const panel = document.getElementById('evalsPanel');
  if (!panel) return;
  panel.innerHTML = `<div style="color:var(--text2);">${escHtml(t('evals_loading')||'Loading…')}</div>`;
  apiFetch('/api/evals/suites').then(data => {
    const suites = (data && data.suites) || [];
    apiFetch('/api/evals/runs?limit=10').then(rdata => {
      const runs = (rdata && rdata.runs) || [];
      _renderEvalsPanel(panel, suites, runs);
    }).catch(() => _renderEvalsPanel(panel, suites, []));
  }).catch(err => {
    panel.innerHTML = `<div style="color:var(--error);">${escHtml(String(err.message||err))}</div>`;
  });
}
window.loadEvalsPanel = loadEvalsPanel;

function _renderEvalsPanel(panel, suites, runs) {
  const intro = `<div style="font-size:11px;color:var(--text2);margin-bottom:8px;">${escHtml(t('evals_intro')||'Rubric-based grading suites at ~/.datawatch/evals/<name>.yaml. Replaces the legacy binary verifier.')}</div>`;
  let suitesHtml = '';
  if (!suites || suites.length === 0) {
    suitesHtml = `<div style="text-align:center;padding:8px;color:var(--text2);font-size:12px;">${escHtml(t('evals_empty_suites')||'No suites yet. Drop a YAML file into ~/.datawatch/evals/ and reload.')}</div>`;
  } else {
    suitesHtml = suites.map(s => {
      const idJ = escHtml(JSON.stringify(s.name));
      const modeBadge = `<span style="font-size:9px;background:rgba(99,102,241,0.15);color:var(--accent,#6366f1);padding:1px 5px;border-radius:8px;margin-left:4px;">${escHtml(s.mode||'?')}</span>`;
      return `<div class="settings-row" style="padding:6px 4px;border-bottom:1px solid var(--border);display:flex;align-items:center;gap:6px;flex-wrap:wrap;">
        <strong style="font-size:12px;">${escHtml(s.name)}</strong>${modeBadge}
        <span style="font-size:10px;color:var(--text2);">${escHtml(t('evals_threshold')||'threshold')} ${(s.pass_threshold||0).toFixed(2)}</span>
        <span style="font-size:10px;color:var(--text2);">${(s.case_count||0)} ${escHtml(t('evals_cases')||'cases')}</span>
        <button class="btn-primary" style="font-size:11px;padding:3px 8px;margin-left:auto;" onclick="evalsRun(${idJ})">${escHtml(t('evals_btn_run')||'Run')}</button>
      </div>`;
    }).join('');
  }
  let runsHtml = '';
  if (runs && runs.length > 0) {
    runsHtml = `<div style="font-size:11px;font-weight:600;color:var(--text2);margin:10px 0 4px;">${escHtml(t('evals_recent')||'Recent Runs')}</div>` +
      runs.map(r => {
        const passBadge = r.pass
          ? `<span style="background:rgba(16,185,129,0.15);color:var(--success,#10b981);font-size:9px;padding:1px 5px;border-radius:8px;">PASS</span>`
          : `<span style="background:rgba(239,68,68,0.15);color:var(--error,#ef4444);font-size:9px;padding:1px 5px;border-radius:8px;">FAIL</span>`;
        const idJ = escHtml(JSON.stringify(r.id));
        return `<div style="padding:4px 4px;border-bottom:1px solid var(--border);display:flex;align-items:center;gap:6px;font-size:11px;">
          ${passBadge}
          <strong>${escHtml(r.suite)}</strong>
          <span style="color:var(--text2);">${(r.pass_rate*100).toFixed(0)}% (vs ${(r.threshold*100).toFixed(0)}%)</span>
          <span style="color:var(--text2);font-size:10px;font-family:monospace;">${escHtml(r.id.substring(0,8))}</span>
          <button class="btn-icon" style="font-size:11px;padding:2px 6px;margin-left:auto;" onclick="evalsViewRun(${idJ})">${escHtml(t('evals_btn_detail')||'detail')}</button>
        </div>`;
      }).join('');
  }
  panel.innerHTML = `<div>${intro}${suitesHtml}${runsHtml}</div>`;
}

window.evalsRun = function(name) {
  showToast((t('evals_running')||'Running ') + name + '…', 'info', 2000);
  apiFetch('/api/evals/run?suite=' + encodeURIComponent(name), { method: 'POST' })
    .then(run => {
      const status = run.pass ? (t('evals_passed')||'PASS') : (t('evals_failed')||'FAIL');
      showToast(name + ': ' + status + ' (' + (run.pass_rate*100).toFixed(0) + '%)', run.pass ? 'success' : 'error', 4000);
      loadEvalsPanel();
    })
    .catch(e => showToast(String(e.message||e), 'error'));
};
window.evalsViewRun = function(id) {
  apiFetch('/api/evals/runs/' + encodeURIComponent(id))
    .then(run => alert(JSON.stringify(run, null, 2)))
    .catch(e => showToast(String(e.message||e), 'error'));
};

// ── BL260 v6.11.0 — Council Mode card ───────────────────────────────────
//
// Persona checkbox list + proposal textarea + mode picker + Run button +
// recent runs table.

function loadCouncilPanel() {
  const panel = document.getElementById('councilPanel');
  if (!panel) return;
  panel.innerHTML = `<div style="color:var(--text2);">${escHtml(t('council_loading')||'Loading…')}</div>`;
  apiFetch('/api/council/personas').then(data => {
    const personas = (data && data.personas) || [];
    apiFetch('/api/council/runs?limit=5').then(rdata => {
      _renderCouncilPanel(panel, personas, (rdata && rdata.runs) || []);
    }).catch(() => _renderCouncilPanel(panel, personas, []));
  }).catch(err => {
    panel.innerHTML = `<div style="color:var(--error);">${escHtml(String(err.message||err))}</div>`;
  });
}
window.loadCouncilPanel = loadCouncilPanel;

function _renderCouncilPanel(panel, personas, runs) {
  // v6.12.1 (BL275 + BL276) — drop the v6.11.0 stubbed-responses note (real
  // LLM debate is shipped) and surface a "View / edit personas" affordance
  // so operators can find / customize ~/.datawatch/council/personas/.
  // v6.13.7 — operator unclassified note ("how do we add more persona?
  // Let me know how i can edit and or view the persona definitions"):
  // promote the link into a real button with the gear glyph so it's
  // unmissable. Same target — the existing modal already supports
  // view + add + delete.
  const intro = `<div style="font-size:11px;color:var(--text2);margin-bottom:8px;display:flex;align-items:center;gap:8px;flex-wrap:wrap;">
    <span>${escHtml(t('council_intro')||'Multi-persona structured debate. Pick personas, type a proposal, and run.')}</span>
    <button class="btn-secondary" style="font-size:11px;padding:4px 10px;" onclick="councilOpenPersonasView()" title="${escHtml(t('council_personas_view_title')||'View / edit / add persona YAMLs at ~/.datawatch/council/personas/')}">⚙ ${escHtml(t('council_personas_view_btn')||'View / edit / add personas')}</button>
  </div>`;
  const personaCheckboxes = personas.map(p => {
    const id = 'council-p-' + escHtml(p.name);
    return `<label style="display:flex;align-items:center;gap:4px;font-size:11px;cursor:pointer;">
      <input type="checkbox" id="${id}" data-persona="${escHtml(p.name)}" checked />
      <span title="${escHtml(p.system_prompt||'')}">${escHtml(p.name)}</span>
    </label>`;
  }).join('');
  const runForm = `<div style="display:flex;flex-direction:column;gap:6px;margin-bottom:10px;">
    <div style="display:flex;flex-wrap:wrap;gap:8px;">${personaCheckboxes}</div>
    <textarea id="councilProposal" rows="3" placeholder="${escHtml(t('council_proposal_ph')||'Proposal text...')}" style="font-size:12px;padding:6px 8px;background:var(--bg);border:1px solid var(--border);border-radius:6px;color:var(--text);font-family:inherit;"></textarea>
    <div style="display:flex;gap:6px;align-items:center;">
      <select id="councilMode" style="font-size:12px;padding:4px 8px;background:var(--bg);border:1px solid var(--border);border-radius:6px;color:var(--text);">
        <option value="quick">${escHtml(t('council_mode_quick')||'Quick (1 round)')}</option>
        <option value="debate">${escHtml(t('council_mode_debate')||'Debate (3 rounds)')}</option>
      </select>
      <button class="btn-primary" style="font-size:12px;padding:6px 14px;" onclick="councilRun()">${escHtml(t('council_btn_run')||'Run Council')}</button>
    </div>
  </div>`;
  let runsHtml = '';
  if (runs && runs.length > 0) {
    runsHtml = `<div style="font-size:11px;font-weight:600;color:var(--text2);margin:10px 0 4px;">${escHtml(t('council_recent')||'Recent Runs')}</div>` +
      runs.map(r => {
        const idJ = escHtml(JSON.stringify(r.id));
        return `<div style="padding:4px;border-bottom:1px solid var(--border);display:flex;align-items:center;gap:6px;font-size:11px;">
          <span style="font-size:9px;background:rgba(99,102,241,0.15);color:var(--accent,#6366f1);padding:1px 5px;border-radius:8px;">${escHtml(r.mode||'')}</span>
          <span style="color:var(--text2);">${(r.personas||[]).length} ${escHtml(t('council_personas_count')||'personas')} × ${(r.rounds||[]).length} ${escHtml(t('council_rounds_count')||'rounds')}</span>
          <span style="color:var(--text2);font-size:10px;font-family:monospace;">${escHtml(r.id.substring(0,8))}</span>
          <button class="btn-icon" style="font-size:11px;padding:2px 6px;margin-left:auto;" onclick="councilViewRun(${idJ})">${escHtml(t('council_btn_detail')||'detail')}</button>
        </div>`;
      }).join('');
  }
  // BL297 v6.22.4 — Council subsystem runtime config block (parity fix).
  // Shows draft_retention_days, llm_ref, max_parallel, comm_firehose; operator can edit + save inline.
  const cfgBlock = `<details style="margin-top:14px;border:1px solid var(--border);border-radius:6px;background:var(--bg2);">
    <summary style="cursor:pointer;padding:6px 10px;font-size:11px;font-weight:600;color:var(--text2);">${escHtml(t('council_cfg_section')||'Council subsystem config')}</summary>
    <div style="padding:10px;display:flex;flex-direction:column;gap:8px;">
      <label style="font-size:11px;color:var(--text2);">${escHtml(t('council_cfg_llm_ref_label')||'LLM registry entry for debates (e.g. ollama)')}</label>
      <input id="councilCfgLLMRef" type="text" class="form-input" style="font-size:12px;padding:4px 6px;" placeholder="ollama" />
      <label style="font-size:11px;color:var(--text2);">${escHtml(t('council_cfg_max_parallel_label')||'Per-round persona concurrency (0 = serial, default 2)')}</label>
      <input id="councilCfgMaxParallel" type="number" min="0" class="form-input" style="width:120px;font-size:12px;padding:4px 6px;" />
      <label style="display:flex;align-items:center;gap:6px;font-size:11px;color:var(--text2);cursor:pointer;">
        <input id="councilCfgFirehose" type="checkbox" />
        ${escHtml(t('council_cfg_firehose_label')||'Comm firehose — push every persona response to channels (default: milestones only)')}
      </label>
      <label style="font-size:11px;color:var(--text2);">${escHtml(t('council_cfg_retention_label')||'Persona-wizard draft retention (days; 0 disables auto-GC)')}</label>
      <div style="display:flex;gap:6px;align-items:center;">
        <input id="councilCfgRetention" type="number" min="0" class="form-input" style="width:120px;font-size:12px;padding:4px 6px;" />
        <button class="btn-primary" type="button" style="font-size:11px;padding:4px 10px;" onclick="councilSaveCfg()">${escHtml(t('council_cfg_save_btn')||'Save')}</button>
        <span id="councilCfgStatus" style="font-size:10px;color:var(--text2);"></span>
      </div>
      <div style="font-size:10px;color:var(--text2);">${escHtml(t('council_cfg_retention_hint')||'Live: GC ticker re-reads on next 24h sweep. Default 7.')}</div>
    </div>
  </details>`;
  // v7.0.0 S4 — live-watch active runs section (multi-watch
  // collapsible cards per BL295 ASK 28). Each open run gets its own
  // SSE subscription. Cards collapse to one-line summaries; expand
  // for full per-persona detail with response materializing
  // round-by-round.
  const liveSection = `<div id="councilLiveRuns" style="margin-top:10px;display:flex;flex-direction:column;gap:6px;"></div>`;
  panel.innerHTML = `<div>${intro}${runForm}${liveSection}${runsHtml}${cfgBlock}</div>`;
  // Hydrate cfg input.
  apiFetch('/api/council/config').then(d => {
    const inp = document.getElementById('councilCfgRetention');
    if (inp) inp.value = (d && d.draft_retention_days != null) ? d.draft_retention_days : 7;
    const llmRef = document.getElementById('councilCfgLLMRef');
    if (llmRef) llmRef.value = (d && d.llm_ref) || '';
    const maxP = document.getElementById('councilCfgMaxParallel');
    if (maxP) maxP.value = (d && d.max_parallel != null) ? d.max_parallel : 2;
    const fh = document.getElementById('councilCfgFirehose');
    if (fh) fh.checked = !!(d && d.comm_firehose);
  }).catch(()=>{});
}

window.councilSaveCfg = function() {
  const inp = document.getElementById('councilCfgRetention');
  const status = document.getElementById('councilCfgStatus');
  const v = parseInt((inp||{}).value || '', 10);
  if (isNaN(v) || v < 0) { showError('retention must be >= 0'); return; }
  const llmRef = (document.getElementById('councilCfgLLMRef')||{}).value || '';
  const maxPRaw = parseInt((document.getElementById('councilCfgMaxParallel')||{}).value || '2', 10);
  const maxP = isNaN(maxPRaw) ? 2 : maxPRaw;
  const firehose = !!(document.getElementById('councilCfgFirehose')||{}).checked;
  apiFetch('/api/council/config', {
    method: 'PATCH',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ draft_retention_days: v, llm_ref: llmRef, max_parallel: maxP, comm_firehose: firehose }),
  }).then(() => {
    if (status) { status.textContent = '✓ saved'; setTimeout(()=>{ status.textContent=''; }, 2500); }
  }).catch(e => showError('Save failed', String(e.message||e)));
};

window.councilRun = function() {
  const proposal = ((document.getElementById('councilProposal')||{}).value || '').trim();
  if (!proposal) { showToast(t('council_proposal_required')||'Proposal text required', 'warning', 3000); return; }
  const mode = (document.getElementById('councilMode')||{}).value || 'quick';
  const personas = Array.from(document.querySelectorAll('#councilPanel input[type=checkbox]:checked'))
    .map(el => el.getAttribute('data-persona'))
    .filter(Boolean);
  showToast(t('council_running')||'Council started — watching live…', 'info', 2000);
  // v7.0.0 S4 — async-first. POST returns id immediately; SSE delivers
  // round-by-round events into the live-watch card.
  apiFetch('/api/council/run', {
    method: 'POST', headers: {'Content-Type':'application/json'},
    body: JSON.stringify({proposal, personas, mode, async: true})
  }).then(d => {
    if (d && d.id) {
      councilOpenLiveWatch(d.id, {proposal, personas, mode});
    } else {
      // Legacy blocking fallback (older daemon).
      showToast((t('council_done')||'Council done — ') + ((d.rounds||[]).length) + ' rounds', 'success', 3000);
      loadCouncilPanel();
    }
  }).catch(e => showError('Council start failed', String(e.message||e)));
};

// v7.0.0 S4 — open a collapsible live-watch card for a council run +
// subscribe to its SSE event stream. Card shows round/persona state
// as events arrive. Auto-collapses when run_completed fires.
window._councilLiveES = window._councilLiveES || {}; // run_id → EventSource

window.councilOpenLiveWatch = function(runID, init) {
  const container = document.getElementById('councilLiveRuns');
  if (!container) return;
  // De-dup if already open.
  if (document.getElementById('councilLive-' + runID)) return;
  const idShort = runID.slice(0, 8);
  const card = document.createElement('details');
  card.id = 'councilLive-' + runID;
  card.open = true;
  card.style.cssText = 'border:1px solid var(--accent);border-radius:6px;background:var(--bg2);';
  card.innerHTML = `
    <summary style="cursor:pointer;padding:6px 10px;display:flex;align-items:center;gap:6px;font-size:12px;">
      <span style="font-size:9px;background:rgba(34,197,94,0.2);color:#22c55e;padding:1px 5px;border-radius:8px;" id="councilLiveStatus-${runID}">running</span>
      <strong>${escHtml(idShort)}</strong>
      <span style="color:var(--text2);font-size:11px;">${escHtml((init.mode||'quick'))}</span>
      <span style="color:var(--text2);font-size:11px;">${(init.personas||[]).length} personas</span>
      <button class="btn-icon" style="margin-left:auto;font-size:11px;padding:2px 6px;" onclick="event.preventDefault();event.stopPropagation();councilCancelRun('${runID}')">✕ ${escHtml(t('council_cancel_btn')||'cancel')}</button>
    </summary>
    <div style="padding:8px 10px;font-size:11px;color:var(--text2);">
      <div style="font-weight:600;color:var(--text);margin-bottom:4px;">${escHtml((init.proposal||'').slice(0,200))}</div>
      <div id="councilLiveLog-${runID}" style="max-height:60vh;overflow:auto;font-family:monospace;font-size:10px;background:var(--bg);padding:6px;border-radius:4px;"></div>
    </div>`;
  container.prepend(card);

  const log = document.getElementById('councilLiveLog-' + runID);
  const append = (line, color) => {
    if (!log) return;
    const el = document.createElement('div');
    el.style.cssText = 'padding:2px 0;' + (color ? 'color:'+color+';' : '');
    el.textContent = line;
    log.appendChild(el);
    log.scrollTop = log.scrollHeight;
  };

  // SSE subscribe.
  try {
    const es = new EventSource('/api/council/runs/' + encodeURIComponent(runID) + '/events');
    window._councilLiveES[runID] = es;
    const eventTypes = ['hello','run_started','round_started','persona_responding','persona_response','persona_error','round_completed','synthesis_started','run_completed','run_cancelled','close'];
    eventTypes.forEach(et => {
      es.addEventListener(et, (ev) => {
        let payload = {};
        try { payload = JSON.parse(ev.data || '{}'); } catch (_) {}
        switch (et) {
          case 'hello': append('● connected', '#22c55e'); break;
          case 'run_started': append(`▶ run started — mode=${payload.mode}, personas=${(payload.personas||[]).join(',')}, max_parallel=${payload.max_parallel}`, '#22c55e'); break;
          case 'round_started': append(`── round ${payload.round} ──`, '#6366f1'); break;
          case 'persona_responding': append(`  ⏳ ${payload.persona} responding...`, '#f59e0b'); break;
          case 'persona_response': {
            const text = String(payload.text||'').slice(0, 600);
            append(`  ✓ ${payload.persona}: ${text}${payload.text && payload.text.length > 600 ? '…' : ''}`, '#22c55e');
            break;
          }
          case 'persona_error': append(`  ✗ ${payload.persona} ERROR: ${payload.error}`, '#ef4444'); break;
          case 'round_completed': append(`── round ${payload.round} done ──`, '#6366f1'); break;
          case 'synthesis_started': append(`◆ synthesizing...`, '#a855f7'); break;
          case 'run_completed':
            append(`✅ run completed`, '#22c55e');
            if (payload.consensus) append(`CONSENSUS: ${String(payload.consensus).slice(0,400)}`, '#22c55e');
            if (payload.dissent) append(`DISSENT: ${String(payload.dissent).slice(0,400)}`, '#f59e0b');
            const st = document.getElementById('councilLiveStatus-' + runID);
            if (st) { st.textContent = 'completed'; st.style.background = 'rgba(99,102,241,0.2)'; st.style.color = '#6366f1'; }
            es.close(); delete window._councilLiveES[runID];
            loadCouncilPanel();
            break;
          case 'run_cancelled':
            append(`✕ run cancelled`, '#ef4444');
            const st2 = document.getElementById('councilLiveStatus-' + runID);
            if (st2) { st2.textContent = 'cancelled'; st2.style.background = 'rgba(239,68,68,0.2)'; st2.style.color = '#ef4444'; }
            es.close(); delete window._councilLiveES[runID];
            loadCouncilPanel();
            break;
          case 'close':
            es.close(); delete window._councilLiveES[runID];
            break;
        }
      });
    });
    es.onerror = () => {
      append('⚠ SSE connection lost (will not auto-reconnect; refresh to re-subscribe)', '#ef4444');
    };
  } catch (e) {
    append('⚠ SSE not supported in this browser: ' + e.message, '#ef4444');
  }
};

window.councilCancelRun = function(runID) {
  if (!confirm('Cancel council run ' + runID.slice(0,8) + '?')) return;
  apiFetch('/api/council/runs/' + encodeURIComponent(runID) + '/cancel', { method: 'POST' })
    .then(() => showToast('Cancel requested', 'info', 2000))
    .catch(e => showError('Cancel failed', String(e.message||e)));
};
window.councilViewRun = function(id) {
  apiFetch('/api/council/runs/' + encodeURIComponent(id))
    .then(run => alert(JSON.stringify(run, null, 2)))
    .catch(e => showToast(String(e.message||e), 'error'));
};

// v6.12.4 — operator: "add ability to add/remove persona". Modal now
// includes per-persona × delete button + a "+ Add Persona" form at the
// bottom that POSTs to /api/council/personas. The .seeded marker file
// makes deletes durable across daemon restarts.
